let tokenMetadataResolverInstance = null;
const pumpFunMetadataCache = new Map();
const geckoTerminalMetadataCache = new Map();

function getTokenMetadataResolver() {
  if (tokenMetadataResolverInstance) return tokenMetadataResolverInstance;
  tokenMetadataResolverInstance = createTokenMetadataResolver({
    ttlMs: 5 * 60 * 1000,
    getSlimeWireMetadata: ({ mint }) => slimeWireLaunchMetadataForMint(mint),
    getDexMetadata: (mint) => getDexScreenerTokenMetadata(mint).catch(() => ({})),
    getPumpMetadata: (mint, options = {}) => getPumpFunTokenMetadata(mint, {
      timeoutMs: options.pumpTimeoutMs || options.timeoutMs || 1_500
    }).catch(() => ({})),
    getOnchainMetadata: () => ({}),
    fetchMetadataJson: fetchTokenMetadataJsonForResolver,
    verifyImageUri: verifyTokenImageForResolver,
    log: logTokenMetadataResolution
  });
  return tokenMetadataResolverInstance;
}

function invalidateTokenMetadataCache(tokenMint = "") {
  const mint = String(tokenMint || "").trim();
  if (!mint) return;
  dexMetadataCache.delete(mint);
  pumpFunMetadataCache.delete(mint);
  geckoTerminalMetadataCache.delete(mint);
  tokenMetadataResolverInstance?.invalidate(mint);
}

async function getDexTokenMetadata(tokenMint, options = {}) {
  const mint = String(tokenMint || "").trim();
  if (!mint) return {};
  const cached = dexMetadataCache.get(mint);
  if (!options.force && cached && Date.now() - cached.cachedAt < 5 * 60 * 1000) {
    return cached.value;
  }
  let value = await getTokenMetadataResolver().resolveTokenMetadata({ mint }, options);
  if (!value?.imageUrl || !value?.imageUri || !value?.marketCap || !value?.liquidityUsd) {
    const geckoValue = await getGeckoTerminalTokenMetadata(mint, { timeoutMs: options.geckoTimeoutMs || 1_800 }).catch(() => ({}));
    value = {
      ...value,
      symbol: firstString(value?.symbol, geckoValue.symbol),
      name: firstString(value?.name, geckoValue.name),
      imageUrl: firstString(value?.imageUrl, value?.imageUri, geckoValue.imageUrl, geckoValue.imageUri),
      imageUri: firstString(value?.imageUri, value?.imageUrl, geckoValue.imageUri, geckoValue.imageUrl),
      websiteUrl: firstString(value?.websiteUrl, geckoValue.websiteUrl),
      twitterUrl: firstString(value?.twitterUrl, geckoValue.twitterUrl),
      telegramUrl: firstString(value?.telegramUrl, geckoValue.telegramUrl),
      marketCap: firstMeaningfulNumber(value?.marketCap, value?.marketCapUsd, value?.fdv, geckoValue.marketCap, geckoValue.fdv) || null,
      fdv: firstMeaningfulNumber(value?.fdv, value?.marketCap, geckoValue.fdv, geckoValue.marketCap) || null,
      liquidityUsd: firstMeaningfulNumber(value?.liquidityUsd, geckoValue.liquidityUsd) || null,
      volume: value?.volume || geckoValue.volume || null,
      priceChange: value?.priceChange || geckoValue.priceChange || null,
      pairCreatedAt: firstNumber(value?.pairCreatedAt, geckoValue.pairCreatedAt) || null,
      metadataSourceUsed: value?.metadataSourceUsed || (geckoValue.imageUrl ? "geckoterminal" : value?.source || ""),
      source: value?.source || geckoValue.source || ""
    };
  }
  dexMetadataCache.set(mint, { cachedAt: Date.now(), value });
  return value;
}

async function tokenMetadataMapForMints(tokenMints, options = {}) {
  const addresses = [...new Set((tokenMints || []).filter(Boolean))].slice(0, options.limit || 30);
  const metadataByMint = new Map();
  const uncached = [];

  for (const mint of addresses) {
    const cached = dexMetadataCache.get(mint);
    if (!options.force && cached && Date.now() - cached.cachedAt < 5 * 60 * 1000) {
      metadataByMint.set(mint, cached.value);
    } else {
      uncached.push(mint);
    }
  }

  if (!uncached.length) return metadataByMint;

  const pairs = await fetchDexScreenerTokenPairsBatch(uncached, { timeoutMs: options.timeoutMs || 3_500 }).catch(() => []);
  await runWithConcurrency(uncached, options.concurrency || 3, async (mint) => {
    const dexValue = metadataFromDexPair(mint, bestDexPairForToken(mint, pairs));
    const value = await getTokenMetadataResolver().resolveTokenMetadata({ mint }, {
      ...options,
      dexMetadata: dexValue,
      metadataTimeoutMs: options.metadataTimeoutMs || 1_500,
      imageTimeoutMs: options.imageTimeoutMs || 1_500
    }).catch(() => ({
      symbol: dexValue.symbol || "",
      name: dexValue.name || "",
      imageUrl: dexValue.imageUrl || "",
      imageUri: dexValue.imageUrl || "",
      metadataSourceUsed: dexValue.imageUrl ? "dex" : "placeholder",
      source: dexValue.imageUrl ? "dex" : "placeholder",
      metadataMissing: !dexValue.imageUrl,
      warnings: ["metadata resolver failed"]
    }));
    dexMetadataCache.set(mint, { cachedAt: Date.now(), value });
    metadataByMint.set(mint, value);
  });

  return metadataByMint;
}

async function slimeWireLaunchMetadataForMint(tokenMint = "") {
  const mint = String(tokenMint || "").trim();
  if (!mint) return {};
  const [attemptStore, tradeStore] = await Promise.all([
    readPumpLaunchAttempts().catch(() => ({ attempts: [] })),
    readTradeHistory().catch(() => ({ trades: [] }))
  ]);
  const attempts = (attemptStore.attempts || [])
    .filter((attempt) => String(firstString(attempt.mintPublicKey, attempt.tokenMint, attempt.mint, attempt.requestBody?.mint)) === mint)
    .sort((a, b) => tradeTimestampMs(b.completedAt || b.updatedAt || b.createdAt) - tradeTimestampMs(a.completedAt || a.updatedAt || a.createdAt));
  const preferredAttempt = attempts.find((attempt) => (
    String(attempt.status || "").toUpperCase() === PUMP_LAUNCH_STATUS.COMPLETE
    && (attempt.imageUri || attempt.metadataUri || attempt.metadataJson)
  )) || attempts.find((attempt) => attempt.imageUri || attempt.metadataUri || attempt.metadataJson);
  if (preferredAttempt) {
    return {
      tokenMint: mint,
      source: "pumpfun",
      tokenName: firstString(preferredAttempt.tokenName, preferredAttempt.name, preferredAttempt.metadataJson?.name, preferredAttempt.requestBody?.tokenMetadata?.name),
      symbol: firstString(preferredAttempt.symbol, preferredAttempt.metadataJson?.symbol, preferredAttempt.requestBody?.tokenMetadata?.symbol),
      imageUri: firstString(preferredAttempt.imageUri, preferredAttempt.metadataJson?.image, preferredAttempt.metadataValidation?.imageUri),
      metadataUri: firstString(preferredAttempt.metadataUri, preferredAttempt.requestBody?.tokenMetadata?.uri),
      metadataJson: preferredAttempt.metadataJson || null,
      launchAttemptId: preferredAttempt.launchAttemptId || preferredAttempt.id || "",
      completedAt: firstString(preferredAttempt.completedAt, preferredAttempt.updatedAt, preferredAttempt.createdAt),
      confidence: String(preferredAttempt.status || "").toUpperCase() === PUMP_LAUNCH_STATUS.COMPLETE ? "high" : "medium"
    };
  }

  const launchTrade = (tradeStore.trades || [])
    .filter((trade) => String(trade.tokenMint || "") === mint && /pump|launch/i.test(String(trade.source || trade.type || "")))
    .sort((a, b) => tradeTimestampMs(b.timestamp) - tradeTimestampMs(a.timestamp))[0];
  if (!launchTrade) return {};
  return {
    tokenMint: mint,
    source: "pumpfun",
    tokenName: firstString(launchTrade.tokenName, launchTrade.name),
    symbol: firstString(launchTrade.symbol, launchTrade.ticker),
    imageUri: firstString(launchTrade.imageUri, launchTrade.imageUrl),
    metadataUri: firstString(launchTrade.metadataUri),
    completedAt: launchTrade.timestamp || "",
    confidence: "medium"
  };
}

async function fetchTokenMetadataJsonForResolver(uri, options = {}) {
  let lastError = null;
  for (const candidate of metadataUriGatewayCandidates(uri)) {
    try {
      const fetched = await fetchTextWithBackoff(candidate, {
        timeoutMs: Math.max(900, Math.min(Number(options.timeoutMs || 1_500), 4_000)),
        retries: Number.isFinite(Number(options.retries)) ? Number(options.retries) : 1
      });
      const json = JSON.parse(fetched.text);
      return {
        json,
        uri: fetched.url,
        status: fetched.response?.status || 200,
        contentType: fetched.response?.headers?.get?.("content-type") || "",
        attempts: fetched.attempts || []
      };
    } catch (error) {
      lastError = error;
    }
  }
  if (lastError) throw lastError;
  return null;
}

async function verifyTokenImageForResolver(uri, options = {}) {
  let lastError = null;
  for (const candidate of imageUriGatewayCandidates(uri)) {
    try {
      const result = await fetchPublicImageWithBackoff(candidate, {
        timeoutMs: Math.max(900, Math.min(Number(options.timeoutMs || 1_500), 4_000)),
        retries: Number.isFinite(Number(options.retries)) ? Number(options.retries) : 1
      });
      return {
        ok: true,
        status: result.status || 200,
        uri: result.url || candidate,
        contentType: result.contentType || ""
      };
    } catch (error) {
      lastError = error;
    }
  }
  return {
    ok: false,
    status: lastError?.providerStatus || lastError?.status || lastError?.statusCode || null,
    uri: String(uri || "")
  };
}

function logTokenMetadataResolution(event, payload = {}) {
  try {
    console.info("TOKEN_METADATA_RESOLVED", {
      event,
      tokenAddress: shortMint(payload.tokenAddress || ""),
      metadataSourceUsed: payload.metadataSourceUsed || "",
      imagePresent: Boolean(payload.imagePresent),
      metadataMissing: Boolean(payload.metadataMissing),
      warningCount: Number(payload.warningCount || 0)
    });
  } catch {
    // PnL display metadata diagnostics must never block rendering.
  }
}

async function getDexScreenerTokenMetadata(tokenMint) {
  const pairs = await fetchDexScreenerTokenPairsBatch([tokenMint]);
  return metadataFromDexPair(tokenMint, bestDexPairForToken(tokenMint, pairs));
}

async function fetchDexScreenerTokenPairsBatch(tokenMints, options = {}) {
  const addresses = [...new Set((tokenMints || []).filter(Boolean))].slice(0, 30);
  if (addresses.length === 0) return [];

  const tokenPath = addresses.map((address) => encodeURIComponent(address)).join(",");
  const data = await fetchJson(`https://api.dexscreener.com/tokens/v1/solana/${tokenPath}`, {
    headers: { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" },
    timeoutMs: options.timeoutMs || 4_500
  });
  return Array.isArray(data) ? data : [];
}

let _dsSoftBlockLogAt = 0;
async function fetchDexScreenerTokenPairsFallback(tokenMint, options = {}) {
  const mint = String(tokenMint || "").trim();
  if (!mint) return [];
  const data = await fetchJson(`https://api.dexscreener.com/latest/dex/tokens/${encodeURIComponent(mint)}`, {
    headers: { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" },
    timeoutMs: options.timeoutMs || 3_500
  }).catch(() => null);
  if (Array.isArray(data?.pairs) && data.pairs.length) return data.pairs;
  // `200 {"pairs":null}` = DexScreener's answer for an unindexed token AND (sometimes) a rate-limited IP —
  // indistinguishable. Try the newer v1 endpoint (separately limited) before giving up, and log (1/min) so
  // "everything blank" is diagnosable from Render logs instead of looking like a data bug.
  const alt = await fetchJson(`https://api.dexscreener.com/tokens/v1/solana/${encodeURIComponent(mint)}`, {
    headers: { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" },
    timeoutMs: options.timeoutMs || 3_500
  }).catch(() => null);
  const altPairs = Array.isArray(alt) ? alt : (Array.isArray(alt?.pairs) ? alt.pairs : []);
  if (altPairs.length) return altPairs;
  if (data && data.pairs === null && Date.now() - _dsSoftBlockLogAt > 60_000) {
    _dsSoftBlockLogAt = Date.now();
    try { console.warn(`[dexscreener] empty (200 + pairs:null) for ${shortMint(mint)} — unindexed or rate-limited; scans lean on Gecko/SolanaTracker/pump/cache`); } catch { /* logging is best-effort */ }
  }
  return [];
}

function bestDexPairForToken(tokenMint, pairs) {
  const matching = (pairs || []).filter((pair) => pairMatchesToken(pair, tokenMint));
  // CORRUPT-LISTING GUARD: DexScreener sometimes carries a broken pair whose reported marketCap is
  // wildly off (live case: BONK's deepest-liq pair was a Meteora listing with mc $1.744T — 1000× real —
  // liq $40.67M and NO h1, so it won the liquidity sort and poisoned MC/LIQ/1H on the card). When 3+
  // pairs exist, drop any pair whose mc/fdv disagrees with the MEDIAN across pairs by >5× before sorting.
  let candidates = matching;
  if (matching.length >= 3) {
    const mcs = matching.map((p) => Number(p?.marketCap || p?.fdv) || 0).filter((v) => v > 0).sort((a, b) => a - b);
    if (mcs.length >= 3) {
      const median = mcs[Math.floor(mcs.length / 2)];
      const sane = matching.filter((p) => {
        const mc = Number(p?.marketCap || p?.fdv) || 0;
        return !(mc > 0) || (mc / median <= 5 && median / mc <= 5);   // no-mc pairs pass; wild outliers drop
      });
      if (sane.length) candidates = sane;
    }
  }
  return candidates.sort(compareDexPairsForSniper)[0] || null;
}

function pairMatchesToken(pair, tokenMint) {
  return pair?.baseToken?.address === tokenMint || pair?.quoteToken?.address === tokenMint;
}

function compareDexPairsForSniper(a, b) {
  return Number(b?.liquidity?.usd || 0) - Number(a?.liquidity?.usd || 0)
    || Number(b?.volume?.h1 || 0) - Number(a?.volume?.h1 || 0)
    || Number(b?.marketCap || b?.fdv || 0) - Number(a?.marketCap || a?.fdv || 0);
}

function metadataFromDexPair(tokenMint, best = null) {
  const token = best?.baseToken?.address === tokenMint ? best.baseToken : best?.quoteToken || best?.baseToken || {};
  const links = dexPairLinks(best);
  const dexId = firstString(best?.dexId, best?.dexName);
  const pairAddress = firstString(best?.pairAddress, best?.address);
  const raydiumPool = /raydium|meteora|orca/i.test(dexId) ? pairAddress : "";
  const graduated = Boolean(
    raydiumPool
    && isPumpStyleToken({ tokenMint, symbol: token.symbol, name: token.name })
  );

  return {
    symbol: token.symbol || "",
    name: token.name || "",
    imageUrl: firstString(
      best?.info?.imageUrl,
      best?.info?.image,
      best?.info?.logo,
      best?.imageUrl,
      best?.image,
      token.imageUrl,
      token.image,
      token.logoURI,
      token.logo
    ),
    websiteUrl: links.websiteUrl,
    twitterUrl: links.twitterUrl,
    telegramUrl: links.telegramUrl,
    marketCap: firstMeaningfulNumber(
      best?.marketCap,
      best?.marketCapUsd,
      best?.market_cap_usd,
      best?.fdv,
      token.marketCap,
      token.marketCapUsd,
      token.fdv
    ),
    fdv: firstNumber(best?.fdv),
    priceChange: best?.priceChange || null,
    liquidityUsd: firstNumber(best?.liquidity?.usd),
    volume: best?.volume || null,
    txns: best?.txns || null,
    pairCreatedAt: normalizePairCreatedAt(firstString(
      best?.pairCreatedAt,
      best?.pairCreatedTimestamp,
      best?.createdAt,
      best?.created_at,
      best?.poolCreatedAt,
      best?.pool_created_at,
      best?.listedAt,
      best?.listed_at
    )) || null,
    dexId,
    dexName: dexId,
    pairAddress,
    pairUrl: firstString(best?.url),
    raydiumPool,
    graduated,
    isGraduated: graduated
  };
}

function mergeTokenMarketMetadata(primary = null, fallback = null) {
  if (!fallback || typeof fallback !== "object") return primary || null;
  if (!primary || typeof primary !== "object") return { ...fallback };
  const priceChange = { ...((fallback && fallback.priceChange) || {}), ...((primary && primary.priceChange) || {}) };
  const volume = { ...((fallback && fallback.volume) || {}), ...((primary && primary.volume) || {}) };
  const txns = { ...((fallback && fallback.txns) || {}), ...((primary && primary.txns) || {}) };
  return {
    ...fallback,
    ...primary,
    symbol: firstString(primary.symbol, fallback.symbol),
    name: firstString(primary.name, fallback.name),
    imageUrl: firstString(primary.imageUrl, primary.imageUri, fallback.imageUrl, fallback.imageUri),
    websiteUrl: firstString(primary.websiteUrl, fallback.websiteUrl),
    twitterUrl: firstString(primary.twitterUrl, fallback.twitterUrl),
    telegramUrl: firstString(primary.telegramUrl, fallback.telegramUrl),
    marketCap: firstMeaningfulNumber(primary.marketCap, fallback.marketCap, fallback.fdv),
    fdv: firstMeaningfulNumber(primary.fdv, fallback.fdv),
    priceUsd: firstMeaningfulNumber(primary.priceUsd, fallback.priceUsd),
    liquidityUsd: firstMeaningfulNumber(primary.liquidityUsd, fallback.liquidityUsd),
    // carry AGE + holder-count through the merge (were being dropped → "age n/a"/blank holders on the merged meta)
    pairCreatedAt: firstMeaningfulNumber(primary.pairCreatedAt, fallback.pairCreatedAt) || primary.pairCreatedAt || fallback.pairCreatedAt || null,
    holderCount: firstMeaningfulNumber(primary.holderCount, primary.holders, fallback.holderCount, fallback.holders) || null,
    priceChange: Object.keys(priceChange).length ? priceChange : null,
    volume: Object.keys(volume).length ? volume : null,
    txns: Object.keys(txns).length ? txns : null,
  };
}

function dexPairLinks(pair = null) {
  const websites = Array.isArray(pair?.info?.websites) ? pair.info.websites : [];
  const socials = Array.isArray(pair?.info?.socials) ? pair.info.socials : [];
  const websiteUrl = firstString(
    websites.find((item) => /website|site|web/i.test(item?.label || ""))?.url,
    websites[0]?.url
  );
  const twitterUrl = firstString(
    socials.find((item) => /twitter|x/i.test(item?.type || item?.label || ""))?.url,
    socials.find((item) => /twitter\.com|x\.com/i.test(item?.url || ""))?.url
  );
  const telegramUrl = firstString(
    socials.find((item) => /telegram|tg/i.test(item?.type || item?.label || ""))?.url,
    socials.find((item) => /t\.me|telegram/i.test(item?.url || ""))?.url
  );
  return { websiteUrl, twitterUrl, telegramUrl };
}

function heliusDasEnabled() {
  if (!CONFIG.heliusDasEnrichmentEnabled || !CONFIG.rpcUrl) return false;
  return /helius/i.test(`${CONFIG.rpcProviderName || ""} ${CONFIG.rpcUrlHost || ""} ${CONFIG.rpcUrl || ""}`);
}

function heliusDasExternalKey(mint = "") {
  return externalCacheKey(`helius:das:${String(mint || "").trim().toLowerCase()}`, "global");
}

function metadataFromHeliusDasAsset(mint = "", asset = null) {
  if (!asset || typeof asset !== "object") return {};
  const content = asset.content || {};
  const metadata = content.metadata || {};
  const links = content.links || {};
  const files = Array.isArray(content.files) ? content.files : [];
  const imageFile = files.find((file) => /image/i.test(String(file?.mime || file?.type || ""))) || files[0] || {};
  const tokenInfo = asset.token_info || {};
  const priceInfo = tokenInfo.price_info || {};
  const creators = Array.isArray(asset.creators) ? asset.creators : [];
  const authorities = Array.isArray(asset.authorities) ? asset.authorities : [];
  const verifiedCreator = creators.find((creator) => creator?.verified && solanaPublicKeyLike(creator?.address)) || creators.find((creator) => solanaPublicKeyLike(creator?.address)) || {};
  const metadataAuthority = firstString(
    authorities.find((authority) => solanaPublicKeyLike(authority?.address))?.address,
    asset.update_authority,
    asset.updateAuthority
  );
  const mintAuthority = firstString(tokenInfo.mint_authority, tokenInfo.mintAuthority);
  const freezeAuthority = firstString(tokenInfo.freeze_authority, tokenInfo.freezeAuthority);
  const riskFlags = uniqueStrings([
    mintAuthority ? "Mint authority is still set in token metadata." : "",
    freezeAuthority ? "Freeze authority is still set in token metadata." : "",
    asset.mutable === true ? "Token metadata is mutable." : ""
  ]);
  const imageUrl = normalizeTokenAvatarUrl(firstString(
    links.image,
    links.imageUrl,
    metadata.image,
    metadata.image_url,
    imageFile.cdn_uri,
    imageFile.uri
  ));
  return {
    tokenMint: mint,
    mint,
    symbol: firstString(metadata.symbol, tokenInfo.symbol, asset.symbol),
    name: firstString(metadata.name, tokenInfo.name, asset.name),
    description: firstString(metadata.description, content.description),
    avatarUrl: imageUrl,
    imageUrl,
    metadataUri: firstString(content.json_uri, content.jsonUri, metadata.uri),
    websiteUrl: firstString(links.external_url, links.externalUrl, links.website, links.websiteUrl, metadata.external_url, metadata.website),
    twitterUrl: firstString(links.twitter, links.x, links.twitterUrl, metadata.twitter, metadata.x),
    telegramUrl: firstString(links.telegram, links.telegramUrl, metadata.telegram),
    decimals: firstMeaningfulNumber(tokenInfo.decimals),
    totalSupply: firstMeaningfulNumber(tokenInfo.supply, asset.supply?.print_current_supply),
    priceUsd: firstMeaningfulNumber(priceInfo.price_per_token, priceInfo.priceUsd, priceInfo.value),
    creatorWallet: firstString(verifiedCreator.address),
    creator: firstString(verifiedCreator.address),
    metadataAuthority,
    updateAuthority: metadataAuthority,
    mintAuthority,
    freezeAuthority,
    riskFlags,
    heliusDasIndexedAt: asset.last_indexed_slot ? `slot ${asset.last_indexed_slot}` : "",
    source: "helius-das"
  };
}

async function fetchHeliusDasTokenMetadata(mint = "", options = {}) {
  const cleanMint = String(mint || "").trim();
  if (!cleanMint || !solanaPublicKeyLike(cleanMint) || !heliusDasEnabled()) return {};
  const ttlMs = Math.max(60_000, Number(options.ttlMs || CONFIG.heliusDasCacheTtlMs));
  const cached = heliusDasAssetCache.get(cleanMint);
  if (!options.force && cached && Date.now() - Number(cached.cachedAt || 0) < ttlMs) {
    return cached.value || {};
  }
  const external = !options.force ? await cacheGetJson(heliusDasExternalKey(cleanMint)).catch(() => null) : null;
  if (external?.value && Number.isFinite(Number(external.cachedAt)) && Date.now() - Number(external.cachedAt) < ttlMs) {
    heliusDasAssetCache.set(cleanMint, { cachedAt: Number(external.cachedAt), value: external.value });
    return external.value;
  }
  const timeoutMs = Math.max(500, Math.min(5_000, Number(options.timeoutMs || CONFIG.heliusDasTimeoutMs)));
  try {
    const response = await rpcWithRetry("helius das getAsset", () => fetchJson(CONFIG.rpcUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "application/json"
      },
      body: JSON.stringify({
        jsonrpc: "2.0",
        id: "slimewire-devinfo",
        method: "getAsset",
        params: {
          id: cleanMint
        }
      }),
      timeoutMs
    }), 1, { priority: false });
    if (response?.error) throw new Error(providerErrorValue(response.error) || "Helius DAS returned an error");
    const value = metadataFromHeliusDasAsset(cleanMint, response?.result);
    if (Object.keys(value).length) {
      heliusDasAssetCache.set(cleanMint, { cachedAt: Date.now(), value });
      await cacheSetJson(heliusDasExternalKey(cleanMint), displayCacheEnvelope(value), ttlMs).catch(() => false);
    }
    return value;
  } catch (error) {
    const value = { tokenMint: cleanMint, mint: cleanMint, source: "helius-das", metadataMissing: true };
    heliusDasAssetCache.set(cleanMint, { cachedAt: Date.now(), value });
    logCacheEvent({
      cacheName: `helius-das:${cleanMint}`,
      action: "miss",
      provider: "helius",
      cacheHit: false,
      error: safePerfEventText(error?.message || "Helius DAS metadata unavailable", 120)
    });
    return {};
  }
}

function geckoTerminalHandleUrl(value = "", kind = "x") {
  const text = String(value || "").trim();
  if (!text) return "";
  if (/^https?:\/\//i.test(text)) return text;
  const handle = text.replace(/^@+/, "").replace(/^\/+/, "").trim();
  if (!handle) return "";
  if (kind === "telegram") return `https://t.me/${handle}`;
  return `https://x.com/${handle}`;
}

function geckoTerminalVolumeObject(attributes = {}) {
  const volume = attributes.volume_usd || attributes.volumeUsd || attributes.volume || {};
  return {
    m5: firstMeaningfulNumber(volume.m5, volume["5m"], attributes.volume5m, attributes.volume_m5) || 0,
    m15: firstMeaningfulNumber(volume.m15, volume.m15m, volume["15m"], attributes.volume15m, attributes.volume_m15) || 0,
    m30: firstMeaningfulNumber(volume.m30, volume.m30m, volume["30m"], attributes.volume30m, attributes.volume_m30) || 0,
    h1: firstMeaningfulNumber(volume.h1, volume["1h"], attributes.volumeH1, attributes.volume_h1) || 0,
    h24: firstMeaningfulNumber(volume.h24, volume.d1, volume["24h"], attributes.volumeH24, attributes.volume_h24) || 0
  };
}

function geckoTerminalTxnsObject(attributes = {}) {
  const transactions = attributes.transactions || attributes.txns || {};
  return {
    m5: {
      buys: firstNumber(transactions.m5?.buys, transactions["5m"]?.buys, attributes.buys5m) || 0,
      sells: firstNumber(transactions.m5?.sells, transactions["5m"]?.sells, attributes.sells5m) || 0
    },
    h1: {
      buys: firstNumber(transactions.h1?.buys, transactions["1h"]?.buys, attributes.buysH1, attributes.buys) || 0,
      sells: firstNumber(transactions.h1?.sells, transactions["1h"]?.sells, attributes.sellsH1, attributes.sells) || 0
    }
  };
}

async function getGeckoTerminalTokenMetadata(tokenMint, options = {}) {
  const mint = String(tokenMint || "").trim();
  if (!mint) return {};
  const cacheTtlMs = Number.isFinite(Number(options.cacheTtlMs)) ? Number(options.cacheTtlMs) : 5 * 60 * 1000;
  const cached = geckoTerminalMetadataCache.get(mint);
  if (!options.force && cached && Date.now() - cached.cachedAt < cacheTtlMs) {
    return cached.value;
  }

  const headers = {
    "Accept": "application/json",
    "User-Agent": "solana-telegram-wallet-ops-bot"
  };
  const baseUrl = "https://api.geckoterminal.com/api/v2/networks/solana";
  const timeoutMs = options.timeoutMs || 2_500;
  const [infoResult, poolsResult] = await Promise.allSettled([
    fetchJson(`${baseUrl}/tokens/${encodeURIComponent(mint)}/info`, { headers, timeoutMs }),
    fetchJson(`${baseUrl}/tokens/${encodeURIComponent(mint)}/pools?page=1&limit=5`, { headers, timeoutMs })
  ]);
  const infoData = infoResult.status === "fulfilled" ? infoResult.value : null;
  const poolsData = poolsResult.status === "fulfilled" ? poolsResult.value : null;
  const attributes = infoData?.data?.attributes || infoData?.attributes || {};
  const pools = arrayFromApiData(poolsData)
    .map((pool) => ({ pool, attributes: pool?.attributes || pool || {} }))
    .sort((a, b) => (
      (firstMeaningfulNumber(b.attributes.reserve_in_usd, b.attributes.reserveUsd, b.attributes.liquidity_usd, b.attributes.liquidityUsd) || 0)
      - (firstMeaningfulNumber(a.attributes.reserve_in_usd, a.attributes.reserveUsd, a.attributes.liquidity_usd, a.attributes.liquidityUsd) || 0)
    ) || (
      (firstMeaningfulNumber(b.attributes.volume_usd?.h24, b.attributes.volumeUsd?.h24, b.attributes.volumeH24) || 0)
      - (firstMeaningfulNumber(a.attributes.volume_usd?.h24, a.attributes.volumeUsd?.h24, a.attributes.volumeH24) || 0)
    ));
  const bestPool = pools[0]?.pool || null;
  const poolAttributes = pools[0]?.attributes || {};
  const websiteUrl = firstString(
    Array.isArray(attributes.websites) ? attributes.websites[0] : "",
    attributes.website_url,
    attributes.websiteUrl
  );
  const twitterUrl = firstString(
    geckoTerminalHandleUrl(attributes.twitter_handle || attributes.twitter || attributes.x_handle || attributes.x, "x"),
    attributes.twitter_url,
    attributes.x_url
  );
  const telegramUrl = firstString(
    geckoTerminalHandleUrl(attributes.telegram_handle || attributes.telegram, "telegram"),
    attributes.telegram_url
  );
  const volume = geckoTerminalVolumeObject(poolAttributes);
  const value = {
    tokenMint: mint,
    source: "geckoterminal",
    symbol: firstString(attributes.symbol, poolAttributes.base_token_symbol, poolAttributes.name),
    name: firstString(attributes.name, poolAttributes.base_token_name, poolAttributes.name),
    imageUrl: firstString(attributes.image_url, attributes.imageUrl, attributes.image, poolAttributes.image_url, poolAttributes.imageUrl),
    imageUri: firstString(attributes.image_url, attributes.imageUrl, attributes.image, poolAttributes.image_url, poolAttributes.imageUrl),
    websiteUrl,
    twitterUrl,
    telegramUrl,
    marketCap: firstMeaningfulNumber(poolAttributes.market_cap_usd, poolAttributes.marketCapUsd, attributes.market_cap_usd, attributes.marketCapUsd, poolAttributes.fdv_usd, poolAttributes.fdvUsd) || null,
    fdv: firstMeaningfulNumber(poolAttributes.fdv_usd, poolAttributes.fdvUsd, poolAttributes.fdv, attributes.fdv_usd, attributes.fdvUsd) || null,
    liquidityUsd: firstMeaningfulNumber(poolAttributes.reserve_in_usd, poolAttributes.reserveUsd, poolAttributes.liquidity_usd, poolAttributes.liquidityUsd) || null,
    priceUsd: firstMeaningfulNumber(poolAttributes.base_token_price_usd, poolAttributes.price_usd, attributes.price_usd, attributes.priceUsd) || null,
    volume,
    txns: geckoTerminalTxnsObject(poolAttributes),
    priceChange: poolAttributes.price_change_percentage || poolAttributes.priceChange || null,
    pairCreatedAt: normalizePairCreatedAt(firstString(poolAttributes.pool_created_at, poolAttributes.poolCreatedAt, poolAttributes.created_at, poolAttributes.createdAt)) || null,
    pairAddress: firstString(bestPool?.id, poolAttributes.address, poolAttributes.pool_address, poolAttributes.pairAddress).replace(/^solana_/, ""),
    pairUrl: firstString(poolAttributes.url, bestPool?.id ? `https://www.geckoterminal.com/solana/pools/${String(bestPool.id).replace(/^solana_/, "")}` : ""),
    metadataMissing: !firstString(attributes.image_url, attributes.imageUrl, attributes.image)
  };
  geckoTerminalMetadataCache.set(mint, { cachedAt: Date.now(), value });
  return value;
}


// Pump.fun creator launches: the dev's own history straight from the source. Cached
// 10 minutes; this is what fills Dev Info for the pump tokens that dominate the feeds.
const pumpFunCreatorCache = new Map();
async function getPumpFunCreatorLaunches(creator, options = {}) {
  const key = String(creator || "").trim();
  if (!key) return [];
  const cached = pumpFunCreatorCache.get(key);
  if (cached && Date.now() - cached.at < 10 * 60 * 1000) return cached.value;
  const headers = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  if (CONFIG.pumpFunApiToken) headers.Authorization = `Bearer ${CONFIG.pumpFunApiToken}`;
  let launches = [];
  for (const base of [CONFIG.pumpFunApiBase, "https://frontend-api-v3.pump.fun"].filter((value, index, list) => value && list.indexOf(value) === index)) {
    try {
      const cleanBase = String(base).replace(/\/$/, "");
      let data = await fetchJson(`${cleanBase}/coins/user-created-coins/${encodeURIComponent(key)}?offset=0&limit=10&includeNsfw=false`, { headers, timeoutMs: options.timeoutMs || 3_500 })
        .catch(() => null);
      if (!data || (Array.isArray(data) && !data.length)) {
        data = await fetchJson(`${cleanBase}/coins/user-created-coins?creator=${encodeURIComponent(key)}&offset=0&limit=10`, { headers, timeoutMs: options.timeoutMs || 3_500 }).catch(() => null);
      }
      if (!data) continue;
      const list = Array.isArray(data) ? data : (Array.isArray(data?.coins) ? data.coins : []);
      launches = list.map((coin) => ({
        mint: firstString(coin?.mint, coin?.address),
        symbol: firstString(coin?.symbol, coin?.ticker),
        name: firstString(coin?.name),
        marketCap: firstMeaningfulNumber(coin?.usd_market_cap, coin?.market_cap, coin?.marketCap),
        complete: Boolean(coin?.complete),
        createdTimestamp: firstMeaningfulNumber(coin?.created_timestamp, coin?.createdTimestamp)
      })).filter((coin) => coin.mint);
      break;
    } catch {
      // try the next base
    }
  }
  pumpFunCreatorCache.set(key, { at: Date.now(), value: launches });
  if (pumpFunCreatorCache.size > 200) {
    const oldest = [...pumpFunCreatorCache.entries()].sort((a, b) => a[1].at - b[1].at)[0]?.[0];
    if (oldest) pumpFunCreatorCache.delete(oldest);
  }
  return launches;
}

// Bonding-curve market read shaped like a DexScreener pair, so every client path
// (chart bar, /t page, pair-lite race) renders pump.fun numbers identically to
// graduated tokens. Returns null when pump.fun doesn't know the mint either.
async function pumpCurvePairFallback(tokenMint, options = {}) {
  const pump = await getPumpFunTokenMetadata(tokenMint, { cacheTtlMs: 15_000, timeoutMs: options.timeoutMs || 3_000 }).catch(() => null);
  if (!pump || (!pump.marketCap && !pump.priceUsd && !pump.virtualSolReserves)) return null;
  // SOL/USD from the coin payload itself (usd_market_cap / market_cap-in-SOL):
  // zero extra requests, and immune to the DexScreener shared-IP rate limit that
  // makes getSolUsdPrice flaky on Render.
  const usdMc = Number(pump.usdMarketCap) || Number(pump.marketCap) || 0;
  const solMc = Number(pump.marketCapSol) || 0;
  const solUsd = (usdMc > 0 && solMc > 0 && solMc < usdMc)
    ? usdMc / solMc
    : await getSolUsdPrice({ timeoutMs: 1_500 }).catch(() => null);
  // virtual_sol_reserves is lamports when it's a huge integer.
  const rawVirtualSol = Number(pump.virtualSolReserves) || 0;
  const virtualSol = rawVirtualSol > 1e6 ? rawVirtualSol / 1e9 : rawVirtualSol;
  const liquidityUsd = Number(pump.liquidityUsd)
    || (virtualSol && Number.isFinite(solUsd) && solUsd > 0 ? Math.round(virtualSol * solUsd) : null);
  // Pump supply is 1B tokens; MC/1e9 recovers price when the API omits it.
  const priceUsd = Number(pump.priceUsd) || (Number(pump.marketCap) ? Number(pump.marketCap) / 1e9 : null);
  // Bonding progress: ~85 real SOL graduates a pump curve.
  const rawRealSol = Number(pump.realSolReserves) || 0;
  const realSol = rawRealSol > 1e6 ? rawRealSol / 1e9 : rawRealSol;
  const bondingProgressPct = Number(pump.bondingProgressPct)
    || (realSol ? Math.min(100, Math.round((realSol / 85) * 100)) : null);
  return {
    tokenMint,
    baseToken: { symbol: pump.symbol || "", name: pump.name || "" },
    priceUsd,
    marketCap: Number(pump.marketCap) || null,
    fdv: Number(pump.marketCap) || null,
    liquidity: { usd: liquidityUsd },
    volume: { h24: Number(pump.volume?.h24) || null, h1: Number(pump.volume?.h1) || null },
    priceChange: { h1: Number(pump.priceChange?.h1) ?? null },
    info: { imageUrl: pump.imageUrl || "" },
    url: `https://pump.fun/coin/${tokenMint}`,
    pairAddress: "",
    dexId: "pump-curve",
    pumpCurve: true,
    bondingProgressPct
  };
}

// pump.fun stores creator-entered socials (usually full URLs, occasionally a bare @handle or domain).
// Normalize to a clickable absolute URL so the terminal's social icons always render a working link.
function normalizeSocialLink(value, kind) {
  let s = String(value || "").trim();
  if (!s) return "";
  if (/^https?:\/\//i.test(s)) return s;
  s = s.replace(/^@/, "");
  if (kind === "twitter") return `https://x.com/${s.replace(/^(?:www\.)?(?:x|twitter)\.com\//i, "")}`;
  if (kind === "telegram") return `https://t.me/${s.replace(/^(?:www\.)?t\.me\//i, "")}`;
  return /\./.test(s) ? `https://${s}` : "";
}

// The DEFINITIVE socials source for fresh pump coins: their off-chain metadata JSON (the token's
// json_uri / metadata uri). pump.fun's own API blocks Render's datacenter IP, but the metadata JSON
// lives on IPFS/Arweave and is fetchable from anywhere — and it holds twitter/telegram/website at the
// top level. We only hit this when nothing else gave us socials. Cached 30min per mint (one fetch each).
const offchainSocialsCache = new Map();
async function fetchOffchainTokenSocials(metadataUri = "", cacheKey = "") {
  const uri = String(metadataUri || "").trim();
  if (!uri) return {};
  const key = String(cacheKey || uri);
  const cached = offchainSocialsCache.get(key);
  if (cached && Date.now() - cached.at < 30 * 60 * 1000) return cached.socials;
  let socials = {};
  try {
    let fetched = null;
    for (const candidate of metadataUriGatewayCandidates(uri)) {
      try { fetched = await fetchTextWithBackoff(candidate, { timeoutMs: 2_500, retries: 0 }); break; }
      catch { /* try the next gateway */ }
    }
    if (fetched && fetched.text) {
      const meta = JSON.parse(fetched.text);
      if (meta && typeof meta === "object" && !Array.isArray(meta)) {
        socials = {
          twitterUrl: normalizeSocialLink(firstString(meta.twitter, meta.x, meta.twitter_url, meta.twitterUrl), "twitter"),
          telegramUrl: normalizeSocialLink(firstString(meta.telegram, meta.telegram_url, meta.telegramUrl), "telegram"),
          websiteUrl: normalizeSocialLink(firstString(meta.website, meta.website_url, meta.websiteUrl, meta.external_url), "website")
        };
      }
    }
  } catch { socials = {}; }
  offchainSocialsCache.set(key, { at: Date.now(), socials });
  if (offchainSocialsCache.size > 1000) {
    const oldest = [...offchainSocialsCache.entries()].sort((a, b) => a[1].at - b[1].at).slice(0, 300);
    for (const [k] of oldest) offchainSocialsCache.delete(k);
  }
  return socials;
}

async function getPumpFunTokenMetadata(tokenMint, options = {}) {
  const mint = String(tokenMint || "").trim();
  if (!mint) return {};
  const cacheTtlMs = Number.isFinite(Number(options.cacheTtlMs)) ? Number(options.cacheTtlMs) : 30_000;
  const cached = pumpFunMetadataCache.get(mint);
  if (!options.force && cached && Date.now() - cached.cachedAt < cacheTtlMs) {
    return cached.value;
  }

  const publicHeaders = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const authedHeaders = { ...publicHeaders };
  if (CONFIG.pumpFunApiToken) {
    authedHeaders.Authorization = `Bearer ${CONFIG.pumpFunApiToken}`;
  }

  const bases = [
    CONFIG.pumpFunApiBase,
    "https://frontend-api-v3.pump.fun",
    "https://frontend-api.pump.fun"
  ].filter((base, index, list) => base && list.indexOf(base) === index);
  let response = null;
  let lastError = null;
  for (const base of bases) {
    const url = `${String(base).replace(/\/$/, "")}/coins/${encodeURIComponent(mint)}?sync=false`;
    const headerAttempts = CONFIG.pumpFunApiToken ? [authedHeaders, publicHeaders] : [publicHeaders];
    for (const headers of headerAttempts) {
      try {
        response = await fetchJson(url, { headers, timeoutMs: options.timeoutMs || 3_500 });
        break;
      } catch (error) {
        lastError = error;
      }
    }
    if (response) break;
  }
  if (!response && lastError) throw lastError;
  const coin = response?.data || response;
  const volume = typeof coin?.volume === "object" && coin.volume !== null ? coin.volume : {};
  const txns = typeof coin?.txns === "object" && coin.txns !== null ? coin.txns : {};
  const transactions = typeof coin?.transactions === "object" && coin.transactions !== null ? coin.transactions : {};
  const raydiumPool = firstString(coin?.raydium_pool, coin?.raydiumPool, coin?.poolAddress, coin?.pool, coin?.amm_pool);
  // ACCURATE bonding progress from on-curve reserves. pump.fun sells 793.1M tokens from
  // the curve to graduate; real_token_reserves (raw, 6 decimals) falls from 793.1M -> 0.
  // progress = (1 - reserves/793.1M) * 100. This is exact — the API "progress" fields are
  // unreliable and an MC/$69k proxy is wrong (the curve is nonlinear: a $25k coin can be 96%).
  const realTokenReservesRaw = firstMeaningfulNumber(coin?.real_token_reserves, coin?.realTokenReserves) || 0;
  let bondingFromReserves = null;
  if (realTokenReservesRaw > 0) {
    const rtrUi = realTokenReservesRaw >= 1e9 ? realTokenReservesRaw / 1e6 : realTokenReservesRaw;
    bondingFromReserves = Math.max(0, Math.min(100, (1 - rtrUi / 793_100_000) * 100));
  }
  const apiBondingPct = firstMeaningfulNumber(
    coin?.bondingProgressPct,
    coin?.bondingProgress,
    coin?.bonding_curve_progress,
    coin?.bondingCurveProgress,
    coin?.progress,
    coin?.pumpProgress,
    coin?.graduationProgress,
    coin?.completion,
    coin?.completePct
  );
  // Prefer the reserves math; only fall back to an API field if it's a sane 0-100 value.
  const bondingProgressPct = bondingFromReserves != null
    ? bondingFromReserves
    : (apiBondingPct != null && apiBondingPct >= 0 && apiBondingPct <= 100 ? apiBondingPct : 0);
  const graduated = Boolean(
    coin?.complete
    || coin?.completed
    || coin?.bonded
    || coin?.isBonded
    || coin?.graduated
    || coin?.isGraduated
    || raydiumPool
  );

  const value = {
    symbol: coin?.symbol || "",
    name: coin?.name || "",
    imageUrl: firstString(coin?.image_uri, coin?.imageUri, coin?.imageUrl, coin?.image_url, coin?.image, coin?.metadata?.image, coin?.metadata?.imageUrl, coin?.logoURI, coin?.logo),
    imageUri: firstString(coin?.image_uri, coin?.imageUri, coin?.imageUrl, coin?.image_url, coin?.image, coin?.metadata?.image, coin?.metadata?.imageUrl, coin?.logoURI, coin?.logo),
    metadataUri: firstString(coin?.metadata_uri, coin?.metadataUri, coin?.uri, coin?.metadata?.uri),
    // Creator-entered socials. pump.fun has these the instant a coin launches — long before
    // DexScreener lists it — so this is what fills the social icons on the freshest Trenches rows.
    twitterUrl: normalizeSocialLink(firstString(coin?.twitter, coin?.twitterUrl, coin?.twitter_url, coin?.x, coin?.metadata?.twitter, coin?.metadata?.x), "twitter"),
    telegramUrl: normalizeSocialLink(firstString(coin?.telegram, coin?.telegramUrl, coin?.telegram_url, coin?.metadata?.telegram), "telegram"),
    websiteUrl: normalizeSocialLink(firstString(coin?.website, coin?.websiteUrl, coin?.website_url, coin?.metadata?.website, coin?.metadata?.external_url), "website"),
    creatorWallet: firstString(coin?.creator, coin?.creatorWallet, coin?.creator_wallet, coin?.creatorPublicKey, coin?.creator_public_key, coin?.deployer, coin?.deployerWallet, coin?.launchWallet),
    creator: firstString(coin?.creator, coin?.creatorWallet, coin?.creator_wallet, coin?.creatorPublicKey, coin?.creator_public_key),
    deployerWallet: firstString(coin?.deployerWallet, coin?.deployer_wallet, coin?.deployer),
    poolCreator: firstString(coin?.poolCreator, coin?.pool_creator, coin?.pairCreator, coin?.pair_creator),
    initialLiquidityWallet: firstString(coin?.initialLiquidityWallet, coin?.initial_liquidity_wallet, coin?.liquidityProvider, coin?.liquidity_provider),
    source: "pumpfun",
    priceSol: firstMeaningfulNumber(coin?.priceSol, coin?.price_sol, coin?.priceNative, coin?.price_native, coin?.priceInSol) || null,
    priceUsd: firstMeaningfulNumber(coin?.priceUsd, coin?.price_usd, coin?.usdPrice, coin?.priceUSD, coin?.price) || null,
    virtualSolReserves: firstMeaningfulNumber(coin?.virtual_sol_reserves, coin?.virtualSolReserves) || null,
    virtualTokenReserves: firstMeaningfulNumber(coin?.virtual_token_reserves, coin?.virtualTokenReserves) || null,
    realSolReserves: firstMeaningfulNumber(coin?.real_sol_reserves, coin?.realSolReserves) || null,
    // market_cap is SOL-denominated on the pump.fun API (usd_market_cap is USD);
    // their ratio recovers SOL/USD with zero extra requests.
    marketCapSol: firstMeaningfulNumber(coin?.market_cap, coin?.marketCapSol) || null,
    marketCap: firstMeaningfulNumber(coin?.usd_market_cap, coin?.usdMarketCap, coin?.marketCapUsd, coin?.market_cap_usd, coin?.market_cap, coin?.marketCap, coin?.currentMarketCap, coin?.current_market_cap, coin?.fdv, coin?.mcap, coin?.mc) || null,
    usdMarketCap: firstMeaningfulNumber(coin?.usd_market_cap, coin?.usdMarketCap, coin?.marketCapUsd, coin?.market_cap_usd, coin?.market_cap, coin?.marketCap, coin?.currentMarketCap, coin?.current_market_cap, coin?.fdv, coin?.mcap, coin?.mc) || null,
    fdv: firstMeaningfulNumber(coin?.fdv, coin?.fullyDilutedValuation, coin?.marketCap, coin?.marketCapUsd, coin?.usdMarketCap, coin?.usd_market_cap, coin?.market_cap_usd, coin?.market_cap, coin?.mcap, coin?.mc) || null,
    totalSupply: firstMeaningfulNumber(coin?.total_supply, coin?.totalSupply, coin?.supply, coin?.tokenSupply, coin?.token_supply) || null,
    tokenSupply: firstMeaningfulNumber(coin?.tokenSupply, coin?.token_supply, coin?.totalSupply, coin?.total_supply, coin?.supply) || null,
    supply: firstMeaningfulNumber(coin?.supply, coin?.total_supply, coin?.totalSupply, coin?.tokenSupply, coin?.token_supply) || null,
    liquidityUsd: firstMeaningfulNumber(coin?.liquidity_usd, coin?.liquidityUsd, coin?.liquidityUSD, coin?.liquidity?.usd, coin?.liquidity, coin?.currentLiquidityUsd, coin?.current_liquidity_usd, coin?.poolLiquidityUsd, coin?.pool_liquidity_usd) || null,
    volume: {
      m5: firstMeaningfulNumber(volume.m5, volume["5m"], coin?.volume5m, coin?.volume_5m, coin?.volumeM5, coin?.volume_m5) || 0,
      m15: firstMeaningfulNumber(volume.m15, volume.m15m, volume["15m"], coin?.volume15m, coin?.volume_15m, coin?.volumeM15, coin?.volume_m15) || 0,
      m30: firstMeaningfulNumber(volume.m30, volume.m30m, volume["30m"], coin?.volume30m, coin?.volume_30m, coin?.volumeM30, coin?.volume_m30) || 0,
      h1: firstMeaningfulNumber(volume.h1, volume["1h"], coin?.volumeH1, coin?.volume_h1, coin?.volume_1h, coin?.volumeH, coin?.volume) || 0,
      h24: firstMeaningfulNumber(volume.h24, volume.d1, volume["24h"], coin?.volume24h, coin?.volume_h24, coin?.volume_24h, coin?.volumeH24, coin?.volume_d1) || 0
    },
    txns: {
      m5: {
        buys: firstNumber(txns.m5?.buys, transactions.m5?.buys, coin?.buys5m, coin?.buys_5m) || 0,
        sells: firstNumber(txns.m5?.sells, transactions.m5?.sells, coin?.sells5m, coin?.sells_5m) || 0
      },
      h1: {
        buys: firstNumber(txns.h1?.buys, transactions.h1?.buys, coin?.buysH1, coin?.buys_h1, coin?.buys) || 0,
        sells: firstNumber(txns.h1?.sells, transactions.h1?.sells, coin?.sellsH1, coin?.sells_h1, coin?.sells) || 0
      }
    },
    priceChange: {
      m5: normalizePercentLike(coin?.priceChange?.m5 ?? coin?.price_change_m5 ?? coin?.m5) || 0,
      h1: normalizePercentLike(coin?.priceChange?.h1 ?? coin?.price_change_h1 ?? coin?.h1) || 0,
      h6: normalizePercentLike(coin?.priceChange?.h6 ?? coin?.price_change_h6 ?? coin?.h6) || 0,
      h24: normalizePercentLike(coin?.priceChange?.h24 ?? coin?.price_change_h24 ?? coin?.h24) || 0
    },
    pairCreatedAt: normalizePairCreatedAt(firstString(coin?.created_timestamp, coin?.createdAt, coin?.created_at, coin?.timestamp)),
    bondingProgressPct,
    graduated,
    isGraduated: graduated,
    raydiumPool
  };
  pumpFunMetadataCache.set(mint, { cachedAt: Date.now(), value });
  return value;
}

async function fetchSniperCandidates(options = {}) {
  const ttlMs = Number.isFinite(Number(options.ttlMs)) ? Number(options.ttlMs) : 2_500;
  if (!options.force && ttlMs > 0 && Date.now() - sniperCandidatesCache.cachedAt < ttlMs) {
    return sniperCandidatesCache.value;
  }

  const headers = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const requestOptions = { headers, timeoutMs: options.timeoutMs || 3_500 };
  const [profiles, latestBoosts, topBoosts] = await Promise.all([
    fetchJson("https://api.dexscreener.com/token-profiles/latest/v1", requestOptions).catch(() => []),
    fetchJson("https://api.dexscreener.com/token-boosts/latest/v1", requestOptions).catch(() => []),
    fetchJson("https://api.dexscreener.com/token-boosts/top/v1", requestOptions).catch(() => [])
  ]);

  const value = uniqueSniperCandidates([
    ...sniperCandidatesFromDexList(profiles, "profile"),
    ...sniperCandidatesFromDexList(latestBoosts, "latest-boost"),
    ...sniperCandidatesFromDexList(topBoosts, "top-boost")
  ]);
  sniperCandidatesCache = { cachedAt: Date.now(), value };
  return value;
}

async function fetchSniperCandidatesForMode(mode, options = {}) {
  const safeMode = normalizeSniperMode(mode);
  const [base, search, pumpLatest] = await Promise.all([
    fetchSniperCandidates(options).catch(() => []),
    fetchDexSearchCandidatesForMode(safeMode, options).catch(() => []),
    ["pumpsnipe", "moonshot"].includes(safeMode)
      ? fetchPumpFunLatestCandidates(options).catch(() => [])
      : Promise.resolve([])
  ]);
  const latestFirst = base.filter((candidate) => candidate.source !== "top-boost");
  const topBoostBackup = base.filter((candidate) => candidate.source === "top-boost");
  return uniqueSniperCandidates([...pumpLatest, ...search, ...latestFirst, ...topBoostBackup]);
}

async function fetchDexSearchCandidatesForMode(mode, options = {}) {
  const queries = sniperModeSearchQueries(mode, options.scanState);
  if (queries.length === 0) return [];

  const ttlMs = Number.isFinite(Number(options.searchTtlMs))
    ? Number(options.searchTtlMs)
    : Math.max(1_500, Number(options.ttlMs || 0), 5_000);
  const headers = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const rows = [];

  await runWithConcurrency(queries, 3, async (query) => {
    const cacheKey = `${mode}:${query}`;
    const cached = dexSearchCandidatesCache.get(cacheKey);
    if (!options.force && cached && Date.now() - cached.cachedAt < ttlMs) {
      rows.push(...cached.value);
      return;
    }

    const data = await fetchJson(`https://api.dexscreener.com/latest/dex/search?q=${encodeURIComponent(query)}`, {
      headers,
      timeoutMs: options.timeoutMs || 3_500
    }).catch(() => null);
    const value = sniperCandidatesFromDexPairs(arrayFromApiData(data, ["pairs"]), `search:${mode}:${query}`);
    dexSearchCandidatesCache.set(cacheKey, { cachedAt: Date.now(), value });
    rows.push(...value);
  });

  return uniqueSniperCandidates(rows);
}

function sniperModeSearchQueries(mode, scanState = {}) {
  const querySets = {
    safe: ["solana trending", "solana volume", "raydium solana", "jupiter solana", "bonk solana", "solana community", "solana breakout", "solana movers"],
    smart: ["solana accumulation", "cto solana", "community solana", "smart money solana", "holder solana", "solana steady", "solana reversal", "solana base"],
    fast: ["solana pump", "solana breakout", "solana moon", "solana volume", "send solana", "ape solana", "fast solana", "raydium pump"],
    moonshot: ["pump low cap", "solana low cap", "moon pump", "solana gem", "new pump", "micro cap solana", "low mcap solana", "pumpfun solana"],
    pumpsnipe: ["pump", "pumpfun", "new pump", "fresh pump", "moon pump", "solana pump", "cto pump", "ape pump"],
    meme: ["solana meme", "pepe solana", "cat solana", "dog solana", "frog solana", "bonk meme", "wif solana", "cto meme"],
    ai: ["ai solana", "agent solana", "gpt solana", "robot solana", "compute solana", "neural solana", "ai meme solana", "agent pump"],
    long: ["solana utility", "solana ai", "solana gaming", "solana defi", "solana protocol", "solana community", "solana infra", "solana agent"],
    autosnipe: ["solana breakout", "solana volume", "solana pump", "raydium solana", "pump trending", "solana movers"]
  };
  const list = querySets[mode] || querySets.safe;
  const refreshCount = Number(scanState?.refreshCount || 0);
  const modeSeed = stringModulo(mode, list.length || 1);
  const offset = refreshCount * 2 + modeSeed + Math.floor(Date.now() / 45_000);
  return rotateItems(list, offset).slice(0, mode === "pumpsnipe" || mode === "moonshot" ? 5 : 4);
}

async function fetchPumpSnipeCandidates(options = {}) {
  const [pumpLatest, candidates, search] = await Promise.all([
    fetchPumpFunLatestCandidates(options).catch(() => []),
    fetchSniperCandidates(options),
    fetchDexSearchCandidatesForMode("pumpsnipe", options).catch(() => [])
  ]);
  const latestFirst = candidates.filter((candidate) => candidate.source !== "top-boost");
  const topBoostBackup = candidates.filter((candidate) => candidate.source === "top-boost");
  return uniqueSniperCandidates([...pumpLatest, ...search, ...latestFirst, ...topBoostBackup]);
}

// GeckoTerminal pools — a FREE (no-key) independent source of genuinely-trending, established
// Solana pools across MULTIPLE endpoints. Fixes the "Trending/Surging/Top Volume/Migrated re-rank
// the same ~20-row pool and look identical" problem: each tab now draws a DISTINCT pool —
//   trending → /trending_pools           (the curated trending list)
//   volume   → /pools?sort=h24_volume…   (the biggest-volume pools, a different membership)
//   new      → /new_pools                (the freshest on-DEX pools → recently migrated)
// We fetch 2 pages each for depth (~40 rows) and cache per-kind. The same v2 pool shape parses for
// all three. New stays fresh from pump creations; these older pools sink under the fresh-sort there.
function geckoPoolsToCandidates(data, sourceTag) {
  const pools = arrayFromApiData(data, ["data"]);
  if (!pools.length) return [];
  const tokenMap = new Map();
  for (const inc of (Array.isArray(data?.included) ? data.included : [])) {
    if (inc?.type === "token" && inc.id) tokenMap.set(inc.id, inc.attributes || {});
  }
  return pools.map((pool) => {
    const a = pool?.attributes || {};
    const baseId = pool?.relationships?.base_token?.data?.id || "";
    const mint = String(baseId).replace(/^solana_/, "");
    if (!mint || mint === SOL_MINT) return null;
    const tok = tokenMap.get(baseId) || {};
    const dexId = pool?.relationships?.dex?.data?.id || "";
    const pc = a.price_change_percentage || {};
    const vol = a.volume_usd || {};
    const tx = a.transactions || {};
    const grad = /raydium|meteora|orca|pumpswap|fluxbeam/i.test(dexId); // on a DEX = migrated/graduated
    return {
      tokenMint: mint,
      source: sourceTag,
      profile: {
        symbol: tok.symbol || String(a.name || "").split(" / ")[0] || "",
        name: tok.name || "",
        icon: tok.image_url || "",
        imageUrl: tok.image_url || "",
        dexId, dexName: dexId,
        pairAddress: a.address || "",
        pairUrl: "",
        raydiumPool: /raydium|meteora|orca|pumpswap|fluxbeam/i.test(dexId) ? (a.address || "") : "",
        graduated: grad,
        pairCreatedAt: a.pool_created_at || null,
        marketCap: firstNumber(a.market_cap_usd, a.fdv_usd),
        fdv: a.fdv_usd || null,
        liquidityUsd: Number(a.reserve_in_usd) || null,
        liquidity: { usd: Number(a.reserve_in_usd) || null },
        volume: { m5: Number(vol.m5) || 0, h1: Number(vol.h1) || 0, h6: Number(vol.h6) || 0, h24: Number(vol.h24) || 0 },
        txns: { m5: { buys: tx.m5?.buys || 0, sells: tx.m5?.sells || 0 }, h1: { buys: tx.h1?.buys || 0, sells: tx.h1?.sells || 0 }, h24: { buys: tx.h24?.buys || 0, sells: tx.h24?.sells || 0 } },
        priceChange: { m5: Number(pc.m5) || 0, h1: Number(pc.h1) || 0, h6: Number(pc.h6) || 0, h24: Number(pc.h24) || 0 }
      }
    };
  }).filter(Boolean);
}
const GECKO_POOL_ENDPOINTS = {
  trending: (page) => `https://api.geckoterminal.com/api/v2/networks/solana/trending_pools?include=base_token&page=${page}`,
  volume: (page) => `https://api.geckoterminal.com/api/v2/networks/solana/pools?include=base_token&sort=h24_volume_usd_desc&page=${page}`,
  new: (page) => `https://api.geckoterminal.com/api/v2/networks/solana/new_pools?include=base_token&page=${page}`
};
const _geckoPoolCache = new Map(); // kind -> { at, rows }
async function fetchGeckoPools(kind, options = {}) {
  const builder = GECKO_POOL_ENDPOINTS[kind];
  if (!builder) return [];
  const ttl = Math.max(6_000, Number(options.ttlMs || 0));
  const cached = _geckoPoolCache.get(kind);
  if (!options.force && cached && cached.rows.length && Date.now() - cached.at < ttl) return cached.rows;
  const pages = Math.max(1, Math.min(3, Number(options.pages || 2)));
  try {
    const pageData = await Promise.all(
      Array.from({ length: pages }, (_, i) =>
        fetchJson(builder(i + 1), { headers: { Accept: "application/json" }, timeoutMs: options.timeoutMs || 2_500 }).catch(() => null)
      )
    );
    const rows = [];
    for (const d of pageData) rows.push(...geckoPoolsToCandidates(d, `gecko-${kind}`));
    const deduped = uniqueSniperCandidates(rows);
    if (deduped.length) _geckoPoolCache.set(kind, { at: Date.now(), rows: deduped });
    return deduped.length ? deduped : (cached?.rows || []);
  } catch { return cached?.rows || []; }
}
// Back-compat shim: the fresh-feed merge + dexTrending category still call the trending fetcher.
async function fetchGeckoTrendingCandidates(options = {}) {
  return fetchGeckoPools("trending", { ...options, pages: options.pages || 2 });
}
// Live swaps for one pool — powers the /gg "Transactions" tab natively (no iframe, no CORS). FREE,
// no key. Shaped to the minimum the table needs; cached briefly so tab-flipping doesn't hammer it.
const _geckoTradesCache = new Map(); // pool -> { at, trades }
async function fetchGeckoPoolTrades(pool, options = {}) {
  const key = String(pool || "").trim();
  if (!key) return [];
  const cached = _geckoTradesCache.get(key);
  if (!options.force && cached && Date.now() - cached.at < (options.ttlMs || 12_000)) return cached.trades;
  const url = `https://api.geckoterminal.com/api/v2/networks/solana/pools/${encodeURIComponent(key)}/trades?trade_volume_in_usd_greater_than=0`;
  // GeckoTerminal free tier occasionally 429s the FIRST (uncached) hit from Render's busy IP — a
  // single quick retry clears it, after which the 12s cache serves everyone.
  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const data = await fetchJson(url, { headers: { Accept: "application/json" }, timeoutMs: options.timeoutMs || 3_500 });
      const rows = arrayFromApiData(data);
      const trades = rows.slice(0, 60).map((t) => {
        const a = t?.attributes || {};
        const kind = /sell/i.test(String(a.kind || "")) ? "sell" : "buy";
        return {
          ts: a.block_timestamp || null,
          kind,
          usd: Number(a.volume_in_usd) || 0,
          price: Number(a.price_to_in_usd || a.price_from_in_usd) || 0,
          maker: String(a.tx_from_address || "").trim(),
          tx: String(a.tx_hash || "").trim()
        };
      }).filter((t) => t.tx);
      if (trades.length) { _geckoTradesCache.set(key, { at: Date.now(), trades }); return trades; }
    } catch {}
    if (attempt === 0) await new Promise((r) => setTimeout(r, 350));
  }
  return cached?.trades || [];
}
async function fetchLivePairCandidates(options = {}) {
  const ttlMs = Number.isFinite(Number(options.ttlMs)) ? Number(options.ttlMs) : 500;
  const safeBucket = normalizeLivePairBucket(options.bucket);
  const [photon, pumpLatest, dexLatest, dexBucketSearch, geckoTrending] = await Promise.all([
    fetchPhotonNewPairCandidates({ ...options, ttlMs }).catch(() => []),
    fetchPumpFunLatestCandidates({ ...options, timeoutMs: options.timeoutMs || 1_800 }).catch(() => []),
    fetchSniperCandidates({ ...options, ttlMs, timeoutMs: options.timeoutMs || 1_800 }).catch(() => []),
    safeBucket === "live"
      ? Promise.resolve([])
      : fetchDexSearchCandidatesForLiveBucket(safeBucket, options).catch(() => []),
    fetchGeckoTrendingCandidates({ ttlMs, timeoutMs: 2_500 }).catch(() => [])
  ]);
  const freshDexRows = dexLatest.filter((candidate) => candidate.source !== "top-boost" || safeBucket !== "live");
  // The fresh-only sources (realtime PumpPortal creations, Photon new-pairs, pump-latest) are
  // seconds-to-minutes old — they belong on the FRESHEST buckets. Force-adding them to the older
  // buckets flooded EVERY tab with brand-new dust ("mainly fresh pairs show everywhere"): the
  // volume / trending / graduated tabs source from the wider buckets and were drowned in launch
  // coins. So feed those fresh sources only to live/under1h; the older buckets use the bucket's own
  // search terms (solana volume/movers) + boosted/trending — i.e. genuinely non-fresh movers.
  const freshOnly = safeBucket === "live" || safeBucket === "under1h";
  const realtime = (safeBucket === "live") ? pumpPortalStream.getCreationCandidates({ limit: 150 }) : [];
  const photonRows = freshOnly ? photon : [];
  const pumpRows = freshOnly ? pumpLatest : [];
  return uniqueSniperCandidates([...realtime, ...photonRows, ...pumpRows, ...geckoTrending, ...dexBucketSearch, ...freshDexRows])
    .sort(compareLivePairCandidates);
}

// ===== PER-CATEGORY PATHS (so the tabs stop crossing) ========================================
// Each category fetches its OWN DexScreener search pool (+ the boosted endpoint / a bonding filter
// where it matters), cached under its own key — instead of many categories sharing one bucket:sort
// pool and showing identical/mostly-fresh coins. Distinct queries → distinct coins per tab.
// ONLY discovery categories get a dedicated path — and the terms MUST be real token name/symbol
// fragments (DexScreener /search is name-based, not concept-based: "solana volume" matches nothing,
// "bonk"/"pump"/"meme" match coins). The defining SOURCE (boosts endpoint / pump creations) does the
// real work; the searches add breadth. The metric tabs (volume/liquidity/gainers/active/marketcap)
// are NOT here — they keep the shared bucket pool and differentiate by SORT (already distinct), so
// they don't need a name-search that returns nothing.
const LIVE_CATEGORY_QUERIES = {
  dexTrending: ["raydium solana", "bonk solana", "pump solana"],            // + GeckoTerminal trending_pools + token-boosts
  dexBoosted: ["raydium solana", "pump solana"],                            // + token-boosts endpoint (defining source)
  pumpTrending: ["pump solana", "pumpfun", "bonk solana"],                  // + live pump creations + pump-latest
  memeMovers: ["bonk solana", "meme solana", "dog solana", "cat solana", "pepe solana", "wif solana"],
  earlyMomentum: ["pump solana", "pumpfun", "raydium pump"],                // + live pump creations + pump-latest
  graduating: ["pump solana", "raydium pump", "pumpfun"],                   // + live pump creations (≥50% bonding filter)
  graduated: ["raydium solana", "meteora solana", "orca solana"]           // + graduated filter
};
// GeckoTerminal-backed tabs draw a DISTINCT pool per tab (different endpoint), not a re-rank of one
// list — so Trending vs Surging vs Top-Volume vs Migrated finally look genuinely different. These
// take the dedicated category path even though they have no DexScreener name-search of their own.
const GECKO_BACKED_CATEGORIES = new Set(["dexTrending", "gtVolume", "gtSurging", "gtMigrated", "graduated"]);
// Stablecoins / LSTs / wrapped bluechips dominate raw 24h volume but are not what a memecoin Top
// Volume tab should show — keep them out so the tab reads as the highest-volume MEMECOINS.
const GTVOLUME_EXCLUDE_MINTS = new Set([
  "EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v", // USDC
  "Es9vMFrzaCERmJfrF4H2FYD4KCoNkY11McCe8BenwNYB", // USDT
  "So11111111111111111111111111111111111111112",  // wSOL
  "mSoLzYCxHdYgdzU16g5QSh3i5K3z3KZK7ytfqcJm7So",   // mSOL
  "J1toso1uCk3RLmjorhTtrVwY9HJ7X8V9yYac6Y7kGCPn",  // JitoSOL
  "bSo13r4TkiE4KumL71LsHTPpL2euBYLFx6h9HP3piy1",   // bSOL
  "7dHbWXmci3dT8UFYWYZweBLXgycu7Y3iL6trKn1Y7ARj",  // stSOL
  "cbbtcf3aa214zXHbiAZQwf4122FBYbraNdFqgw4iMij",   // cbBTC
  "JUPyiwrYJFskUPiHa7hkeR8VUtAeFoSYbKedZNsDvCN"    // JUP
]);
function livePairCategoryFilter(category) {
  // Only the discovery categories need a post-filter; the metric tabs rank the whole pool.
  // Graduating = pump coins HIGH on the bonding curve and ABOUT TO BOND — roughly $35k–$72k MC, not
  // yet graduated. p is MC-anchored now (see slimeScopeProgressPct). The MC ceiling matters because
  // progress caps at 99: without it, already-bonded $200k+ coins read "99%" and wrongly show here.
  if (category === "graduating") return (row) => {
    // The user wants Graduating to be the $18k–$27k CLIMBING band — coins mid-curve, working their way
    // up to graduation, not the thin near-bond ($35k+) sliver (which barely populated). This band is
    // also naturally distinct from the Gecko-backed DEX tabs (established/higher MC), so it stops
    // sharing coins with Trending/Surging/Top-Volume. NOTE: do NOT gate on slimeScopeProgressPct>=50
    // here — at $18–27k the curve progress is only ~26–39%, so a p>=50 gate would exclude the whole band.
    const mc = Number(firstMeaningfulNumber(row.marketCap, row.fdv)) || 0;
    return (isPumpStyleToken(row) || row.isPump) && mc >= 18_000 && mc <= 27_000 && !(row.graduated || row.isGraduated);
  };
  if (category === "graduated" || category === "gtMigrated") return (row) => Boolean(row.graduated || row.isGraduated || isGraduatedSlimeScopePair(row));
  // Surging = genuine gainers only (positive 5m OR 1h). Soft-applied (kept only when ≥6 match), so a
  // flat market never empties the tab.
  if (category === "gtSurging") return (row) => { const m5 = liveRowPct(row.m5); const h1 = liveRowPct(row.h1); return (Number.isFinite(m5) && m5 > 0) || (Number.isFinite(h1) && h1 > 0); };
  // Top Volume = highest-volume memecoins → drop stablecoins/LSTs/bluechips.
  if (category === "gtVolume") return (row) => !GTVOLUME_EXCLUDE_MINTS.has(String(row.tokenMint || ""));
  if (category === "dexBoosted") return (row) => Boolean(row.boosted || row.boosts || /boost/i.test(String(row.source || "")));
  if (category === "pumpTrending") return (row) => Boolean(isPumpStyleToken(row) || row.isPump || /pump/i.test(String(row.source || "")));
  return null;
}
async function fetchLiveCategoryCandidates(category, options = {}) {
  const queries = LIVE_CATEGORY_QUERIES[category] || [];
  const ttlMs = Math.max(4_000, Number(options.ttlMs || 0), 8_000);
  const headers = { Accept: "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const rows = [];
  await runWithConcurrency(queries, 3, async (query) => {
    const cacheKey = `cat:${category}:${query}`;
    const cached = dexSearchCandidatesCache.get(cacheKey);
    if (!options.force && cached && Date.now() - cached.cachedAt < ttlMs) { rows.push(...cached.value); return; }
    const data = await fetchJson(`https://api.dexscreener.com/latest/dex/search?q=${encodeURIComponent(query)}`, { headers, timeoutMs: options.timeoutMs || 3_000 }).catch(() => null);
    const value = sniperCandidatesFromDexPairs(arrayFromApiData(data, ["pairs"]), `cat:${category}:${query}`);
    dexSearchCandidatesCache.set(cacheKey, { cachedAt: Date.now(), value });
    rows.push(...value);
  });
  // Boosted / trending tabs also pull the real DexScreener token-boosts endpoint (their defining source).
  if (category === "dexBoosted" || category === "dexTrending") {
    try { rows.push(...(await fetchSniperCandidates({ ...options, ttlMs }).catch(() => []))); } catch {}
  }
  // GeckoTerminal (FREE, no key) is the defining source for the established/mover tabs — full pages
  // of real movers regardless of age (the bucket path's age cap is what starved these). Each tab
  // draws a DISTINCT endpoint so Trending / Surging / Top-Volume / Migrated stop re-ranking one list:
  if (category === "dexTrending") {
    // Trending → the curated trending_pools list (2 pages, ~40).
    try { rows.push(...(await fetchGeckoPools("trending", { ttlMs, timeoutMs: 2_500, pages: 2 }).catch(() => []))); } catch {}
  } else if (category === "gtVolume") {
    // Top Volume → highest-volume MEMECOINS. The global /pools?sort=volume endpoint is mostly
    // stablecoin/bluechip pairs (USDT/USDC/SOL) AND flaky from Render's IP, so we draw the proven
    // memecoin pool (trending + new, reliably cached) and let the volume SORT rank it; the volume
    // endpoint is a best-effort bonus. (Distinctness comes from the cross-category de-dup downstream,
    // NOT from dropping trending here — dropping it emptied the tab when the volume endpoint returned
    // stablecoins only.) Stablecoins are filtered out.
    try {
      const [tr, nw, vol] = await Promise.all([
        fetchGeckoPools("trending", { ttlMs, timeoutMs: 2_500, pages: 2 }).catch(() => []),
        fetchGeckoPools("new", { ttlMs, timeoutMs: 2_500, pages: 2 }).catch(() => []),
        fetchGeckoPools("volume", { ttlMs, timeoutMs: 3_500, pages: 2 }).catch(() => [])
      ]);
      rows.push(...tr, ...nw, ...vol);
    } catch {}
  } else if (category === "gtSurging") {
    // Surging → "what's pumping right now": blend fresh-on-DEX + high-volume + trending (all carry the
    // momentum data the positive-mover filter needs — leading with brand-new pools alone emptied it),
    // then momentum-sort + positive-only downstream. The cross-category de-dup drops trending coins so
    // it still reads distinct from the Trending tab.
    try {
      const [nw, vol, tr] = await Promise.all([
        fetchGeckoPools("new", { ttlMs, timeoutMs: 2_500, pages: 2 }).catch(() => []),
        fetchGeckoPools("volume", { ttlMs, timeoutMs: 2_500, pages: 1 }).catch(() => []),
        fetchGeckoPools("trending", { ttlMs, timeoutMs: 2_500, pages: 1 }).catch(() => [])
      ]);
      rows.push(...nw, ...vol, ...tr);
    } catch {}
  } else if (category === "gtMigrated" || category === "graduated") {
    // Migrated → the freshest pools that are already on a real DEX (raydium/pumpswap/…) = just
    // graduated off the pump curve. Backfill with graduated trending pools so the tab stays full.
    try {
      const nw = await fetchGeckoPools("new", { ttlMs, timeoutMs: 2_500, pages: 2 }).catch(() => []);
      rows.push(...nw.filter((r) => r.profile?.graduated));
      const tr = await fetchGeckoPools("trending", { ttlMs, timeoutMs: 2_500, pages: 2 }).catch(() => []);
      rows.push(...tr.filter((r) => r.profile?.graduated));
    } catch {}
  }
  // Pump-curve tabs add the live pump creations (fresh) + latest so there's curve material to filter.
  // Graduating wants coins NEAR bonding (high on the curve), which were created a while ago and have
  // since climbed — so it scans the whole 1h creation buffer (with each coin's LATEST market cap),
  // not just the freshest 120, or near-bond coins fall off the bottom and the tab fills with dust.
  if (category === "pumpTrending" || category === "earlyMomentum" || category === "graduating") {
    const creationLimit = category === "graduating" ? 600 : 120;
    try { rows.push(...pumpPortalStream.getCreationCandidates({ limit: creationLimit })); } catch {}
    try { rows.push(...(await fetchPumpFunLatestCandidates({ ...options, timeoutMs: options.timeoutMs || 1_800 }).catch(() => []))); } catch {}
  }
  return uniqueSniperCandidates(rows).sort(compareLivePairCandidates);
}

async function fetchDexSearchCandidatesForLiveBucket(bucket, options = {}) {
  const safeBucket = normalizeLivePairBucket(bucket);
  const queries = livePairBucketSearchQueries(safeBucket, options.scanState);
  if (!queries.length) return [];

  const ttlMs = Number.isFinite(Number(options.searchTtlMs))
    ? Number(options.searchTtlMs)
    : Math.max(3_000, Number(options.ttlMs || 0), 6_000);
  const headers = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const rows = [];

  await runWithConcurrency(queries, 3, async (query) => {
    const cacheKey = `live:${safeBucket}:${query}`;
    const cached = dexSearchCandidatesCache.get(cacheKey);
    if (!options.force && cached && Date.now() - cached.cachedAt < ttlMs) {
      rows.push(...cached.value);
      return;
    }

    const data = await fetchJson(`https://api.dexscreener.com/latest/dex/search?q=${encodeURIComponent(query)}`, {
      headers,
      timeoutMs: options.timeoutMs || 3_000
    }).catch(() => null);
    const value = sniperCandidatesFromDexPairs(arrayFromApiData(data, ["pairs"]), `live:${safeBucket}:${query}`);
    dexSearchCandidatesCache.set(cacheKey, { cachedAt: Date.now(), value });
    rows.push(...value);
  });

  return uniqueSniperCandidates(rows);
}

function livePairBucketSearchQueries(bucket, scanState = {}) {
  const querySets = {
    under1h: ["pump solana", "pumpfun solana", "new pump", "solana meme", "raydium pump", "solana trending", "solana volume", "cto pump"],
    under3h: ["solana trending", "solana pump", "raydium solana", "solana movers", "bonk solana", "pumpfun", "solana breakout", "cto solana"],
    under1d: ["solana volume", "solana movers", "solana meme", "solana breakout", "raydium solana", "pump trending", "solana community", "solana gem"]
  };
  const list = querySets[normalizeLivePairBucket(bucket)] || [];
  const refreshCount = Number(scanState?.refreshCount || 0);
  const offset = refreshCount * 2 + stringModulo(bucket, list.length || 1) + Math.floor(Date.now() / 60_000);
  return rotateItems(list, offset).slice(0, 6);
}

function compareLivePairCandidates(a, b) {
  return Number(livePairCandidateCreatedAt(b) || 0) - Number(livePairCandidateCreatedAt(a) || 0);
}

// ---- Native chart OHLCV (GeckoTerminal candles + PumpPortal tick synth) ----
// Powers SlimeWire-branded lightweight-charts instead of the DexScreener
// iframe. GeckoTerminal serves free OHLCV for any indexed Solana pool; brand
// new bonding-curve tokens have no pool yet, so their candles are synthesized
// from the live PumpPortal trade stream we are already subscribed to.

const OHLCV_TIMEFRAMES = {
  "1m": { path: "minute", aggregate: 1, seconds: 60 },
  "5m": { path: "minute", aggregate: 5, seconds: 300 },
  "15m": { path: "minute", aggregate: 15, seconds: 900 },
  "1h": { path: "hour", aggregate: 1, seconds: 3600 },
  "4h": { path: "hour", aggregate: 4, seconds: 14400 },
  "1d": { path: "day", aggregate: 1, seconds: 86400 }
};

const GECKO_HEADERS = {
  Accept: "application/json;version=20230302",
  // GeckoTerminal sits behind Cloudflare and silently rejects UA-less requests
  // from datacenter IPs (Render). Same lesson DexScreener taught us.
  "User-Agent": "Mozilla/5.0 (compatible; SlimeWire/1.0; +https://www.slimewire.org)"
};

async function resolveGeckoPoolForMint(mint) {
  const cached = geckoPoolCache.get(mint);
  if (cached && Date.now() - cached.at < (cached.pool ? 10 * 60 * 1000 : 90 * 1000)) {
    return cached.pool;
  }
  const data = await fetchJson(
    `https://api.geckoterminal.com/api/v2/networks/solana/tokens/${encodeURIComponent(mint)}/pools?page=1`,
    { headers: GECKO_HEADERS, timeoutMs: 3_500 }
  ).catch(() => null);
  const pools = Array.isArray(data?.data) ? data.data : [];
  const best = pools
    .map((item) => ({
      address: String(item?.attributes?.address || ""),
      reserveUsd: Number(item?.attributes?.reserve_in_usd) || 0
    }))
    .filter((item) => item.address)
    .sort((a, b) => b.reserveUsd - a.reserveUsd)[0] || null;
  let pool = best?.address || null;
  if (!pool) {
    // Fallback: DexScreener already knows the pair address for indexed tokens
    // (cached server-side), and GeckoTerminal accepts pool addresses directly.
    const litePair = pairLiteCache.get(mint)?.payload?.pair;
    pool = String(litePair?.pairAddress || "") || null;
    if (!pool) {
      const pairs = await fetchDexScreenerTokenPairsFallback(mint).catch(() => []);
      pool = String(bestDexPairForToken(mint, pairs)?.pairAddress || "") || null;
    }
  }
  geckoPoolCache.set(mint, { at: Date.now(), pool });
  if (geckoPoolCache.size > 500) {
    const oldest = [...geckoPoolCache.entries()].sort((a, b) => a[1].at - b[1].at)[0]?.[0];
    if (oldest) geckoPoolCache.delete(oldest);
  }
  return pool;
}

// --- /chart for crypto tickers (btc/eth/...) — CoinGecko data + QuickChart image -------------
// Both are free + no key + US-accessible (Binance is geo-blocked on US hosts). Solana CAs use
// the existing native chart; stocks/unknown fall back to a TradingView link. Timeframe buttons
// re-render the image.
const CG_TICKER_IDS = { btc: "bitcoin", xbt: "bitcoin", eth: "ethereum", sol: "solana", bnb: "binancecoin", xrp: "ripple", doge: "dogecoin", ada: "cardano", avax: "avalanche-2", link: "chainlink", matic: "matic-network", pol: "matic-network", dot: "polkadot", ltc: "litecoin", trx: "tron", shib: "shiba-inu", pepe: "pepe", wif: "dogwifcoin", bonk: "bonk", ton: "the-open-network", sui: "sui", apt: "aptos", arb: "arbitrum", op: "optimism", near: "near", inj: "injective-protocol", atom: "cosmos", uni: "uniswap", fet: "fetch-ai", rndr: "render-token", tao: "bittensor", hype: "hyperliquid", ena: "ethena" };
const CHART_TF_DAYS = { "1D": 1, "7D": 7, "1M": 30, "3M": 90, "1Y": 365 };
const chartCgIdCache = new Map();
async function resolveCoinGeckoId(input) {
  const k = String(input || "").trim().toLowerCase().replace(/^\$/, "");
  if (!k) return null;
  if (CG_TICKER_IDS[k]) return { id: CG_TICKER_IDS[k], symbol: k.toUpperCase() };
  if (chartCgIdCache.has(k)) return chartCgIdCache.get(k);
  try {
    const d = await fetchJson(`https://api.coingecko.com/api/v3/search?query=${encodeURIComponent(k)}`, { timeoutMs: 5000 }).catch(() => null);
    const coins = Array.isArray(d?.coins) ? d.coins : [];
    const coin = coins.find((c) => String(c.symbol || "").toLowerCase() === k) || coins[0];
    const out = coin ? { id: coin.id, symbol: String(coin.symbol || k).toUpperCase() } : null;
    chartCgIdCache.set(k, out);
    return out;
  } catch { return null; }
}
async function fetchCoinGeckoOhlc(id, days) {
  const d = await fetchJson(`https://api.coingecko.com/api/v3/coins/${encodeURIComponent(id)}/ohlc?vs_currency=usd&days=${days}`, { timeoutMs: 7500 }).catch(() => null);
  const list = Array.isArray(d) ? d : [];
  return list.map((r) => ({ t: Number(r[0]) || 0, o: Number(r[1]), h: Number(r[2]), l: Number(r[3]), c: Number(r[4]) })).filter((k) => k.h > 0 && k.l > 0);
}
async function fetchCoinGeckoMarket(id) {
  const d = await fetchJson(`https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&ids=${encodeURIComponent(id)}`, { timeoutMs: 7000 }).catch(() => null);
  return (Array.isArray(d) && d[0]) ? d[0] : null;
}
function fmtChartPrice(p) {
  p = Number(p) || 0;
  if (p >= 1000) return "$" + Math.round(p).toLocaleString("en-US");
  if (p >= 1) return "$" + p.toFixed(2);
  if (p >= 0.01) return "$" + p.toFixed(4);
  return "$" + p.toPrecision(3);
}
// Self-rendered candlestick chart (SVG -> PNG via sharp) — clean + detailed (price axis, grid,
// time labels, green/red candles, last-price line). No flaky external chart service.
function candleChartSvg(candles, opts = {}) {
  const W = 880, H = 470, padL = 12, padR = 80, padT = 52, padB = 30;
  const plotW = W - padL - padR, plotH = H - padT - padB;
  const cs = candles.slice(-120);
  const hi = Math.max(...cs.map((c) => c.h)), lo = Math.min(...cs.map((c) => c.l));
  const pad = (hi - lo) * 0.08 || (hi * 0.08) || 1;
  const top = hi + pad, bot = Math.max(0, lo - pad), span = (top - bot) || 1;
  const xAt = (i) => padL + (cs.length <= 1 ? plotW / 2 : (i / (cs.length - 1)) * plotW);
  const yAt = (p) => padT + (1 - (p - bot) / span) * plotH;
  const cw = Math.max(2.2, Math.min(13, (plotW / Math.max(1, cs.length)) * 0.64));
  let grid = "", ylab = "";
  for (let g = 0; g <= 4; g++) {
    const p = bot + (g / 4) * span, yy = yAt(p);
    grid += `<line x1="${padL}" y1="${yy.toFixed(1)}" x2="${(padL + plotW).toFixed(1)}" y2="${yy.toFixed(1)}" stroke="rgba(255,255,255,0.06)"/>`;
    ylab += `<text x="${padL + plotW + 7}" y="${(yy + 4).toFixed(1)}" fill="#8aa680" font-size="13" font-family="monospace">${escapeSvg(fmtChartPrice(p))}</text>`;
  }
  let body = "";
  for (let i = 0; i < cs.length; i++) {
    const c = cs[i], up = c.c >= c.o, col = up ? "#39ff14" : "#ff5470", cx = xAt(i);
    const yH = yAt(c.h), yL = yAt(c.l), yo = yAt(c.o), yc = yAt(c.c);
    const t2 = Math.min(yo, yc), h2 = Math.max(1.2, Math.abs(yc - yo));
    body += `<line x1="${cx.toFixed(1)}" y1="${yH.toFixed(1)}" x2="${cx.toFixed(1)}" y2="${yL.toFixed(1)}" stroke="${col}" stroke-width="1.3"/>`;
    body += `<rect x="${(cx - cw / 2).toFixed(1)}" y="${t2.toFixed(1)}" width="${cw.toFixed(1)}" height="${h2.toFixed(1)}" fill="${col}" rx="1"/>`;
  }
  const lastY = yAt(cs[cs.length - 1].c);
  const lastCol = cs[cs.length - 1].c >= cs[0].o ? "#39ff14" : "#ff5470";
  const lastLine = `<line x1="${padL}" y1="${lastY.toFixed(1)}" x2="${(padL + plotW).toFixed(1)}" y2="${lastY.toFixed(1)}" stroke="${lastCol}" stroke-width="1" stroke-dasharray="4 4" opacity="0.55"/>`;
  let xlab = "";
  if (cs.length > 1) {
    const fmtT = (ms) => { const dt = new Date(ms); return `${dt.getUTCMonth() + 1}/${dt.getUTCDate()}`; };
    for (const i of [0, Math.floor(cs.length / 2), cs.length - 1]) {
      xlab += `<text x="${xAt(i).toFixed(1)}" y="${H - 10}" fill="#6f8a66" font-size="12" font-family="monospace" text-anchor="middle">${fmtT(cs[i].t)}</text>`;
    }
  }
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
  <defs><linearGradient id="cbg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0e1c10"/><stop offset="1" stop-color="#060d07"/></linearGradient></defs>
  <rect width="${W}" height="${H}" fill="url(#cbg)"/>
  ${grid}${lastLine}
  <text x="${padL}" y="30" fill="#d6ffbf" font-size="21" font-weight="800" font-family="Inter, sans-serif">${escapeSvg(opts.title || "")}</text>
  <text x="${padL}" y="46" fill="#7fae6f" font-size="13" font-family="Inter, sans-serif">${escapeSvg(opts.sub || "")}</text>
  ${body}${ylab}${xlab}
</svg>`;
}
async function renderCandleChartPng(candles, opts) {
  return sharp(Buffer.from(candleChartSvg(candles, opts))).png().toBuffer();
}
function chartTickerKeyboard(id, symbol, activeTf) {
  const tfRow = Object.keys(CHART_TF_DAYS).map((tf) => ({ text: tf === activeTf ? `· ${tf} ·` : tf, callback_data: `chartx:${id}:${symbol}:${tf}` }));
  return { inline_keyboard: [tfRow, [{ text: "📈 TradingView", url: `https://www.tradingview.com/chart/?symbol=${encodeURIComponent(symbol)}USD` }]] };
}
async function sendCryptoChart(chatId, id, symbol, tf, messageId = null) {
  const days = CHART_TF_DAYS[tf] || 1;
  const [candles, mkt] = await Promise.all([fetchCoinGeckoOhlc(id, days), fetchCoinGeckoMarket(id)]);
  if (!candles.length) { if (!messageId) await say(chatId, `Couldn't pull ${symbol} chart data right now — try again in a moment.`); return false; }
  const price = Number(mkt?.current_price) || candles[candles.length - 1].c;
  const ch = Number(mkt?.price_change_percentage_24h);
  const name = mkt?.name || symbol;
  const mc = Number(mkt?.market_cap) || 0;
  const mcStr = mc ? `MC ${mc >= 1e9 ? "$" + (mc / 1e9).toFixed(2) + "B" : "$" + (mc / 1e6).toFixed(0) + "M"}` : "";
  const title = `${name}  ${fmtChartPrice(price)}  ${Number.isFinite(ch) ? (ch >= 0 ? "▲ +" : "▼ ") + ch.toFixed(1) + "%" : ""}`;
  const png = await renderCandleChartPng(candles, { title, sub: `${symbol}/USD · ${tf}${mcStr ? " · " + mcStr : ""}` }).catch(() => null);
  if (!png) { if (!messageId) await say(chatId, `${title}\nhttps://www.tradingview.com/chart/?symbol=${symbol}USD`); return false; }
  const cap = `<b>${escapeTelegramHtml(name)}</b> ($${escapeTelegramHtml(symbol)})\n💵 <b>${escapeTelegramHtml(fmtChartPrice(price))}</b>  ${Number.isFinite(ch) ? (ch >= 0 ? "🟢 +" : "🔴 ") + ch.toFixed(1) + "% 24h" : ""}${mcStr ? "\n📊 " + escapeTelegramHtml(mcStr) : ""}  ·  ${tf}`;
  const kb = chartTickerKeyboard(id, symbol, tf);
  try {
    const sent = await sendPhoto(chatId, `chart-${symbol}.png`, png, cap, kb, "HTML");
    if (messageId) { try { await telegram("deleteMessage", { chat_id: chatId, message_id: messageId }); } catch {} } // re-render: replace the old chart
    return Boolean(sent);
  } catch { if (!messageId) await say(chatId, `${title}\nhttps://www.tradingview.com/chart/?symbol=${symbol}USD`); return false; }
}

async function fetchGeckoOhlcv(mint, tfKey) {
  const tf = OHLCV_TIMEFRAMES[tfKey] || OHLCV_TIMEFRAMES["1m"];
  const pool = await resolveGeckoPoolForMint(mint);
  if (!pool) return { candles: [], poolAddress: null };
  const data = await fetchJson(
    `https://api.geckoterminal.com/api/v2/networks/solana/pools/${encodeURIComponent(pool)}/ohlcv/${tf.path}?aggregate=${tf.aggregate}&limit=300&currency=usd&token=base`,
    { headers: GECKO_HEADERS, timeoutMs: 4_000 }
  ).catch(() => null);
  const list = Array.isArray(data?.data?.attributes?.ohlcv_list) ? data.data.attributes.ohlcv_list : [];
  const candles = list
    .map((row) => ({
      t: Number(row?.[0]) || 0,
      o: Number(row?.[1]) || 0,
      h: Number(row?.[2]) || 0,
      l: Number(row?.[3]) || 0,
      c: Number(row?.[4]) || 0,
      v: Number(row?.[5]) || 0
    }))
    .filter((candle) => candle.t > 0 && candle.c > 0)
    .sort((a, b) => a.t - b.t);
  return { candles, poolAddress: pool };
}

// Bonding-curve tokens: build candles out of the live trade ticks we hold in
// memory. History starts when the websocket first saw the token (its creation
// for fresh launches), which is exactly when degens care about it.
function synthCandlesFromPumpTrades(mint, tfKey) {
  const tf = OHLCV_TIMEFRAMES[tfKey] || OHLCV_TIMEFRAMES["1m"];
  const solUsd = Number.isFinite(solUsdPriceCache?.value) && solUsdPriceCache.value > 0 ? solUsdPriceCache.value : null;
  if (!solUsd) return [];
  const trades = pumpPortalStream.getTrades(mint, { limit: 240 });
  if (!trades.length) return [];
  const buckets = new Map();
  for (const trade of [...trades].reverse()) { // oldest first
    // pump.fun supply is 1B; marketCapSol is the steadiest per-trade price read.
    const priceUsd = Number(trade.marketCapSol) > 0
      ? (trade.marketCapSol / 1_000_000_000) * solUsd
      : Number(trade.priceSol) > 0 ? trade.priceSol * solUsd : null;
    if (!priceUsd) continue;
    const bucketTs = Math.floor(trade.at / 1000 / tf.seconds) * tf.seconds;
    const volumeUsd = (Number(trade.solAmount) || 0) * solUsd;
    const bucket = buckets.get(bucketTs);
    if (!bucket) {
      buckets.set(bucketTs, { t: bucketTs, o: priceUsd, h: priceUsd, l: priceUsd, c: priceUsd, v: volumeUsd });
    } else {
      bucket.h = Math.max(bucket.h, priceUsd);
      bucket.l = Math.min(bucket.l, priceUsd);
      bucket.c = priceUsd;
      bucket.v += volumeUsd;
    }
  }
  return [...buckets.values()].sort((a, b) => a.t - b.t);
}

async function webOhlcvPayload(mint, tfKey) {
  const cacheKey = `${mint}:${tfKey}`;
  const cached = geckoOhlcvCache.get(cacheKey);
  if (cached && Date.now() - cached.at < 12_000) return cached.payload;

  pumpPortalStream.watchMint(mint); // start collecting live ticks either way
  let { candles, poolAddress } = await fetchGeckoOhlcv(mint, tfKey);
  let source = candles.length ? "geckoterminal" : "";
  if (!candles.length) {
    candles = synthCandlesFromPumpTrades(mint, tfKey);
    source = candles.length ? "pumpportal" : "none";
  }
  // GeckoTerminal free tier rate-limits the shared Render IP now and then.
  // A slightly stale chart beats a blank one: serve the last good payload
  // for up to 10 minutes when a refresh comes back empty.
  if (!candles.length && cached?.payload?.candles?.length && Date.now() - cached.at < 10 * 60 * 1000) {
    return { ...cached.payload, stale: true };
  }
  const payload = {
    ok: true,
    mint,
    tf: tfKey,
    source,
    poolAddress: poolAddress || null,
    lastPriceUsd: candles.length ? candles[candles.length - 1].c : null,
    candles
  };
  // Never cache an empty answer for long - a fresh token can get its first
  // candle seconds from now.
  if (candles.length) {
    geckoOhlcvCache.set(cacheKey, { at: Date.now(), payload });
    if (geckoOhlcvCache.size > 300) {
      const oldest = [...geckoOhlcvCache.entries()].sort((a, b) => a[1].at - b[1].at)[0]?.[0];
      if (oldest) geckoOhlcvCache.delete(oldest);
    }
  }
  return payload;
}

// Resolve a free-text query ($OGRE, ogre, a name, or a raw mint) to the most
// relevant Solana token. Used by the top search bar so users can search by
// ticker/name, not just paste a contract address.
async function webTokenSearch(rawQuery = "") {
  const cleaned = String(rawQuery || "").trim().replace(/^\$+/, "").trim();
  if (!cleaned) return { query: "", matches: [] };

  // Already a valid mint -> return it directly, no lookup needed.
  try {
    const mint = parsePublicKey(cleaned).toBase58();
    return { query: cleaned, matches: [{ tokenMint: mint, symbol: "", name: "", source: "mint" }] };
  } catch {
    // not a mint; fall through to ticker/name search
  }

  const headers = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const data = await fetchJson(`https://api.dexscreener.com/latest/dex/search?q=${encodeURIComponent(cleaned)}`, {
    headers,
    timeoutMs: 4_000
  }).catch(() => null);
  const pairs = arrayFromApiData(data, ["pairs"]).filter((pair) => String(pair?.chainId || "").toLowerCase() === "solana");
  const q = cleaned.toLowerCase();
  const seen = new Set();
  const matches = [];
  for (const pair of pairs) {
    const base = pair?.baseToken || {};
    const mint = String(base.address || "").trim();
    if (!mint || seen.has(mint)) continue;
    seen.add(mint);
    const symbol = String(base.symbol || "");
    const name = String(base.name || "");
    const sym = symbol.toLowerCase();
    const nm = name.toLowerCase();
    const liquidityUsd = Number(pair?.liquidity?.usd || 0);
    const volumeUsd = Number(pair?.volume?.h24 || 0);
    let score = 0;
    if (sym === q) score += 1000;
    else if (sym.startsWith(q)) score += 600;
    else if (sym.includes(q)) score += 280;
    if (nm === q) score += 480;
    else if (nm.startsWith(q)) score += 220;
    else if (nm.includes(q)) score += 110;
    if (!score) continue; // no symbol/name relevance
    score += Math.min(220, Math.log10(Math.max(1, liquidityUsd)) * 32);
    score += Math.min(140, Math.log10(Math.max(1, volumeUsd)) * 20);
    matches.push({ tokenMint: mint, symbol, name, liquidityUsd, volumeUsd, score: Math.round(score) });
  }
  matches.sort((a, b) => b.score - a.score);
  return { query: cleaned, matches: matches.slice(0, 8) };
}

function livePairCandidateCreatedAt(candidate) {
  const profile = candidate?.metadata || candidate?.profile || {};
  return normalizePairCreatedAt(firstString(
    profile.pairCreatedAt,
    profile.pair_created_at,
    profile.pair_created_timestamp,
    profile.poolCreatedAt,
    profile.pool_created_at,
    profile.pool_created_timestamp,
    profile.listingCreatedAt,
    profile.listedAt,
    profile.launchTimestamp,
    profile.created_timestamp,
    profile.createdAt,
    profile.created_at,
    profile.pairCreatedTime,
    profile.timestamp
  ));
}

async function findManualLaunchCandidate(ticker) {
  const target = cleanTickerSymbol(ticker);
  const candidates = await fetchManualLaunchCandidates();
  const hydrated = await hydrateSniperCandidates(rotatePumpSnipeCandidatePool(candidates, { candidateOffset: Date.now() }));
  const exact = [];
  const fuzzy = [];

  for (const candidate of hydrated) {
    const metadata = candidate.metadata || {};
    const symbol = cleanTickerForCompare(metadata.symbol || candidate.profile?.symbol || "");
    const name = cleanTickerForCompare(metadata.name || candidate.profile?.name || "");
    const row = {
      tokenMint: candidate.tokenMint,
      symbol: metadata.symbol || candidate.profile?.symbol || "",
      name: metadata.name || candidate.profile?.name || "",
      pairCreatedAt: metadata.pairCreatedAt || null
    };
    if (symbol === target) {
      exact.push(row);
    } else if (name.includes(target) || symbol.includes(target)) {
      fuzzy.push(row);
    }
  }

  return [...exact, ...fuzzy]
    .sort((a, b) => Number(b.pairCreatedAt || 0) - Number(a.pairCreatedAt || 0))[0] || null;
}

async function fetchManualLaunchCandidates() {
  const cacheTtlMs = Math.max(500, Math.min(CONFIG.manualLaunchScanIntervalMs, 2_000));
  if (Date.now() - manualLaunchCandidatesCache.cachedAt < cacheTtlMs) {
    return manualLaunchCandidatesCache.value;
  }

  const [photon, pump] = await Promise.all([
    fetchPhotonNewPairCandidates({ ttlMs: cacheTtlMs }).catch(() => []),
    fetchPumpSnipeCandidates({ ttlMs: cacheTtlMs, timeoutMs: 2_500 }).catch(() => [])
  ]);
  const realtime = pumpPortalStream.getCreationCandidates({ limit: 150 });
  const value = uniqueSniperCandidates([...realtime, ...photon, ...pump]);
  manualLaunchCandidatesCache = { cachedAt: Date.now(), value };
  return value;
}

async function fetchPhotonNewPairCandidates(options = {}) {
  if (!CONFIG.photonNewPairsUrl) return [];
  const ttlMs = Number.isFinite(Number(options.ttlMs)) ? Number(options.ttlMs) : Math.max(500, Math.min(CONFIG.manualLaunchScanIntervalMs, 2_000));
  if (!options.force && ttlMs > 0 && Date.now() - photonNewPairsCache.cachedAt < ttlMs) {
    return photonNewPairsCache.value;
  }

  const headers = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  if (CONFIG.photonApiKey) {
    headers.Authorization = `Bearer ${CONFIG.photonApiKey}`;
  }

  const timeoutMs = Number.isFinite(Number(options.timeoutMs))
    ? Number(options.timeoutMs)
    : Math.max(1_200, Math.min(3_500, CONFIG.manualLaunchScanIntervalMs));
  const data = await fetchJson(CONFIG.photonNewPairsUrl, { headers, timeoutMs });
  const value = sniperCandidatesFromPhotonData(data);
  photonNewPairsCache = { cachedAt: Date.now(), value };
  return value;
}

function sniperCandidatesFromPhotonData(data) {
  const items = Array.isArray(data)
    ? data
    : Array.isArray(data?.data) ? data.data
      : Array.isArray(data?.pairs) ? data.pairs
        : Array.isArray(data?.tokens) ? data.tokens
          : Array.isArray(data?.results) ? data.results
            : [];

  return items
    .map((item) => {
      const token = item?.token || item?.baseToken || item?.base || item || {};
      const tokenMint = token.address
        || token.mint
        || token.tokenAddress
        || item?.tokenAddress
        || item?.mint
        || item?.ca
        || item?.contractAddress
        || item?.address;
      if (!tokenMint) return null;

      return {
        tokenMint,
        source: "photon",
        profile: {
          symbol: token.symbol || item?.symbol || item?.ticker || "",
          name: token.name || item?.name || "",
          description: item?.description || "",
          icon: token.image || token.imageUrl || item?.image || item?.imageUrl || "",
          pairCreatedAt: item?.pairCreatedAt || item?.createdAt || item?.created_at || item?.timestamp || null,
          marketCap: firstNumber(item?.marketCap, item?.market_cap, item?.fdv, item?.usdMarketCap, token.marketCap, token.market_cap),
          fdv: firstNumber(item?.fdv, token.fdv),
          liquidityUsd: firstNumber(item?.liquidityUsd, item?.liquidity_usd, item?.liquidity?.usd, item?.liquidity, token.liquidityUsd, token.liquidity?.usd),
          volume: {
            m5: firstNumber(item?.volume?.m5, item?.volume5m, item?.volume_5m, token.volume?.m5),
            h1: firstNumber(item?.volume?.h1, item?.volume1h, item?.volume_h1, item?.volume, token.volume?.h1, token.volume)
          }
        }
      };
    })
    .filter(Boolean);
}

async function fetchPumpFunLatestCandidates(options = {}) {
  const publicHeaders = { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" };
  const authedHeaders = { ...publicHeaders };
  if (CONFIG.pumpFunApiToken) {
    authedHeaders.Authorization = `Bearer ${CONFIG.pumpFunApiToken}`;
  }

  const timeoutMs = options.timeoutMs || 2_500;
  const fetchPumpJson = async (url) => {
    const headerAttempts = CONFIG.pumpFunApiToken ? [authedHeaders, publicHeaders] : [publicHeaders];
    let lastError = null;
    for (const headers of headerAttempts) {
      try {
        return await fetchJson(url, { headers, timeoutMs });
      } catch (error) {
        lastError = error;
      }
    }
    throw lastError || new Error("Pump metadata request failed");
  };
  const latestUrl = `${CONFIG.pumpFunApiBase}/coins/latest`;
  const listUrl = `${CONFIG.pumpFunApiBase}/coins?offset=0&limit=100&sort=created_timestamp&order=DESC&includeNsfw=false`;
  const [latest, list] = await Promise.all([
    fetchPumpJson(latestUrl).catch(() => null),
    fetchPumpJson(listUrl).catch(() => [])
  ]);
  return uniqueSniperCandidates(sniperCandidatesFromPumpFunData([latest, ...arrayFromApiData(list)], "pumpfun-latest"));
}

function sniperCandidatesFromPumpFunData(items, source = "pumpfun") {
  return (Array.isArray(items) ? items : [])
    .map((item) => {
      const coin = item?.data || item?.coin || item;
      if (!coin || typeof coin !== "object") return null;
      const tokenMint = firstString(coin.mint, coin.address, coin.tokenAddress, coin.token_address, coin.ca, coin.contractAddress);
      if (!tokenMint) return null;
      const raydiumPool = firstString(coin.raydium_pool, coin.raydiumPool, coin.poolAddress, coin.pool, coin.amm_pool);
      const bondingProgressPct = firstMeaningfulNumber(
        coin.bondingProgressPct,
        coin.bondingProgress,
        coin.bonding_curve_progress,
        coin.bondingCurveProgress,
        coin.progress,
        coin.pumpProgress,
        coin.graduationProgress,
        coin.completion,
        coin.completePct
      ) || 0;
      const graduated = Boolean(
        coin.complete
        || coin.completed
        || coin.bonded
        || coin.isBonded
        || coin.graduated
        || coin.isGraduated
        || raydiumPool
      );
      return {
        tokenMint,
        source,
        profile: {
          symbol: firstString(coin.symbol, coin.ticker),
          name: firstString(coin.name),
          description: firstString(coin.description),
          icon: firstString(coin.image_uri, coin.imageUri, coin.imageUrl, coin.image_url, coin.image, coin.metadata?.image, coin.metadata?.imageUrl, coin.logoURI, coin.logo),
          imageUrl: firstString(coin.image_uri, coin.imageUri, coin.imageUrl, coin.image_url, coin.image, coin.metadata?.image, coin.metadata?.imageUrl, coin.logoURI, coin.logo),
          imageUri: firstString(coin.image_uri, coin.imageUri, coin.imageUrl, coin.image_url, coin.image, coin.metadata?.image, coin.metadata?.imageUrl, coin.logoURI, coin.logo),
          pairCreatedAt: normalizePairCreatedAt(firstString(coin.created_timestamp, coin.createdAt, coin.created_at, coin.timestamp)),
          marketCap: firstNumber(coin.usd_market_cap, coin.usdMarketCap, coin.marketCapUsd, coin.market_cap_usd, coin.market_cap, coin.marketCap, coin.currentMarketCap, coin.current_market_cap, coin.fdv),
          fdv: firstNumber(coin.fdv, coin.fullyDilutedValuation, coin.marketCap, coin.marketCapUsd, coin.usdMarketCap, coin.usd_market_cap, coin.market_cap_usd, coin.market_cap),
          liquidityUsd: firstNumber(coin.liquidity_usd, coin.liquidityUsd, coin.liquidityUSD, coin.liquidity?.usd, coin.liquidity, coin.currentLiquidityUsd, coin.current_liquidity_usd, coin.poolLiquidityUsd, coin.pool_liquidity_usd),
          volume: typeof coin.volume === "object" && coin.volume !== null ? coin.volume : firstNumber(coin.volume, coin.volumeUsd, coin.volume_usd),
          volume5m: firstNumber(coin.volume5m, coin.volume_5m, coin.volumeM5, coin.volume_m5, coin.volume?.m5, coin.volume?.["5m"]),
          volume15m: firstNumber(coin.volume15m, coin.volume_15m, coin.volumeM15, coin.volume_m15, coin.volume?.m15, coin.volume?.["15m"]),
          volume30m: firstNumber(coin.volume30m, coin.volume_30m, coin.volumeM30, coin.volume_m30, coin.volume?.m30, coin.volume?.["30m"]),
          volumeH1: firstNumber(coin.volumeH1, coin.volume_h1, coin.volume_1h, coin.volumeH, coin.volume?.h1, coin.volume?.["1h"]),
          volume24h: firstNumber(coin.volume24h, coin.volume_h24, coin.volume_24h, coin.volumeH24, coin.volume_d1, coin.volume?.h24, coin.volume?.["24h"]),
          txns: coin.txns || coin.transactions || null,
          virtualSolReserves: firstNumber(coin.virtual_sol_reserves),
          virtualTokenReserves: firstNumber(coin.virtual_token_reserves),
          bondingProgressPct,
          graduated,
          isGraduated: graduated,
          raydiumPool
        }
      };
    })
    .filter(Boolean);
}

function cleanTickerForCompare(text) {
  return String(text || "").replace(/[^a-z0-9]/gi, "").toUpperCase();
}

function sniperCandidatesFromDexList(items, source) {
  return (Array.isArray(items) ? items : [])
    .filter((item) => String(item.chainId || "").toLowerCase() === "solana" && item.tokenAddress)
    .filter((item) => item.tokenAddress !== SOL_MINT)
    .map((item) => ({
      tokenMint: item.tokenAddress,
      source,
      profile: item
    }));
}

function sniperCandidatesFromDexPairs(pairs, source) {
  return (Array.isArray(pairs) ? pairs : [])
    .filter((pair) => String(pair?.chainId || "").toLowerCase() === "solana")
    .map((pair) => {
      const base = pair?.baseToken || {};
      const quote = pair?.quoteToken || {};
      const token = base.address && base.address !== SOL_MINT ? base : quote.address && quote.address !== SOL_MINT ? quote : null;
      if (!token?.address) return null;
      const links = dexPairLinks(pair);
      return {
        tokenMint: token.address,
        source,
        profile: {
          symbol: token.symbol || "",
          name: token.name || "",
          icon: pair?.info?.imageUrl || "",
          imageUrl: pair?.info?.imageUrl || "",
          websiteUrl: links.websiteUrl,
          twitterUrl: links.twitterUrl,
          telegramUrl: links.telegramUrl,
          dexId: pair?.dexId || pair?.dexName || "",
          dexName: pair?.dexId || pair?.dexName || "",
          pairAddress: pair?.pairAddress || "",
          pairUrl: pair?.url || "",
          raydiumPool: /raydium|meteora|orca/i.test(String(pair?.dexId || pair?.dexName || "")) ? (pair?.pairAddress || "") : "",
          graduated: Boolean(/raydium|meteora|orca/i.test(String(pair?.dexId || pair?.dexName || "")) && String(token.address || "").toLowerCase().endsWith("pump")),
          pairCreatedAt: pair?.pairCreatedAt || null,
          marketCap: firstNumber(pair?.marketCap, pair?.fdv),
          fdv: pair?.fdv || null,
          liquidityUsd: pair?.liquidity?.usd || null,
          liquidity: pair?.liquidity || null,
          volume: pair?.volume || null,
          txns: pair?.txns || null,
          priceChange: pair?.priceChange || null
        }
      };
    })
    .filter(Boolean);
}

function nextSniperScanState(userId, mode) {
  const key = `${userId}:${mode}`;
  const modeSeed = stringModulo(mode, 97);
  const previous = sniperScanState.get(key) || {
    refreshCount: 0,
    candidateOffset: -24 + modeSeed,
    displayOffset: -5 + (modeSeed % 19)
  };
  const refreshCount = previous.refreshCount + 1;
  const jitter = Math.floor(Math.random() * 17);
  const next = {
    refreshCount,
    candidateOffset: previous.candidateOffset + 37 + (refreshCount % 5) * 11 + jitter,
    displayOffset: previous.displayOffset + 7 + (refreshCount % 4) * 3 + jitter,
    previousShown: uniqueStrings([
      ...(previous.recentShown || previous.lastShown || []),
      ...recentSniperShownMintsForUser(userId, mode)
    ]).slice(-180),
    lastShown: previous.lastShown || [],
    recentShown: previous.recentShown || [],
    updatedAt: Date.now()
  };
  sniperScanState.set(key, next);
  pruneSniperScanState();
  return next;
}

function recentSniperShownMintsForUser(userId, currentMode) {
  const prefix = `${userId}:`;
  const rows = [];
  for (const [key, state] of sniperScanState.entries()) {
    if (!key.startsWith(prefix) || key === `${userId}:${currentMode}`) continue;
    rows.push(...(state.recentShown || state.lastShown || []));
  }
  return rows;
}

function stringModulo(value, modulo) {
  const text = String(value || "");
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = (hash * 31 + text.charCodeAt(index)) % modulo;
  }
  return hash;
}

function pruneSniperScanState() {
  const maxAgeMs = 60 * 60 * 1000;
  const now = Date.now();
  for (const [key, state] of sniperScanState.entries()) {
    if (now - Number(state.updatedAt || 0) > maxAgeMs) {
      sniperScanState.delete(key);
    }
  }
}

function rotateSniperCandidatePool(candidates, scanState) {
  const unique = uniqueSniperCandidates(candidates);
  const primary = unique.filter((candidate) => candidate.source !== "top-boost");
  const backup = unique.filter((candidate) => candidate.source === "top-boost");
  const pool = primary.length >= 80 ? [...primary, ...backup] : unique;
  return rotateItems(pool.slice(0, 520), scanState.candidateOffset).slice(0, 220);
}

function rotatePumpSnipeCandidatePool(candidates, scanState) {
  const unique = uniqueSniperCandidates(candidates);
  const primary = unique.filter((candidate) => candidate.source !== "top-boost");
  const backup = unique.filter((candidate) => candidate.source === "top-boost");
  const pool = primary.length >= 30 ? primary : [...primary, ...backup];
  return rotateItems(pool.slice(0, 560), scanState.candidateOffset).slice(0, 240);
}

function uniqueSniperCandidates(candidates) {
  const seen = new Set();
  const rows = [];
  for (const candidate of candidates || []) {
    const tokenMint = candidate?.tokenMint;
    if (!tokenMint || seen.has(tokenMint)) continue;
    seen.add(tokenMint);
    rows.push(candidate);
  }
  return rows;
}

function compareSniperScores(a, b) {
  return Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0)
    || (b.score - a.score)
    || (a.rugRisk - b.rugRisk)
    || (a.exitRisk - b.exitRisk)
    || (a.manipulationScore - b.manipulationScore);
}

function compareSniperScoresForMode(mode, a, b) {
  if (mode === "moonshot") {
    const aMc = Number(a.marketCap || 0);
    const bMc = Number(b.marketCap || 0);
    const aSweetSpot = aMc >= 4_000 && aMc <= 40_000 ? 1 : 0;
    const bSweetSpot = bMc >= 4_000 && bMc <= 40_000 ? 1 : 0;
    return (bSweetSpot - aSweetSpot)
      || Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0)
      || (b.scalpScore - a.scalpScore)
      || (b.score - a.score)
      || (Number(b.volume5m || 0) - Number(a.volume5m || 0))
      || (a.exitRisk - b.exitRisk)
      || (a.rugRisk - b.rugRisk)
      || (aMc - bMc);
  }
  if (mode === "fast" || mode === "pumpsnipe") {
    return (b.scalpScore - a.scalpScore)
      || Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0)
      || (Number(b.volume5m || 0) - Number(a.volume5m || 0))
      || (b.score - a.score)
      || (a.exitRisk - b.exitRisk)
      || (a.rugRisk - b.rugRisk);
  }
  if (mode === "smart") {
    return Number(b.buyPressure || 0) - Number(a.buyPressure || 0)
      || Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0)
      || (b.score - a.score)
      || (a.rugRisk - b.rugRisk);
  }
  if (mode === "long") {
    return (Number(b.h6 || 0) - Number(a.h6 || 0))
      || (Number(b.h24 || 0) - Number(a.h24 || 0))
      || Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0)
      || (b.score - a.score)
      || (a.rugRisk - b.rugRisk);
  }
  if (mode === "meme" || mode === "ai") {
    return Number(b.narrative || 0) - Number(a.narrative || 0)
      || Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0)
      || (b.score - a.score)
      || (Number(b.volumeH1 || 0) - Number(a.volumeH1 || 0));
  }
  return compareSniperScores(a, b);
}

function selectRotatingSniperRows(rows, scanState, limit = 6) {
  const displayLimit = Math.max(1, Math.min(Number.parseInt(limit, 10) || 6, 12));
  if (rows.length <= displayLimit) return uniqueSniperScoreRows(rotateItems(rows, scanState.displayOffset)).slice(0, displayLimit);

  const previousShown = new Set(scanState.previousShown || []);
  const lastShown = new Set(scanState.lastShown || []);
  const neverShownRows = rows.filter((row) => !previousShown.has(row.tokenMint));
  const notLastRows = rows.filter((row) => !lastShown.has(row.tokenMint));
  const pool = neverShownRows.length >= displayLimit
    ? neverShownRows
    : notLastRows.length >= displayLimit
      ? uniqueSniperScoreRows([...neverShownRows, ...notLastRows])
      : uniqueSniperScoreRows([...neverShownRows, ...notLastRows, ...rows]);
  return uniqueSniperScoreRows(rotateItems(pool.slice(0, 180), scanState.displayOffset)).slice(0, displayLimit);
}

function rememberSniperScanRows(userId, mode, rows) {
  const key = `${userId}:${mode}`;
  const previous = sniperScanState.get(key) || {};
  const recentShown = uniqueStrings([
    ...(previous.recentShown || previous.lastShown || []),
    ...rows.map((row) => row.tokenMint)
  ]).slice(-80);
  sniperScanState.set(key, {
    ...previous,
    lastShown: rows.map((row) => row.tokenMint),
    recentShown,
    updatedAt: Date.now()
  });
}

function uniqueStrings(values) {
  const seen = new Set();
  const unique = [];
  for (const value of values || []) {
    if (!value || seen.has(value)) continue;
    seen.add(value);
    unique.push(value);
  }
  return unique;
}

function uniqueSniperScoreRows(rows) {
  const seen = new Set();
  const unique = [];
  for (const row of rows) {
    if (!row?.tokenMint || seen.has(row.tokenMint)) continue;
    seen.add(row.tokenMint);
    unique.push(row);
  }
  return unique;
}

async function findAutoSnipePick(userId) {
  const settings = sniperModeDefaults("autosnipe");
  const scanState = nextSniperScanState(userId, "autosnipe");
  const candidates = await fetchSniperCandidatesForMode("autosnipe", { scanState });
  const scored = [];
  const precheckStats = createSniperPrecheckStats();
  const scanPool = await hydrateSniperCandidates(rotateSniperCandidatePool(candidates, scanState));

  await runWithConcurrency(scanPool, Math.min(6, Math.max(3, CONFIG.balanceConcurrency)), async (candidate) => {
    try {
      scored.push(await scoreSniperCandidate(candidate, settings));
    } catch {
      // Ignore broken rows; AutoSnipe only needs the best valid setup.
    }
  });

  const recentTokens = await recentAutoSnipeTokenSet(userId);
  const previousShown = new Set(scanState.previousShown || []);
  const strictQualified = scored
    .filter((item) => isAutoSnipePick(item))
    .sort(compareAutoSnipeScores);
  const strictMints = new Set(strictQualified.map((item) => item.tokenMint));
  const backupQualified = scored
    .filter((item) => !strictMints.has(item.tokenMint))
    .filter((item) => isAutoSnipeBackupPick(item))
    .sort(compareAutoSnipeScores);

  let tier = "strict";
  let precheck = await filterSniperCandidatesForBuy(
    freshAutoSnipeRows(strictQualified, previousShown, recentTokens).slice(0, 18),
    { userId, slippageBps: AUTOSNIPE_SLIPPAGE_BPS, targetAccepted: 6 }
  );
  mergeSniperPrecheckStats(precheckStats, precheck.stats);
  let safeFresh = precheck.rows;
  if (safeFresh.length === 0) {
    tier = "backup";
    precheck = await filterSniperCandidatesForBuy(
      freshAutoSnipeRows(backupQualified, previousShown, recentTokens).slice(0, 30),
      { userId, slippageBps: AUTOSNIPE_SLIPPAGE_BPS, targetAccepted: 6 }
    );
    mergeSniperPrecheckStats(precheckStats, precheck.stats);
    safeFresh = precheck.rows;
  }
  const pick = chooseAutoModePick(safeFresh, scanState);

  if (pick) {
    rememberSniperScanRows(userId, "autosnipe", [pick]);
  }

  return {
    pick,
    settings,
    scoredCount: scored.length,
    qualifiedCount: strictQualified.length + backupQualified.length,
    strictCount: strictQualified.length,
    backupCount: backupQualified.length,
    freshCount: safeFresh.length,
    tier,
    precheckStats
  };
}

async function findPumpSnipePick(userId) {
  const settings = sniperModeDefaults("pumpsnipe");
  const scanState = nextSniperScanState(userId, "pumpsnipe");
  const candidates = await fetchSniperCandidatesForMode("pumpsnipe", { scanState });
  const scored = [];
  const precheckStats = createSniperPrecheckStats();
  const scanPool = await hydrateSniperCandidates(rotatePumpSnipeCandidatePool(candidates, scanState));

  await runWithConcurrency(scanPool, Math.min(8, Math.max(4, CONFIG.balanceConcurrency)), async (candidate) => {
    try {
      scored.push(await scoreSniperCandidate(candidate, settings));
    } catch {
      // Ignore broken rows; PumpSnipe only needs the best valid early setup.
    }
  });

  const recentTokens = await recentAutoSnipeTokenSet(userId, "pumpsnipe");
  const previousShown = new Set(scanState.previousShown || []);
  const strictQualified = scored
    .filter((item) => isPumpSnipePick(item))
    .sort(comparePumpSnipeScores);
  const strictMints = new Set(strictQualified.map((item) => item.tokenMint));
  const backupQualified = scored
    .filter((item) => !strictMints.has(item.tokenMint))
    .filter((item) => isPumpSnipeBackupPick(item))
    .sort(comparePumpSnipeScores);

  let tier = "strict";
  let precheck = await filterSniperCandidatesForBuy(
    freshPumpSnipeRows(strictQualified, previousShown, recentTokens).slice(0, 24),
    { userId, slippageBps: PUMPSNIPE_SLIPPAGE_BPS, targetAccepted: 6 }
  );
  mergeSniperPrecheckStats(precheckStats, precheck.stats);
  let safeFresh = precheck.rows;
  if (safeFresh.length === 0) {
    tier = "backup";
    precheck = await filterSniperCandidatesForBuy(
      freshPumpSnipeRows(backupQualified, previousShown, recentTokens).slice(0, 36),
      { userId, slippageBps: PUMPSNIPE_SLIPPAGE_BPS, targetAccepted: 6 }
    );
    mergeSniperPrecheckStats(precheckStats, precheck.stats);
    safeFresh = precheck.rows;
  }
  const pick = chooseAutoModePick(safeFresh, scanState);
  if (pick) {
    rememberSniperScanRows(userId, "pumpsnipe", [pick]);
  }

  return {
    pick,
    settings,
    scoredCount: scored.length,
    qualifiedCount: strictQualified.length + backupQualified.length,
    strictCount: strictQualified.length,
    backupCount: backupQualified.length,
    freshCount: safeFresh.length,
    tier,
    precheckStats
  };
}

function freshAutoSnipeRows(rows, previousShown, recentTokens) {
  const fresh = rows.filter((item) => {
    const recentlySeen = previousShown.has(item.tokenMint) || recentTokens.has(item.tokenMint);
    return !recentlySeen;
  });
  if (fresh.length > 0) return fresh;
  return [];
}

function freshPumpSnipeRows(rows, previousShown, recentTokens) {
  const fresh = rows.filter((item) => {
    const recentlySeen = previousShown.has(item.tokenMint) || recentTokens.has(item.tokenMint);
    return !recentlySeen;
  });
  if (fresh.length > 0) return fresh;
  return [];
}

function chooseAutoModePick(rows, scanState) {
  const unique = uniqueSniperScoreRows(rows);
  if (unique.length === 0) return null;
  return rotateItems(unique, scanState.displayOffset)[0] || unique[0] || null;
}

async function filterSniperCandidatesForBuy(rows, options = {}) {
  const accepted = [];
  const stats = createSniperPrecheckStats();
  const targetAccepted = Math.max(1, Number(options.targetAccepted || 1));
  const shouldCheckRoute = options.checkRoute === true;
  const taker = shouldCheckRoute
    ? await sniperRoutePrecheckTaker(options.userId, options.routeProbeLamports || SNIPER_ROUTE_PROBE_LAMPORTS)
    : null;

  for (const row of rows) {
    if (accepted.length >= targetAccepted) break;
    stats.checked += 1;
    let isToken2022 = false;

    try {
      const safety = await getMintSafetyInfo(row.tokenMint);
      if (safety.tokenProgram === TOKEN_2022_PROGRAM_ID.toBase58()) {
        stats.token2022 += 1;
        isToken2022 = true;
      }
      if (safety.freezeAuthority) {
        stats.freezeAuthority += 1;
        stats.lastReject = `${sniperCandidateLabel(row)} blocked: freeze authority active`;
        continue;
      }
      if (safety.mintAuthority) {
        stats.mintAuthority += 1;
        stats.lastReject = `${sniperCandidateLabel(row)} blocked: mint authority active`;
        continue;
      }
    } catch {
      stats.mintReadUnavailable += 1;
    }

    if (shouldCheckRoute && taker && CONFIG.jupiterApiKey) {
      const route = await checkSniperRoundTripRoute({
        tokenMint: row.tokenMint,
        taker,
        amountLamports: options.routeProbeLamports || SNIPER_ROUTE_PROBE_LAMPORTS,
        slippageBps: options.slippageBps || CONFIG.sniperDefaultSlippageBps
      });
      if (!route.ok) {
        stats.routeRejected += 1;
        stats.lastReject = `${sniperCandidateLabel(row)} route blocked: ${route.reason}`;
        continue;
      }

      accepted.push({
        ...row,
        autoSnipeSafetyNote: isToken2022
          ? "Token-2022 mint; buy route precheck passed"
          : "mint and buy route precheck passed"
      });
      stats.accepted += 1;
      continue;
    }

    accepted.push({
      ...row,
      autoSnipeSafetyNote: isToken2022
        ? "Token-2022 mint; trade route checks after wallet and amount"
        : "mint precheck passed; trade route checks after wallet and amount"
    });
    stats.accepted += 1;
  }

  return { rows: accepted, stats };
}

async function sniperRoutePrecheckTaker(userId, minLamports = SNIPER_ROUTE_PROBE_LAMPORTS) {
  try {
    const store = await readWalletStore();
    const wallets = walletsForOwner(store, userId);
    for (const wallet of wallets.slice(0, 6)) {
      try {
        const publicKey = new PublicKey(wallet.publicKey);
        const balance = await getSolBalanceCached(publicKey, { force: false });
        if (balance >= minLamports + CONFIG.buyReserveLamports) {
          return publicKey;
        }
      } catch {
        // Try the next wallet.
      }
    }
    return null;
  } catch {
    return null;
  }
}

async function checkSniperRoundTripRoute({ tokenMint, taker, amountLamports, slippageBps }) {
  try {
    const buyOrder = await createJupiterOrder({
      taker,
      inputMint: SOL_MINT,
      outputMint: tokenMint,
      amount: amountLamports,
      slippageBps
    });
    const estimatedTokenOut = BigInt(buyOrder.outAmount || buyOrder.outputAmount || 0);
    if (estimatedTokenOut <= 0n) {
      return { ok: false, reason: "buy route returned zero token output" };
    }

    return { ok: true, estimatedTokenOut: estimatedTokenOut.toString() };
  } catch (error) {
    return { ok: false, reason: friendlyError(error) };
  }
}

function createSniperPrecheckStats() {
  return {
    checked: 0,
    accepted: 0,
    token2022: 0,
    freezeAuthority: 0,
    mintAuthority: 0,
    mintReadUnavailable: 0,
    routeRejected: 0,
    lastReject: ""
  };
}

function mergeSniperPrecheckStats(target, source) {
  if (!source) return target;
  for (const key of ["checked", "accepted", "token2022", "freezeAuthority", "mintAuthority", "mintReadUnavailable", "routeRejected"]) {
    target[key] += Number(source[key] || 0);
  }
  if (source.lastReject) target.lastReject = source.lastReject;
  return target;
}

function formatSniperPrecheckSummary(stats) {
  if (!stats || !stats.checked) return "";
  const blocked = stats.freezeAuthority + stats.mintAuthority + stats.routeRejected;
  const parts = [
    `Prechecked: ${stats.checked}`,
    `Mint-safe: ${stats.accepted}`,
    blocked ? `Blocked: ${blocked}` : "",
    stats.routeRejected ? `No route: ${stats.routeRejected}` : "",
    stats.mintAuthority ? `Mint active: ${stats.mintAuthority}` : "",
    stats.freezeAuthority ? `Freeze active: ${stats.freezeAuthority}` : "",
    stats.token2022 ? `Token-2022 tested: ${stats.token2022}` : "",
    stats.mintReadUnavailable ? `Mint read skipped: ${stats.mintReadUnavailable}` : ""
  ].filter(Boolean);
  return [
    parts.join(" | "),
    stats.lastReject ? `Last blocker: ${stats.lastReject}` : ""
  ].filter(Boolean).join("\n");
}

function sniperCandidateLabel(row) {
  return row?.symbol || row?.name || shortMint(row?.tokenMint || "");
}

function formatAutoSnipeTier(tier) {
  if (tier === "strict") return "strict";
  if (tier === "backup") return "backup";
  if (tier === "repeat") return "repeat-strength";
  return "available";
}

async function recentAutoSnipeTokenSet(userId, source = "autosnipe") {
  const history = await readTradeHistory();
  const cutoff = Date.now() - 6 * 60 * 60 * 1000;
  const tokens = new Set();

  for (const trade of history.trades) {
    if (String(trade.userId) !== String(userId)) continue;
    if (trade.type !== "buy" || trade.source !== source || !trade.tokenMint) continue;
    const timestamp = Date.parse(trade.timestamp || "");
    if (Number.isFinite(timestamp) && timestamp >= cutoff) {
      tokens.add(trade.tokenMint);
    }
  }

  return tokens;
}

function isAutoSnipePick(item) {
  const flags = new Set(item.riskFlags || []);
  const liquidityToMarketCap = item.marketCap > 0 ? item.liquidityUsd / item.marketCap : 0;

  return item.category !== "Avoid"
    && !isPumpMayhemToken(item)
    && item.score >= 78
    && item.rugRisk <= 48
    && item.exitRisk <= 58
    && item.manipulationScore <= 68
    && item.scalpScore >= 4
    && item.marketCap >= 5_000
    && item.marketCap <= 220_000
    && item.liquidityUsd >= 4_000
    && item.liquidityUsd <= 120_000
    && liquidityToMarketCap >= 0.025
    && liquidityToMarketCap <= 1.25
    && (item.volume5m >= 500 || item.volumeH1 >= 5_000)
    && item.buyPressure >= 1.03
    && item.m5 >= -8
    && item.m5 <= 55
    && item.h1 >= -5
    && item.h1 <= 120
    && !flags.has("hard dump")
    && !flags.has("dumping")
    && !flags.has("sell pressure")
    && !flags.has("low volume");
}

function isAutoSnipeBackupPick(item) {
  const flags = new Set(item.riskFlags || []);
  const liquidityToMarketCap = item.marketCap > 0 ? item.liquidityUsd / item.marketCap : 0;

  return item.category !== "Avoid"
    && !isPumpMayhemToken(item)
    && item.score >= 64
    && item.rugRisk <= 64
    && item.exitRisk <= 76
    && item.manipulationScore <= 84
    && item.scalpScore >= 3
    && item.marketCap >= 3_000
    && item.marketCap <= 450_000
    && item.liquidityUsd >= 2_500
    && liquidityToMarketCap >= 0.012
    && (item.volume5m >= 250 || item.volumeH1 >= 2_500)
    && item.buyPressure >= 0.95
    && item.m5 >= -12
    && item.h1 >= -10
    && !flags.has("hard dump")
    && !flags.has("sell pressure")
    && !flags.has("low volume");
}

function isPumpSnipePick(item) {
  const flags = new Set(item.riskFlags || []);
  const liquidityToMarketCap = item.marketCap > 0 ? item.liquidityUsd / item.marketCap : 0;
  const earlyEnough = item.pairAgeMinutes === null
    || item.pairAgeMinutes <= 240
    || isPumpStyleToken(item);

  return item.category !== "Avoid"
    && earlyEnough
    && !isPumpMayhemToken(item)
    && item.score >= 50
    && item.rugRisk <= 84
    && item.exitRisk <= 92
    && item.manipulationScore <= 96
    && item.scalpScore >= 2
    && item.marketCap >= 500
    && item.marketCap <= 220_000
    && item.liquidityUsd >= 500
    && liquidityToMarketCap >= 0.004
    && (item.volume5m >= 75 || item.volumeH1 >= 750)
    && item.buyPressure >= 0.65
    && item.m5 >= -25
    && item.m5 <= 180
    && item.h1 >= -35
    && !flags.has("hard dump")
    && !flags.has("sell pressure");
}

function isPumpSnipeBackupPick(item) {
  const flags = new Set(item.riskFlags || []);
  const liquidityToMarketCap = item.marketCap > 0 ? item.liquidityUsd / item.marketCap : 0;

  return item.category !== "Avoid"
    && !isPumpMayhemToken(item)
    && item.score >= 42
    && item.rugRisk <= 90
    && item.exitRisk <= 96
    && item.manipulationScore <= 98
    && item.scalpScore >= 1
    && item.marketCap >= 400
    && item.marketCap <= 320_000
    && item.liquidityUsd >= 400
    && liquidityToMarketCap >= 0.003
    && (item.volume5m >= 50 || item.volumeH1 >= 400)
    && item.buyPressure >= 0.55
    && item.m5 >= -30
    && !flags.has("hard dump")
    && !flags.has("sell pressure");
}

function compareAutoSnipeScores(a, b) {
  return (b.scalpScore - a.scalpScore)
    || (b.score - a.score)
    || (Number(b.buyPressure || 0) - Number(a.buyPressure || 0))
    || (Number(b.volume5m || 0) - Number(a.volume5m || 0))
    || (a.exitRisk - b.exitRisk)
    || (a.rugRisk - b.rugRisk)
    || (a.manipulationScore - b.manipulationScore);
}

function comparePumpSnipeScores(a, b) {
  return (pumpFreshnessScore(b) - pumpFreshnessScore(a))
    || (Number(b.modeRelevance || 0) - Number(a.modeRelevance || 0))
    || (b.scalpScore - a.scalpScore)
    || (b.score - a.score)
    || (Number(b.buyPressure || 0) - Number(a.buyPressure || 0))
    || (Number(b.volume5m || 0) - Number(a.volume5m || 0))
    || (a.exitRisk - b.exitRisk)
    || (a.rugRisk - b.rugRisk);
}

function pumpFreshnessScore(item) {
  const age = Number(item.pairAgeMinutes);
  if (!Number.isFinite(age)) return isPumpStyleToken(item) ? 4 : 1;
  if (age <= 15) return 8;
  if (age <= 45) return 7;
  if (age <= 90) return 6;
  if (age <= 180) return 4;
  if (age <= 360) return 2;
  return 0;
}

function isPumpStyleToken(item) {
  const haystack = `${item?.tokenMint || ""} ${item?.symbol || ""} ${item?.name || ""} ${item?.source || ""} ${item?.category || ""}`.toLowerCase();
  return haystack.includes("pump");
}

function isPumpMayhemToken(item) {
  // Explicit boolean / enum flags some pump payloads carry (in case the mode isn't in any text field).
  if (item?.mayhem === true || item?.isMayhem === true || item?.pumpMayhem === true) return true;
  const modeFields = [item?.mode, item?.pumpMode, item?.curveType, item?.curve_type, item?.bondingCurveType, item?.coinMode, item?.launchMode]
    .filter(Boolean).map((v) => String(v).toLowerCase());
  if (modeFields.some((v) => v.includes("mayhem"))) return true;
  const labels = [
    item?.tokenMint,
    item?.symbol,
    item?.name,
    item?.source,
    item?.category,
    item?.platform,
    item?.market,
    item?.dexId,
    item?.profileSource,
    item?.profile?.source,
    item?.profile?.market,
    item?.profile?.mode,
    item?.metadata?.source,
    item?.metadata?.market,
    item?.metadata?.mode,
    item?.dexPair?.dexId,
    item?.dexPair?.labels,
    item?.labels,
    item?.riskFlags
  ].flat().filter(Boolean).join(" ").toLowerCase();
  return /\bmayhem\b/.test(labels) || labels.includes("pump mayhem") || labels.includes("mayhem mode");
}

function isStrictSniperPick(item, settings) {
  return item.category !== "Avoid"
    && !isPumpMayhemToken(item)
    && item.score >= Math.max(52, settings.minScore - 10)
    && item.rugRisk <= settings.maxRisk + 14
    && item.exitRisk <= 72
    && item.scalpScore >= 3
    && !item.riskFlags?.includes("dumping")
    && !item.riskFlags?.includes("sell pressure")
    && !item.riskFlags?.includes("low volume");
}

function isFallbackSniperPick(item, settings) {
  return item.score >= Math.max(45, settings.minScore - 22)
    && !isPumpMayhemToken(item)
    && item.rugRisk <= settings.maxRisk + 24
    && item.exitRisk <= 84
    && item.scalpScore >= 2
    && !item.riskFlags?.includes("hard dump");
}

function buildQualifiedSniperRows(scored, settings) {
  const safeMode = String(settings.mode || "safe");
  const eligibleRows = (scored || []).filter((item) => !isPumpMayhemToken(item));
  const sorter = safeMode === "pumpsnipe"
    ? comparePumpSnipeScores
    : (a, b) => compareSniperScoresForMode(safeMode, a, b);

  if (safeMode === "pumpsnipe") {
    const strictRows = eligibleRows.filter((item) => isPumpSnipePick(item)).sort(sorter);
    const strictMints = new Set(strictRows.map((item) => item.tokenMint));
    const fallbackRows = eligibleRows
      .filter((item) => !strictMints.has(item.tokenMint))
      .filter((item) => isPumpSnipeBackupPick(item))
      .sort(sorter);
    return {
      strictRows,
      fallbackRows,
      qualifiedRows: uniqueSniperScoreRows([...strictRows, ...fallbackRows]).sort(sorter)
    };
  }

  const modeRows = eligibleRows
    .filter((item) => isModeRelevantSniperPick(item, safeMode))
    .sort(sorter);
  const modeMints = new Set(modeRows.map((item) => item.tokenMint));
  const looseRows = eligibleRows
    .filter((item) => !modeMints.has(item.tokenMint))
    .filter((item) => isLooseModeRelevantSniperPick(item, safeMode))
    .sort(sorter);
  const looseMints = new Set([...modeMints, ...looseRows.map((item) => item.tokenMint)]);
  const fallbackRows = eligibleRows
    .filter((item) => !looseMints.has(item.tokenMint))
    .filter((item) => isModeFallbackSniperPick(item, safeMode))
    .sort(sorter);
  const genericRows = eligibleRows
    .filter((item) => !looseMints.has(item.tokenMint))
    .filter((item) => isStrictSniperPick(item, settings) || isFallbackSniperPick(item, settings))
    .sort(sorter);

  return {
    strictRows: modeRows,
    fallbackRows: uniqueSniperScoreRows([...looseRows, ...fallbackRows, ...genericRows]).sort(sorter),
    qualifiedRows: uniqueSniperScoreRows([...modeRows, ...looseRows, ...fallbackRows, ...genericRows]).sort(sorter)
  };
}

async function hydrateSniperCandidates(candidates) {
  const unique = uniqueSniperCandidates(candidates);
  const pairByToken = new Map();

  await runWithConcurrency(chunkArray(unique.map((item) => item.tokenMint), 30), 2, async (chunk) => {
    const pairs = await fetchDexScreenerTokenPairsBatch(chunk).catch(() => []);
    for (const tokenMint of chunk) {
      const best = bestDexPairForToken(tokenMint, pairs);
      if (best) pairByToken.set(tokenMint, best);
    }
  });

  return unique.map((candidate) => {
    const pair = pairByToken.get(candidate.tokenMint);
    const metadata = pair
      ? mergeSniperMetadata(metadataFromDexPair(candidate.tokenMint, pair), candidate.profile, candidate.source)
      : mergeSniperMetadata({}, candidate.profile, candidate.source);
    if (metadata) {
      dexMetadataCache.set(candidate.tokenMint, { cachedAt: Date.now(), value: metadata });
    }
    return {
      ...candidate,
      dexPair: pair || null,
      metadata
    };
  });
}

function mergeSniperMetadata(dexValue, profile = {}, source = "profile") {
  const profileVolume = Number(profile.volume || profile.volumeUsd || profile.volume_usd || 0);
  return {
    ...dexValue,
    symbol: dexValue.symbol || profile.symbol || "",
    name: dexValue.name || profile.name || "",
    imageUrl: firstString(
      dexValue.imageUrl,
      profile.imageUrl,
      profile.image_url,
      profile.icon,
      profile.image,
      profile.image_uri,
      profile.logoURI,
      profile.logo,
      profile.metadata?.image
    ),
    description: profile.description || "",
    marketCap: firstMeaningfulNumber(
      dexValue.marketCap,
      profile.marketCap,
      profile.usdMarketCap,
      profile.usd_market_cap,
      profile.market_cap_usd,
      profile.market_cap,
      profile.mcap,
      profile.mc,
      profile.fdv
    ),
    fdv: firstMeaningfulNumber(dexValue.fdv, profile.fdv, profile.fdvUsd, profile.fdv_usd),
    volume: dexValue.volume || (profileVolume > 0 ? { h1: profileVolume } : null),
    volume5m: dexValue.volume?.m5 || profile.volume5m || profile.volume_5m || null,
    volumeM15: dexValue.volume?.m15 || dexValue.volume?.m15m || profile.volumeM15 || profile.volume15m || profile.volume_15m || null,
    volumeM30: dexValue.volume?.m30 || dexValue.volume?.m30m || profile.volumeM30 || profile.volume30m || profile.volume_30m || null,
    volumeH1: dexValue.volume?.h1 || profile.volumeH1 || profile.volume_h1 || null,
    volumeH24: dexValue.volume?.h24 || dexValue.volume?.d1 || profile.volumeH24 || profile.volume24h || profile.volume_h24 || null,
    pairCreatedAt: dexValue.pairCreatedAt || normalizePairCreatedAt(firstString(
      profile.pairCreatedAt,
      profile.pair_created_at,
      profile.pairCreatedTimestamp,
      profile.created_timestamp,
      profile.createdAt,
      profile.created_at,
      profile.poolCreatedAt,
      profile.listedAt,
      profile.launchTimestamp
    )),
    profileSource: source,
    websiteUrl: dexValue.websiteUrl || profile.websiteUrl || profile.website_url || profile.website || profile.url || profile.links?.website || "",
    twitterUrl: dexValue.twitterUrl || profile.twitterUrl || profile.twitter_url || profile.twitter || profile.xUrl || profile.links?.twitter || profile.links?.x || "",
    telegramUrl: dexValue.telegramUrl || profile.telegramUrl || profile.telegram_url || profile.telegram || profile.links?.telegram || "",
    sniperCount: profile.sniperCount || profile.snipers || profile.sniper_count || profile.sniperWallets || profile.sniper_wallets || 0,
    boostAmount: Number(profile.amount || profile.totalAmount || 0)
  };
}

function normalizePairCreatedAt(value) {
  return normalizePairTimestamp(value);
}

function isCleanTrendCandidate(item, options = {}) {
  const flags = new Set(item.riskFlags || []);
  const minM5 = Number(options.minM5 ?? -12);
  const minH1 = Number(options.minH1 ?? -12);
  const minH6 = Number(options.minH6 ?? -20);
  const maxManipulation = Number(options.maxManipulation ?? 82);
  return item.category !== "Avoid"
    && !flags.has("hard dump")
    && !flags.has("sell pressure")
    && (options.allowDumping || !flags.has("dumping"))
    && Number(item.m5 || 0) >= minM5
    && Number(item.h1 || 0) >= minH1
    && Number(item.h6 || 0) >= minH6
    && Number(item.manipulationScore || 0) <= maxManipulation;
}

function isModeRelevantSniperPick(item, mode) {
  if (mode === "autosnipe") return Number(item.modeRelevance || 0) >= 4 && isCleanTrendCandidate(item, { minM5: -6, minH1: -8, minH6: -15, maxManipulation: 70 });
  if (mode === "pumpsnipe") return Number(item.modeRelevance || 0) >= 3 && isCleanTrendCandidate(item, { allowDumping: true, minM5: -18, minH1: -22, minH6: -30, maxManipulation: 92 });
  if (mode === "moonshot") return Number(item.modeRelevance || 0) >= 3
    && item.marketCap >= 4_000
    && item.marketCap <= 40_000
    && isCleanTrendCandidate(item, { allowDumping: true, minM5: -12, minH1: -15, minH6: -25, maxManipulation: 78 });
  if (mode === "long") return Number(item.modeRelevance || 0) >= 3
    && item.h6 >= -5
    && item.h24 >= -10
    && isCleanTrendCandidate(item, { minM5: -10, minH1: -8, minH6: -8, maxManipulation: 62 });
  if (mode === "safe") return Number(item.modeRelevance || 0) >= 3
    && isCleanTrendCandidate(item, { minM5: -6, minH1: -5, minH6: -10, maxManipulation: 58 });
  if (mode === "smart") return Number(item.modeRelevance || 0) >= 3
    && isCleanTrendCandidate(item, { minM5: -8, minH1: -6, minH6: -12, maxManipulation: 64 });
  if (mode === "fast") return Number(item.modeRelevance || 0) >= 3
    && isCleanTrendCandidate(item, { minM5: -6, minH1: -8, minH6: -15, maxManipulation: 72 });
  if (mode === "ai" || mode === "meme") return Number(item.modeRelevance || 0) >= 5
    && isCleanTrendCandidate(item, { allowDumping: true, minM5: -10, minH1: -10, minH6: -18, maxManipulation: 75 });
  return Number(item.modeRelevance || 0) >= 3 && isCleanTrendCandidate(item);
}

function isLooseModeRelevantSniperPick(item, mode) {
  if (mode === "moonshot") {
    return item.marketCap >= 4_000
      && item.marketCap <= 40_000
      && item.liquidityUsd >= 150
      && item.scalpScore >= 1
      && (item.volume5m >= 10 || item.volumeH1 >= 100)
      && isCleanTrendCandidate(item, { allowDumping: true, minM5: -18, minH1: -24, minH6: -34, maxManipulation: 86 });
  }
  if (mode === "pumpsnipe") {
    return item.marketCap >= 3_000
      && item.marketCap <= 60_000
      && item.liquidityUsd >= 400
      && item.scalpScore >= 1
      && (item.volume5m >= 50 || item.volumeH1 >= 400)
      && item.m5 >= -30
      && isCleanTrendCandidate(item, { allowDumping: true, minM5: -30, minH1: -35, minH6: -45, maxManipulation: 94 });
  }
  if (mode === "fast") {
    return item.scalpScore >= 2
      && (item.volume5m >= 75 || item.volumeH1 >= 750)
      && item.m5 >= -12
      && item.buyPressure >= 0.9
      && isCleanTrendCandidate(item, { allowDumping: true, minM5: -12, minH1: -14, minH6: -20, maxManipulation: 78 });
  }
  if (mode === "meme" || mode === "ai") {
    return item.narrative > 0
      && item.scalpScore >= 1
      && (item.volume5m >= 50 || item.volumeH1 >= 750)
      && isCleanTrendCandidate(item, { allowDumping: true, minM5: -12, minH1: -14, minH6: -22, maxManipulation: 80 });
  }
  if (mode === "smart") {
    return item.buyPressure >= 1
      && item.liquidityUsd >= 1_000
      && item.scalpScore >= 1
      && item.m5 <= 35
      && isCleanTrendCandidate(item, { minM5: -10, minH1: -10, minH6: -18, maxManipulation: 70 });
  }
  if (mode === "long") {
    return item.h1 >= -5
      && item.h6 >= -10
      && item.liquidityUsd >= 1_000
      && item.volumeH1 >= 1_000
      && isCleanTrendCandidate(item, { minM5: -12, minH1: -8, minH6: -12, maxManipulation: 68 });
  }
  if (mode === "safe") {
    return item.liquidityUsd >= 5_000
      && (item.volume5m >= 100 || item.volumeH1 >= 1_500)
      && item.buyPressure >= 0.95
      && isCleanTrendCandidate(item, { minM5: -8, minH1: -8, minH6: -12, maxManipulation: 66 });
  }
  return false;
}

function buildSniperModeDisplay(qualifiedRows, mode, scanState, options = {}) {
  const limit = Number.parseInt(options.limit || 6, 10);
  const safeMode = String(mode || "safe");
  const sorter = safeMode === "pumpsnipe"
    ? comparePumpSnipeScores
    : (a, b) => compareSniperScoresForMode(safeMode, a, b);
  const modeRows = qualifiedRows
    .filter((item) => !isKnownBelowExitFloor(item))
    .filter((item) => isModeRelevantSniperPick(item, safeMode))
    .sort(sorter);
  const strictMints = new Set(modeRows.map((item) => item.tokenMint));
  const looseModeRows = qualifiedRows
    .filter((item) => !isKnownBelowExitFloor(item))
    .filter((item) => !strictMints.has(item.tokenMint))
    .filter((item) => isLooseModeRelevantSniperPick(item, safeMode))
    .sort(sorter);
  const looseMints = new Set([...strictMints, ...looseModeRows.map((item) => item.tokenMint)]);
  const fallbackRows = qualifiedRows
    .filter((item) => !isKnownBelowExitFloor(item))
    .filter((item) => !looseMints.has(item.tokenMint))
    .filter((item) => isModeFallbackSniperPick(item, safeMode))
    .sort(sorter);
  const fallbackMints = new Set([...looseMints, ...fallbackRows.map((item) => item.tokenMint)]);
  const remainingRows = safeMode === "moonshot"
    ? []
    : qualifiedRows
      .filter((item) => !isKnownBelowExitFloor(item))
      .filter((item) => !fallbackMints.has(item.tokenMint))
      .sort(sorter);
  const displayRows = uniqueSniperScoreRows([
    ...modeRows,
    ...looseModeRows,
    ...fallbackRows,
    ...remainingRows
  ]).sort(sorter);

  return {
    modeRows,
    looseModeRows,
    fallbackRows,
    displayRows,
    rows: selectRotatingSniperRows(displayRows, scanState, limit)
  };
}

function isModeFallbackSniperPick(item, mode) {
  const flags = new Set(item.riskFlags || []);
  const clean = (options = {}) => isCleanTrendCandidate(item, options)
    && !flags.has("hard dump")
    && !flags.has("sell pressure");

  if (mode === "moonshot") {
    return item.marketCap >= 1_000
      && item.marketCap <= 80_000
      && item.liquidityUsd >= 100
      && item.scalpScore >= 1
      && (item.volume5m >= 5 || item.volumeH1 >= 50)
      && item.m5 >= -30
      && item.h1 >= -40
      && clean({ allowDumping: true, minM5: -30, minH1: -40, minH6: -55, maxManipulation: 92 });
  }
  if (mode === "pumpsnipe") {
    return item.marketCap >= 400
      && item.marketCap <= 260_000
      && item.liquidityUsd >= 350
      && item.scalpScore >= 1
      && (item.volume5m >= 40 || item.volumeH1 >= 350)
      && item.m5 >= -30
      && clean({ allowDumping: true, minM5: -30, minH1: -35, minH6: -45, maxManipulation: 94 });
  }
  if (mode === "fast") {
    return item.scalpScore >= 1
      && (item.volume5m >= 100 || item.volumeH1 >= 1_000)
      && item.buyPressure >= 0.9
      && item.m5 >= -14
      && clean({ allowDumping: true, minM5: -14, minH1: -16, minH6: -24, maxManipulation: 82 });
  }
  if (mode === "smart") {
    return item.buyPressure >= 0.95
      && item.liquidityUsd >= 750
      && (item.volume5m >= 50 || item.volumeH1 >= 750)
      && item.m5 <= 45
      && clean({ minM5: -12, minH1: -12, minH6: -20, maxManipulation: 76 });
  }
  if (mode === "safe") {
    return item.liquidityUsd >= 3_500
      && item.rugRisk <= 66
      && item.exitRisk <= 78
      && (item.volume5m >= 75 || item.volumeH1 >= 1_000)
      && item.buyPressure >= 0.9
      && clean({ minM5: -10, minH1: -10, minH6: -16, maxManipulation: 72 });
  }
  if (mode === "long") {
    return item.h1 >= -8
      && item.h6 >= -14
      && item.h24 >= -18
      && item.liquidityUsd >= 1_000
      && item.volumeH1 >= 750
      && clean({ minM5: -14, minH1: -10, minH6: -16, maxManipulation: 72 });
  }
  if (mode === "meme" || mode === "ai") {
    return item.narrative > 0
      && item.scalpScore >= 1
      && (item.volume5m >= 40 || item.volumeH1 >= 500)
      && clean({ allowDumping: true, minM5: -14, minH1: -16, minH6: -26, maxManipulation: 84 });
  }
  return false;
}

function rotateItems(items, offset) {
  if (!Array.isArray(items) || items.length <= 1) return items || [];
  const start = Math.abs(Number(offset) || 0) % items.length;
  return [...items.slice(start), ...items.slice(0, start)];
}

function buyPressureRatio(buys, sells) {
  const buyCount = Math.max(0, Number(buys) || 0);
  const sellCount = Math.max(0, Number(sells) || 0);
  if (buyCount === 0 && sellCount === 0) return 1;
  return (buyCount + 1) / (sellCount + 1);
}

function sniperScalpSetup({ m5, h1, h6, volume5m, volumeH1, buyPressure, liquidityUsd, sells5m, sellsH1 }) {
  const hasActiveVolume = volume5m >= 750 || volumeH1 >= 5_000;
  const hasGoodLiquidity = liquidityUsd >= 5_000;
  const buyersPresent = buyPressure >= 1.08;
  const notTooMuchShortSelling = sells5m < 8 || buyPressure >= 1.2;

  if (!hasActiveVolume || !hasGoodLiquidity) {
    return { label: "Low-volume watch", score: 0 };
  }

  if (m5 >= 4 && h1 >= 6 && buyersPresent) {
    return { label: "Breakout scalp", score: 5 };
  }

  if (m5 >= -2 && h1 >= 8 && buyersPresent && notTooMuchShortSelling) {
    return { label: "Uptrend scalp", score: 4 };
  }

  if (m5 >= -12 && m5 <= 2 && (h1 >= 15 || h6 >= 20) && buyPressure >= 1.18 && volumeH1 >= 7_500) {
    return { label: "Cool-off bounce", score: 4 };
  }

  if (m5 >= 0 && h1 >= 0 && volumeH1 >= 10_000 && buyPressure >= 1) {
    return { label: "Volume building", score: 3 };
  }

  if (h1 >= 10 && volumeH1 >= 5_000 && buyPressure >= 0.95 && sellsH1 < 30) {
    return { label: "Needs confirmation", score: 2 };
  }

  return { label: "Slow/unclear", score: 1 };
}

function pumpSnipeScalpSetup({ m5, h1, h6, volume5m, volumeH1, buyPressure, liquidityUsd, sells5m, sellsH1 }) {
  const hasEarlyVolume = volume5m >= 75 || volumeH1 >= 750;
  const hasTradableLiquidity = liquidityUsd >= 500;
  const buyersPresent = buyPressure >= 0.85;
  const shortSellsControlled = sells5m < 12 || buyPressure >= 1;

  if (!hasEarlyVolume || !hasTradableLiquidity) {
    return { label: "Early watch", score: 1 };
  }

  if (m5 >= 6 && buyersPresent && volume5m >= 150) {
    return { label: "Fresh pump breakout", score: 5 };
  }

  if (m5 >= -4 && h1 >= 4 && buyersPresent && shortSellsControlled) {
    return { label: "Early uptrend scalp", score: 4 };
  }

  if (m5 >= -10 && h1 >= 8 && buyPressure >= 0.95 && volumeH1 >= 1_500) {
    return { label: "Early cool-off bounce", score: 4 };
  }

  if (m5 >= -8 && volumeH1 >= 1_000 && buyPressure >= 0.8) {
    return { label: "Pump volume building", score: 3 };
  }

  if (h1 >= -5 && volumeH1 >= 750 && buyPressure >= 0.75 && sellsH1 < 40) {
    return { label: "Early confirmation", score: 2 };
  }

  return { label: "Early watch", score: 1 };
}

function sniperVolumePenalty({ volume5m, volumeH1, liquidityUsd }) {
  let penalty = 0;
  if (volume5m < 250 && volumeH1 < 2_000) penalty += 18;
  else if (volume5m < 750 && volumeH1 < 5_000) penalty += 10;
  if (liquidityUsd >= 25_000 && volumeH1 < 2_500) penalty += 6;
  return penalty;
}

function sniperDumpPenalty({ m5, h1, h6, h24 }) {
  let penalty = 0;
  if (m5 < -10) penalty += Math.min(18, Math.abs(m5) * 0.9);
  if (h1 < -8) penalty += Math.min(24, Math.abs(h1) * 0.9);
  if (h6 < -15) penalty += Math.min(20, Math.abs(h6) * 0.45);
  if (h24 < -35) penalty += 10;
  return Math.round(penalty);
}

function sniperLiquidityPenalty({ marketCap, liquidityUsd }) {
  let penalty = 0;
  if (liquidityUsd <= 0) penalty += 18;
  else if (liquidityUsd < 5_000) penalty += 18;
  else if (liquidityUsd < 10_000) penalty += 10;

  if (marketCap > 0 && liquidityUsd > 0) {
    const liqToMc = liquidityUsd / marketCap;
    if (liqToMc < 0.015) penalty += 18;
    else if (liqToMc < 0.03) penalty += 10;
  }

  return Math.round(penalty);
}

function sniperSellPressurePenalty({ buys5m, sells5m, buysH1, sellsH1 }) {
  const shortPressure = buyPressureRatio(buys5m, sells5m);
  const hourlyPressure = buyPressureRatio(buysH1, sellsH1);
  let penalty = 0;
  if (sells5m >= 5 && shortPressure < 0.75) penalty += 18;
  else if (sells5m >= 3 && shortPressure < 0.95) penalty += 8;
  if (sellsH1 >= 10 && hourlyPressure < 0.8) penalty += 14;
  else if (sellsH1 >= 5 && hourlyPressure < 1) penalty += 6;
  return penalty;
}

function sniperRiskFlags(data) {
  const flags = [];
  if (data.namePenalty > 0) flags.push("bad name");
  if (data.m5 < -18 || data.h1 < -20 || data.h6 < -35) flags.push("hard dump");
  else if (data.m5 < -10 || data.h1 < -8 || data.h6 < -15) flags.push("dumping");
  if (data.volume5m < 250 && data.volumeH1 < 2_000) flags.push("low volume");
  if (data.liquidityUsd > 0 && data.liquidityUsd < 10_000) flags.push("thin liquidity");
  if (data.marketCap > 0 && data.liquidityUsd > 0 && data.liquidityUsd / data.marketCap < 0.03) flags.push("weak liquidity");
  if ((data.sells5m >= 5 && buyPressureRatio(data.buys5m, data.sells5m) < 0.9)
    || (data.sellsH1 >= 10 && buyPressureRatio(data.buysH1, data.sellsH1) < 0.85)) {
    flags.push("sell pressure");
  }
  return flags;
}

async function scoreSniperCandidate(candidate, settings) {
  const tokenMint = candidate.tokenMint;
  const metadata = candidate.metadata || await getDexTokenMetadata(tokenMint);
  const text = `${metadata.symbol || ""} ${metadata.name || ""} ${metadata.description || ""}`.toLowerCase();
  const marketCap = Number(metadata.marketCap || metadata.fdv || 0);
  const liquidityUsd = Number(metadata.liquidityUsd || 0);
  const volume5m = Number(metadata.volume?.m5 || 0);
  const volumeH1 = Number(metadata.volume?.h1 || 0);
  const m5 = Number(metadata.priceChange?.m5 || 0);
  const h24 = Number(metadata.priceChange?.h24 || 0);
  const h6 = Number(metadata.priceChange?.h6 || 0);
  const h1 = Number(metadata.priceChange?.h1 || 0);
  const tx5m = metadata.txns?.m5 || {};
  const txH1 = metadata.txns?.h1 || {};
  const buys5m = Number(tx5m.buys || 0);
  const sells5m = Number(tx5m.sells || 0);
  const buysH1 = Number(txH1.buys || 0);
  const sellsH1 = Number(txH1.sells || 0);
  const buyPressure = buyPressureRatio(buys5m + buysH1, sells5m + sellsH1);
  const pairAgeSeconds = metadata.pairCreatedAt ? Math.max(0, Math.floor((Date.now() - Number(metadata.pairCreatedAt)) / 1000)) : null;
  const pairAgeMinutes = pairAgeSeconds === null ? null : Math.floor(pairAgeSeconds / 60);
  const hasImage = Boolean(metadata.imageUrl);
  const hasMeta = Boolean(metadata.symbol && metadata.name);
  const narrative = sniperNarrativeScore(text, settings.mode);
  const modeRelevance = sniperModeRelevance(settings.mode, {
    tokenMint,
    marketCap,
    liquidityUsd,
    m5,
    h1,
    h6,
    h24,
    text,
    buyPressure,
    volume5m,
    volumeH1,
    narrative,
    pairAgeMinutes
  });
  const scalp = settings.mode === "pumpsnipe"
    ? pumpSnipeScalpSetup({ m5, h1, h6, volume5m, volumeH1, buyPressure, liquidityUsd, sells5m, sellsH1 })
    : sniperScalpSetup({ m5, h1, h6, volume5m, volumeH1, buyPressure, liquidityUsd, sells5m, sellsH1 });
  const liquiditySignal = liquidityUsd > 0
    ? Math.min(22, Math.log10(Math.max(10, liquidityUsd)) * 4)
    : marketCap > 0 ? Math.min(12, Math.log10(Math.max(10, marketCap)) * 2) : 2;
  const volumeSignal = Math.min(14, Math.log10(Math.max(1, volumeH1 + volume5m)) * 2.5);
  const buyPressureSignal = clamp(Math.round((buyPressure - 1) * 10), -8, 10);
  const dumpPenalty = sniperDumpPenalty({ m5, h1, h6, h24 });
  const liquidityPenalty = sniperLiquidityPenalty({ marketCap, liquidityUsd });
  const sellPressurePenalty = sniperSellPressurePenalty({ buys5m, sells5m, buysH1, sellsH1 });
  const volumePenalty = sniperVolumePenalty({ volume5m, volumeH1, liquidityUsd });
  const namePenalty = sniperRiskPenalty(text);
  const momentumSignal = Math.max(0, Math.min(25, (m5 * 0.8) + (h1 * 0.35) + (h6 * 0.1) + (h24 * 0.02)));
  const metadataSignal = (hasMeta ? 12 : 2) + (hasImage ? 8 : 0);
  const modeBonus = sniperModeBonus(settings.mode, { tokenMint, marketCap, liquidityUsd, m5, h1, h6, h24, text, buyPressure, volume5m, volumeH1, narrative, pairAgeMinutes });
  const riskTotal = namePenalty + dumpPenalty + liquidityPenalty + sellPressurePenalty + volumePenalty;
  const score = clamp(Math.round(22 + liquiditySignal + volumeSignal + momentumSignal + metadataSignal + narrative + modeBonus + buyPressureSignal + (scalp.score * 5) - riskTotal), 1, 100);
  const rugRisk = clamp(Math.round(70 - metadataSignal - Math.min(18, liquiditySignal) - Math.min(10, volumeSignal) + namePenalty + liquidityPenalty + sellPressurePenalty + volumePenalty + Math.round(dumpPenalty * 0.65)), 1, 100);
  const exitRisk = clamp(Math.round(58 - Math.min(18, momentumSignal) - Math.max(0, buyPressureSignal) - (scalp.score * 3) + dumpPenalty + sellPressurePenalty + volumePenalty + (marketCap > 0 && marketCap < 20_000 ? 12 : 0)), 1, 100);
  const manipulationScore = clamp(Math.round(28 + (liquidityPenalty * 0.8) + (Math.abs(m5) > 60 ? 12 : 0) + (Math.abs(h1) > 100 ? 18 : 0) + sellPressurePenalty + (pairAgeMinutes !== null && pairAgeMinutes < 10 ? 10 : 0) - (hasMeta ? 6 : 0)), 1, 100);
  const riskFlags = sniperRiskFlags({ m5, h1, h6, h24, liquidityUsd, marketCap, volume5m, volumeH1, buys5m, sells5m, buysH1, sellsH1, namePenalty });
  const category = riskFlags.includes("hard dump") || rugRisk > settings.maxRisk + 26
    ? "Avoid"
    : score >= 82 && rugRisk <= settings.maxRisk
    ? "High Conviction"
    : score >= settings.minScore && momentumSignal >= 10
      ? "Momentum"
      : score >= settings.minScore
        ? "Stealth Accumulation"
        : "Avoid";
  const isPump = isPumpStyleToken({
    tokenMint,
    symbol: metadata.symbol,
    name: metadata.name,
    source: metadata.source || metadata.profileSource
  });

  return {
    tokenMint,
    symbol: metadata.symbol,
    name: metadata.name,
    imageUrl: metadata.imageUrl || "",
    isPump,
    pumpUrl: isPump ? pumpFunUrl(tokenMint) : "",
    score,
    category,
    rugRisk,
    exitRisk,
    manipulationScore,
    liquidityUsd,
    volume5m,
    volumeH1,
    buyPressure,
    scalpSetup: scalp.label,
    scalpScore: scalp.score,
    modeRelevance,
    marketCap,
    m5,
    h1,
    h6,
    h24,
    narrative,
    pairCreatedAt: metadata.pairCreatedAt || null,
    pairAgeSeconds,
    pairAgeMinutes,
    riskFlags,
    momentum: scalp.score >= 4 ? "Scalp-ready" : momentumSignal >= 18 ? "Strong" : momentumSignal >= 8 ? "Building" : "Weak",
    smartMoney: score >= 80 ? "High" : score >= 65 ? "Medium" : "Low",
    reasons: sniperReasons({ hasImage, hasMeta, marketCap, liquidityUsd, volume5m, volumeH1, m5, h1, h6, h24, narrative, buyPressure, scalpSetup: scalp.label, riskFlags, settings })
  };
}

function formatSniperPickHtml(score, index = null) {
  const rank = Number.isInteger(index) ? `${index + 1}. ` : "";
  const label = escapeHtml(score.symbol || score.name || shortMint(score.tokenMint));
  const reasons = score.reasons?.length ? escapeHtml(score.reasons.join(" | ")) : "highest available quality signals";
  return [
    `<b>${rank}${escapeHtml(score.category)}: ${label}</b>`,
    `Score: <b>${score.score}/100</b> | Momentum: ${escapeHtml(score.momentum)} | Rug: ${score.rugRisk}/100 | Exit: ${score.exitRisk}/100`,
    `Setup: <b>${escapeHtml(score.scalpSetup || "Scalp watch")}</b> | 5m: ${formatPercentCompact(score.m5)} | 1h: ${formatPercentCompact(score.h1)}`,
    `MC: ${formatUsdCompact(score.marketCap || 0) || "$0"} | Liq: ${formatUsdCompact(score.liquidityUsd || 0) || "$0"} | Vol 5m/1h: ${formatUsdCompact(score.volume5m || 0) || "$0"} / ${formatUsdCompact(score.volumeH1 || 0) || "$0"}`,
    `Flow: ${formatBuyPressure(score.buyPressure)} | Mode fit: ${score.modeRelevance || 0}/5`,
    `Smart: ${escapeHtml(score.smartMoney)} | Manipulation: ${score.manipulationScore}/100${score.riskFlags?.length ? ` | Flags: ${escapeHtml(score.riskFlags.join(", "))}` : ""}`,
    `CA: <code>${score.tokenMint}</code>`,
    `Dex: <a href="${dexScreenerUrl(score.tokenMint)}">Open chart</a>`,
    `Why: ${reasons}`
  ].join("\n");
}

function sniperReasons(data) {
  const reasons = [];
  if (data.scalpSetup) reasons.push(data.scalpSetup);
  if (data.hasMeta) reasons.push("metadata live");
  if (data.liquidityUsd > 0) reasons.push(`liq ${formatUsdCompact(data.liquidityUsd)}`);
  if (data.volume5m > 0) reasons.push(`5m vol ${formatUsdCompact(data.volume5m)}`);
  if (data.volumeH1 > 0 && reasons.length < 4) reasons.push(`1h vol ${formatUsdCompact(data.volumeH1)}`);
  if (data.buyPressure > 1.15) reasons.push("buyers leading");
  if (data.m5 > 0) reasons.push(`5m +${data.m5.toFixed(1)}%`);
  else if (data.h1 > 0) reasons.push(`1h +${data.h1.toFixed(1)}%`);
  if (data.narrative > 0) reasons.push(`${sniperModeLabel(data.settings.mode)} narrative match`);
  for (const flag of data.riskFlags || []) {
    if (reasons.length >= 4) break;
    reasons.push(`watch ${flag}`);
  }
  return reasons.slice(0, 4);
}

function sniperModeDefaults(mode) {
  const defaults = {
    safe: { mode: "safe", minScore: 74, maxRisk: 40 },
    smart: { mode: "smart", minScore: 74, maxRisk: 48 },
    fast: { mode: "fast", minScore: 68, maxRisk: 58 },
    moonshot: { mode: "moonshot", minScore: 56, maxRisk: 70 },
    meme: { mode: "meme", minScore: 66, maxRisk: 58 },
    ai: { mode: "ai", minScore: 66, maxRisk: 58 },
    long: { mode: "long", minScore: 72, maxRisk: 48 },
    autosnipe: { mode: "autosnipe", minScore: 82, maxRisk: 38 },
    pumpsnipe: { mode: "pumpsnipe", minScore: 48, maxRisk: 78 }
  };
  return defaults[mode] || defaults.safe;
}

function sniperModeLabel(mode) {
  const labels = {
    safe: "Safe Picks",
    smart: "Smart Accumulation",
    fast: "Fast Movers",
    moonshot: "Low MC Picks",
    meme: "Narratives",
    ai: "AI Narrative",
    long: "Long Term",
    autosnipe: "AutoSnipe",
    pumpsnipe: "PumpSnipe"
  };
  return labels[mode] || labels.safe;
}

function sniperNarrativeScore(text, mode) {
  const keywords = {
    ai: ["ai", "agent", "gpt", "robot", "neural", "compute", "agi"],
    meme: ["dog", "cat", "frog", "pepe", "bonk", "wif", "meme", "cto"],
    moonshot: ["moon", "rocket", "pump", "gem", "100x"],
    fast: ["pump", "moon", "send", "ape"],
    pumpsnipe: ["pump", "moon", "send", "ape", "cto", "meme"],
    long: ["utility", "ai", "agent", "game", "defi", "protocol", "community"]
  };
  const list = keywords[mode] || [];
  return list.some((word) => text.includes(word)) ? 10 : 0;
}

function sniperModeBonus(mode, data) {
  const relevance = sniperModeRelevance(mode, data);
  if (mode === "safe") return relevance >= 3 ? 8 : 0;
  if (mode === "smart") return relevance >= 3 ? 10 : 0;
  if (mode === "fast") return relevance >= 3 ? 11 : 0;
  if (mode === "autosnipe") return relevance >= 4 ? 13 : relevance >= 3 ? 6 : 0;
  if (mode === "pumpsnipe") return relevance >= 4 ? 15 : relevance >= 3 ? 9 : relevance >= 2 ? 4 : 0;
  if (mode === "moonshot") return relevance >= 3 ? 8 : 0;
  if (mode === "long") return relevance >= 4 ? 10 : relevance >= 3 ? 5 : 0;
  if (mode === "meme" || mode === "ai") return data.narrative > 0 ? 12 : 0;
  return 0;
}

function sniperModeRelevance(mode, data) {
  if (mode === "ai" || mode === "meme") return data.narrative > 0 ? 5 : 0;
  if (mode === "safe") {
    return Number(data.liquidityUsd >= 10_000)
      + Number(data.marketCap >= 50_000)
      + Number(data.buyPressure >= 1)
      + Number(data.m5 >= -4 && data.h1 >= 0)
      + Number(data.volumeH1 >= 5_000 || data.volume5m >= 750);
  }
  if (mode === "smart") {
    return Number(data.buyPressure >= 1.05)
      + Number(data.volumeH1 >= 3_500 || data.volume5m >= 400)
      + Number(data.m5 >= -6 && data.m5 <= 18)
      + Number(data.h1 >= -4 && data.h6 >= -10)
      + Number(data.liquidityUsd >= 2_500);
  }
  if (mode === "fast") {
    return Number(data.m5 > 2 || data.h1 > 8)
      + Number(data.volumeH1 >= 5_000 || data.volume5m >= 750)
      + Number(data.buyPressure >= 1.05)
      + Number(data.liquidityUsd >= 5_000)
      + Number(data.h6 >= -5 && data.m5 >= -8);
  }
  if (mode === "autosnipe") {
    return Number(data.m5 >= 0 && data.h1 >= 4)
      + Number(data.volumeH1 >= 10_000 || data.volume5m >= 1_000)
      + Number(data.buyPressure >= 1.15)
      + Number(data.liquidityUsd >= 8_000)
      + Number(data.h6 >= -5 && data.m5 >= -6);
  }
  if (mode === "pumpsnipe") {
    const age = Number(data.pairAgeMinutes);
    const isEarly = !Number.isFinite(age) || age <= 240;
    return Number(isEarly)
      + Number(data.marketCap > 0 && data.marketCap <= 180_000)
      + Number(data.liquidityUsd >= 1_000)
      + Number(data.volume5m >= 100 || data.volumeH1 >= 1_000)
      + Number(data.buyPressure >= 0.85)
      + Number(data.m5 >= -15 && data.h1 >= -20);
  }
  if (mode === "moonshot") {
    return Number(data.marketCap >= 4_000 && data.marketCap <= 40_000)
      + Number(data.liquidityUsd >= 400)
      + Number(data.buyPressure >= 0.85)
      + Number(data.volumeH1 >= 500 || data.volume5m >= 50)
      + Number(data.h1 >= -12 && data.m5 >= -12);
  }
  if (mode === "long") {
    return Number(data.marketCap >= 30_000 && data.marketCap <= 2_500_000)
      + Number(data.liquidityUsd >= 5_000)
      + Number(data.buyPressure >= 1)
      + Number(data.h1 >= -4 && data.h6 >= -8)
      + Number(data.h24 >= -12);
  }
  return 1;
}

function sniperRiskPenalty(text) {
  const bad = ["test", "rug", "scam", "honeypot", "copy", "fake"];
  return bad.some((word) => text.includes(word)) ? 18 : 0;
}

function applySniperExitPreset(session, presetText) {
  const preset = String(presetText || "").trim().toLowerCase();
  const presets = {
    fast: { sellDelaySeconds: 180, sellPercent: 100, takeProfitPct: 35, stopLossPct: 10, label: "Fast Scalp" },
    balanced: { sellDelaySeconds: 900, sellPercent: 80, takeProfitPct: 50, stopLossPct: 15, label: "Balanced" },
    moonbag: { sellDelaySeconds: 1800, sellPercent: 60, takeProfitPct: 100, stopLossPct: 25, label: "Moonbag" },
    safe: { sellDelaySeconds: 600, sellPercent: 100, takeProfitPct: 20, stopLossPct: 8, label: "Safe" },
    long: { sellDelaySeconds: 172800, sellPercent: 100, takeProfitPct: 75, stopLossPct: 20, label: "Long Term" }
  };
  const selected = presets[preset];
  if (!selected) {
    throw new Error("Choose Fast Scalp, Balanced, Moonbag, Safe, or Long Term.");
  }
  Object.assign(session.data, selected, {
    sellDelayMinutes: selected.sellDelaySeconds / 60,
    triggerSellPercent: 100,
    loopCount: 1,
    loopDelaySeconds: 0,
    exitPreset: selected.label,
    allowRepeat: false,
    takeProfitMode: "single",
    stopLossMode: "single",
    walletTakeProfitTargets: null,
    walletStopLossTargets: null
  });
}

