function howToPageKeyboard(openAction) {
  const rows = [];
  if (openAction) {
    rows.push([{ text: "Open This Menu", callback_data: openAction }]);
  }
  rows.push(
    [{ text: "Back to How To", callback_data: "howto_menu" }],
    [{ text: "Main Menu", callback_data: "main_menu" }]
  );
  return rows;
}

