async function handlePfpCallback(query, userId) {
  const data = String(query?.data || "");
  if (!data.startsWith("pfp:")) return false;
  const chatId = query.message?.chat?.id, messageId = query.message?.message_id;
  const ack = (t, alert) => telegram("answerCallbackQuery", { callback_query_id: query.id, ...(t ? { text: t, show_alert: Boolean(alert) } : {}) }).catch(() => {});
  // 🧟 SlimeWire PFP — roll one of OUR pre-made slime-degen characters (no photo needed).
  const mChar = data.match(/^pfp:char:(\d+)$/);
  if (mChar) {
    if (String(userId) !== mChar[1]) { await ack("Send /pfp to make your own 🐸", true); return true; }
    await ack("🧟 Summoning a SlimeWire character…");
    try {
      const r = await makeCharacterPfp({ frameDir: PFP_FRAME_DIR, seed: Math.floor(Math.random() * 1e9) });
      if (!r) { await telegram("sendMessage", { chat_id: chatId, text: "No characters ready yet — try the site: " + pfpWebUrl() }).catch(() => {}); return true; }
      await sendPhoto(chatId, "slimewire-pfp.png", r.png, "🧟 <b>Your SlimeWire PFP</b> — save it &amp; set it as your profile pic. Tap 🎲 for another.", pfpResultKeyboard(userId, "char"), "HTML");
    } catch { await ack("Couldn't roll — try again.", true); }
    return true;
  }
  // 🫠 Slime Your PFP — YOUR avatar composited with our backgrounds/rings/hats/props (Slime Studio).
  const mSlime = data.match(/^pfp:slime:(\d+)$/);
  if (mSlime) {
    if (String(userId) !== mSlime[1]) { await ack("Send /pfp to make your own 🐸", true); return true; }
    const avatar = await fetchTelegramAvatarBuffer(userId);
    if (!avatar) { await telegram("sendMessage", { chat_id: chatId, text: "I can't see your Telegram profile photo (private or none). Slime any pic on the site 👉 " + pfpWebUrl() }).catch(() => {}); await ack(); return true; }
    await ack("🫠 Sliming your pic…");
    try {
      const png = await makeSlimeStudioPfp({ sourceBuffer: avatar, frameDir: PFP_FRAME_DIR, seed: Math.floor(Math.random() * 1e9) });
      await sendPhoto(chatId, "slimewire-pfp.png", png, "🫠 <b>Slimed!</b> Tap 🎲 for a fresh look, or save this one.", pfpResultKeyboard(userId, "slime"), "HTML");
    } catch { await ack("Couldn't slime that — try again.", true); }
    return true;
  }
  // ✨ AI Slime — repaint the tapper's avatar into custom slime art (owner-gated, paid model).
  const mAi = data.match(/^pfp:ai:([a-z]+):(\d+)$/);
  if (mAi) {
    const styleId = mAi[1], ownerId = mAi[2];
    if (String(userId) !== ownerId) { await ack("Send /pfp to make your own 🐸", true); return true; }
    if (!aiPfpConfigured()) { await ack("AI Slime isn't enabled yet.", true); return true; }
    const avatar = await fetchTelegramAvatarBuffer(userId);
    if (!avatar) { await ack("Couldn't load your avatar.", true); return true; }
    await ack("✨ Painting you in slime… ~10s");
    try {
      const png = await sharp(avatar).png().toBuffer();
      const ai = await aiSlimePfp({ imageDataUrl: `data:image/png;base64,${png.toString("base64")}`, styleId });
      if (!ai) { await telegram("sendMessage", { chat_id: chatId, text: "AI Slime isn't enabled yet." }).catch(() => {}); return true; }
      const branded = await brandAiPfp(ai).catch(() => ai);
      await sendPhoto(chatId, "slimewire-ai-pfp.png", branded, "✨ <b>Your AI SlimeWire PFP</b> — save it &amp; set it as your profile pic.", await pfpFrameButtons(null, userId), "HTML");
    } catch (e) { await telegram("sendMessage", { chat_id: chatId, text: `AI Slime failed: ${String(e?.message || "try again").slice(0, 120)}` }).catch(() => {}); }
    return true;
  }
  // 🎲 Slime Studio — free random combo from the Higgs library, on the tapper's avatar.
  const mSt = data.match(/^pfp:st:(\d+)$/);
  if (mSt) {
    const ownerId = mSt[1];
    if (String(userId) !== ownerId) { await ack("Send /pfp to make your own 🐸", true); return true; }
    const avatar = await fetchTelegramAvatarBuffer(userId);
    if (!avatar) { await ack("Couldn't load your avatar.", true); return true; }
    await ack("🎲 Rolling a slime look…");
    try {
      const png = await makeSlimeStudioPfp({ sourceBuffer: avatar, frameDir: PFP_FRAME_DIR, seed: Math.floor(Math.random() * 1e9) });
      await sendPhoto(chatId, "slimewire-pfp.png", png, "🎨 <b>Slime Studio</b> — tap 🎲 again for a fresh look, or save this one.", await pfpFrameButtons(null, userId), "HTML");
    } catch { await ack("Couldn't roll that — try again.", true); }
    return true;
  }
  const m = data.match(/^pfp:f:([a-z]+):(\d+)$/);
  if (!m) { await ack(); return true; }
  const frameId = m[1], ownerId = m[2];
  if (String(userId) !== ownerId) { await ack("This is someone else's PFP — send /pfp to make your own 🐸", true); return true; }
  const avatar = await fetchTelegramAvatarBuffer(userId);
  if (!avatar) { await ack("Couldn't load your avatar — make one on the site.", true); return true; }
  try {
    const png = await makeSlimewirePfp({ sourceBuffer: avatar, frameId, frameDir: PFP_FRAME_DIR });
    await editMessagePhotoBuffer(chatId, messageId, png, PFP_TG_CAPTION, await pfpFrameButtons(frameId, userId));
    await ack("Styled ✨");
  } catch { await ack("Couldn't apply that style — try another.", true); }
  return true;
}

function providerErrorValue(value) {
  if (!value) return "";
  if (typeof value === "string") return value;
  if (Array.isArray(value)) {
    return value.map(providerErrorValue).filter(Boolean).join("; ");
  }
  if (typeof value === "object") {
    const nested = [
      value.message,
      value.error,
      value.description,
      value.reason,
      value.detail,
      value.details,
      value.errors,
      value.result?.error
    ].map(providerErrorValue).find(Boolean);
    if (nested) return nested;

    try {
      return JSON.stringify(value).replace(/\s+/g, " ").slice(0, 500);
    } catch {
      return "";
    }
  }
  return String(value);
}

function fetchJsonErrorMessage(data, text, status) {
  const message = providerErrorValue(data);
  if (message) return message.slice(0, 500);
  const fallback = String(text || "").replace(/\s+/g, " ").trim();
  if (/^<!doctype html|<html[\s>]/i.test(fallback)) {
    return `HTTP ${status}: endpoint returned an HTML page instead of API data. Check the API URL, provider access, and required API key/JWT.`;
  }
  if (fallback) return fallback.slice(0, 500);
  return `HTTP ${status}`;
}

async function fetchJson(url, init = {}) {
  const { timeoutMs, ...fetchInit } = init || {};
  let timeout = null;
  let controller = null;

  if (Number.isFinite(Number(timeoutMs)) && Number(timeoutMs) > 0 && !fetchInit.signal) {
    controller = new AbortController();
    fetchInit.signal = controller.signal;
    timeout = setTimeout(() => controller.abort(), Number(timeoutMs));
  }

  let response;
  try {
    response = await fetch(url, fetchInit);
  } catch (error) {
    if (error?.name === "AbortError") {
      throw new Error(`Request timed out after ${timeoutMs}ms`);
    }
    throw error;
  } finally {
    if (timeout) clearTimeout(timeout);
  }

  const text = await response.text();
  let data = {};

  if (text) {
    try {
      data = JSON.parse(text);
    } catch {
      data = { error: text.slice(0, 300) };
    }
  }

  if (!response.ok) {
    const error = new Error(fetchJsonErrorMessage(data, text, response.status));
    error.status = response.status;
    error.retryAfter = response.headers.get("retry-after");
    error.responseBody = String(text || "").slice(0, 1000);
    error.providerData = data;
    throw error;
  }

  return data;
}

async function readWalletStore() {
  const store = await readJson(walletPath());
  if (!Array.isArray(store.wallets)) store.wallets = [];
  return store;
}

async function writeWalletStore(store) {
  await writeJsonFile(walletPath(), store);
}

// Atomic read-modify-write of the wallet store. The encrypted secret lives ONLY in this file, so a lost
// update (two concurrent creators each reading then writing → one set of new records dropped) can strand
// an already-funded wallet = unrecoverable SOL. withFileLock serializes the whole read→mutate→write so
// concurrent creates/imports/tags can't clobber each other. fn mutates `store` in place; return value is
// passed back to the caller. NEVER call another wallet-store mutator inside fn (same-file lock = deadlock).
async function mutateWalletStore(fn) {
  return withFileLock(walletPath(), async () => {
    const store = await readWalletStore();
    const result = await fn(store);
    await writeWalletStore(store);
    return result;
  });
}

async function readJson(filePath) {
  const fallback = defaultJsonForPath(filePath);
  let text = "";

  try {
    text = await fs.readFile(filePath, "utf8");
  } catch (error) {
    if (error?.code !== "ENOENT" || fallback === null) throw error;
    await writeJsonFile(filePath, fallback);
    return cloneJson(fallback);
  }

  if (!text.trim()) {
    if (fallback === null) {
      const error = new Error(`${path.basename(filePath)} is empty.`);
      error.statusCode = 500;
      throw error;
    }
    await writeJsonFile(filePath, fallback);
    return cloneJson(fallback);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    const wrapped = new Error(`${path.basename(filePath)} is not valid JSON. Use the backup/restore file if this data file was interrupted during deploy.`);
    wrapped.statusCode = 500;
    wrapped.cause = error;
    throw wrapped;
  }
}

async function writeJsonFile(filePath, value) {
  const tmpPath = `${filePath}.${process.pid}.${Date.now()}.${crypto.randomBytes(4).toString("hex")}.tmp`;
  try {
    await fs.writeFile(tmpPath, JSON.stringify(value, null, 2));
    await fs.rename(tmpPath, filePath);
  } catch (error) {
    await fs.unlink(tmpPath).catch(() => {});
    throw error;
  }
}

function defaultJsonForPath(filePath) {
  switch (path.basename(filePath)) {
    case "wallets.json":
      return { wallets: [] };
    case "swamp-leaderboard.json":
      return { scores: [] };
    case "swamp-receipts.json":
      return { receipts: [] };
    case "community-raids.json":
      return { raids: [] };
    case "raid-posts.json":
      return { posts: [] };
    case "raid-tg.json":
      return { cards: {} };
    case "presales.json":
      return { presales: [] };
    case "swamp-decks.json":
      return { decks: [] };
    case "audit-log.json":
      return { entries: [] };
    case "state.json":
      return { paused: false };
    case "trade-plans.json":
    case "dca-plans.json":
      return { plans: [] };
    case "web-exit-guards.json":
      return { guards: [] };
    case "tpsl-worker-state.json":
      return defaultTpSlWorkerState();
    case "sniper-settings.json":
      return { users: {} };
    case "ogre-autopilot.json":
      return { configs: {} };
    case "trade-history.json":
      return { trades: [] };
    case "holder-rewards.json":
      return { seen: {} };
    case "partner-rewards.json":
      return { programs: {}, tokenIndex: {}, receipts: [], processedFees: {} };
    case "web-auth.json":
      return { codes: [], sessions: [], profiles: {}, browserTradeOrders: [], sessionWalletOrders: [] };
    case "lock-in-events.json":
      return { events: [] };
    case "telegram-groups.json":
      return { groups: {} };
    case "alpha-calls.json":
    case "call-board.json":
      return { calls: [] };
    case "telegram-links.json":
      return { links: {} };
    case "watch-alerts.json":
      return { snapshots: {} };
    case "watch-devs.json":
      return { watchers: {} };
    case "launch-hype.json":
      return { pages: {} };
    case "launch-milestones.json":
      return { tracked: {} };
    case "shield-receipts.json":
      return { receipts: [] };
    case "push-subscriptions.json":
      return { subs: {} };
    case "terminal-feed-events.json":
      return { events: [] };
    case "performance-events.json":
      return { events: [] };
    case "cache-events.json":
      return { events: [] };
    case "app-secret.json":
      return {};
    default:
      return null;
  }
}

function cloneJson(value) {
  return JSON.parse(JSON.stringify(value));
}

function objectRows(value) {
  return Array.isArray(value)
    ? value.filter((item) => item && typeof item === "object" && !Array.isArray(item))
    : [];
}

async function audit(action, details) {
  // Cap + lock: this is appended on EVERY money op. Unbounded growth meant an O(n) read+stringify+write
  // per call (write amplification that worsens forever) and concurrent appends could drop entries.
  await withFileLock(auditPath(), async () => {
    const auditLog = await readJson(auditPath());
    if (!Array.isArray(auditLog.entries)) auditLog.entries = [];
    auditLog.entries.push({
      timestamp: new Date().toISOString(),
      action,
      details
    });
    if (auditLog.entries.length > 2000) auditLog.entries = auditLog.entries.slice(-2000);
    await writeJsonFile(auditPath(), auditLog);
  });
}

async function readState() {
  return readJson(statePath());
}

async function readTradePlans() {
  const store = await readJson(tradePlansPath());
  store.plans = objectRows(store.plans);
  for (const plan of store.plans) {
    plan.wallets = objectRows(plan.wallets);
  }
  return store;
}

// --- Telegram group engagement: /look, /alpha, opt-in alerts ----------------------
// Groups are registered when the bot sees them; alerts stay OFF until a group admin
// runs /slimewire on. Per-chat cooldowns keep the bot useful instead of spammy.
const TG_LOOK_COOLDOWN_MS = 20_000;
const TG_ALPHA_COOLDOWN_MS = 10 * 60 * 1000;
const tgCommandCooldowns = new Map();
const pairLiteCache = new Map();
const rugcheckCache = new Map();
// Rugcheck free summary: named risk factors (LP providers, liquidity, holder
// concentration, authorities) from a second independent engine. Cached 10 min,
// never blocks - it enriches reads, it does not gate them.
// GoPlus token security (free, no key): third risk engine alongside SlimeShield
// and Rugcheck. Returns flag labels for authorities/hooks that bite buyers.
const goplusCache = new Map();
async function fetchGoPlusSolanaSecurity(mint) {
  const key = String(mint || "").trim();
  if (!key) return null;
  const cached = goplusCache.get(key);
  if (cached && Date.now() - cached.at < 10 * 60 * 1000) return cached.value;
  let value = null;
  try {
    const data = await fetchJson(`https://api.gopluslabs.io/api/v1/solana/token_security?contract_addresses=${encodeURIComponent(key)}`, {
      headers: { "Accept": "application/json" },
      timeoutMs: 3_000
    });
    const token = data?.result?.[key] || Object.values(data?.result || {})[0];
    if (token) {
      const flags = [];
      const flagIf = (field, label) => {
        const status = token?.[field]?.status ?? token?.[field];
        if (String(status) === "1" || status === true) flags.push(label);
      };
      flagIf("mintable", "mint authority active");
      flagIf("freezable", "freeze authority active");
      flagIf("closable", "closable token account");
      flagIf("balance_mutable_authority", "balances mutable");
      flagIf("non_transferable", "non-transferable");
      flagIf("transfer_hook", "transfer hook");
      flagIf("transfer_fee_upgradable", "upgradable transfer fee");
      value = { flags: flags.slice(0, 4) };
    }
  } catch {
    // free tier hiccups - reads simply omit the section
  }
  goplusCache.set(key, { at: Date.now(), value });
  if (goplusCache.size > 300) {
    const oldest = [...goplusCache.entries()].sort((a, b) => a[1].at - b[1].at)[0]?.[0];
    if (oldest) goplusCache.delete(oldest);
  }
  return value;
}

async function fetchRugcheckSummary(mint) {
  const key = String(mint || "").trim();
  if (!key) return null;
  const cached = rugcheckCache.get(key);
  if (cached && Date.now() - cached.at < 10 * 60 * 1000) return cached.value;
  let value = null;
  try {
    const data = await fetchJson(`https://api.rugcheck.xyz/v1/tokens/${encodeURIComponent(key)}/report/summary`, {
      headers: { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" },
      timeoutMs: 3_000
    });
    if (data && Array.isArray(data.risks)) {
      value = {
        score: Number(data.score_normalised ?? data.score) || null,
        risks: data.risks.slice(0, 4).map((risk) => ({
          name: String(risk?.name || "").slice(0, 60),
          level: String(risk?.level || "").slice(0, 10)
        })).filter((risk) => risk.name)
      };
    }
  } catch {
    // free tier rate limits happen - reads simply omit the section
  }
  rugcheckCache.set(key, { at: Date.now(), value });
  if (rugcheckCache.size > 300) {
    const oldest = [...rugcheckCache.entries()].sort((a, b) => a[1].at - b[1].at)[0]?.[0];
    if (oldest) rugcheckCache.delete(oldest);
  }
  return value;
}


// Fuller RugCheck report for the scan card: top-holder concentration, holder count,
// mint/freeze authorities, dev-sold (mirrors the OgreScanBot field mapping). Cached.
const rugcheckFullCache = new Map();
async function fetchRugcheckFull(mint) {
  const key = String(mint || "").trim();
  if (!key) return null;
  const cached = rugcheckFullCache.get(key);
  if (cached && Date.now() - cached.at < 10 * 60 * 1000) return cached.value;
  let value = null;
  try {
    const data = await fetchJson(`https://api.rugcheck.xyz/v1/tokens/${encodeURIComponent(key)}/report`, {
      headers: { "Accept": "application/json", "User-Agent": "solana-telegram-wallet-ops-bot" },
      timeoutMs: 6000
    });
    if (data && typeof data === "object") {
      const holders = Array.isArray(data.topHolders) ? data.topHolders : [];
      const lpWords = ["liquidity", "raydium", "meteora", "orca", "pump amm", "pool"];
      const clean = holders.filter((h) => h && typeof h === "object" && !lpWords.some((w) => JSON.stringify(h).toLowerCase().includes(w)));
      const use = clean.length ? clean : holders;
      const pctOf = (h) => Number(h?.pct ?? h?.percentage ?? h?.uiPct) || 0;
      const top = use.slice(0, 10).map(pctOf);
      const holderCount = Number(data.holderCount ?? data.totalHolders ?? data.numHolders ?? data.token?.holderCount ?? data.token?.totalHolders) || null;
      const risksText = JSON.stringify(data.risks || data).toLowerCase();
      const devSold = /dev (has )?not sold|creator (has )?not sold/.test(risksText) ? false
        : /(dev|developer|creator|deployer) (has )?sold/.test(risksText) ? true
        : (Array.isArray(data.risks) ? false : null);
      value = {
        score: Number(data.score_normalised ?? data.score) || null,
        riskCount: Array.isArray(data.risks) ? data.risks.length : null,
        topHolders: top.slice(0, 5),
        top10Pct: top.length ? top.reduce((a, b) => a + b, 0) : null,
        holderCount,
        mintAuthority: (data.mintAuthority || data.token?.mintAuthority) ? String(data.mintAuthority || data.token?.mintAuthority) : null,
        freezeAuthority: (data.freezeAuthority || data.token?.freezeAuthority) ? String(data.freezeAuthority || data.token?.freezeAuthority) : null,
        authoritiesKnown: true,   // RugCheck report loaded → its null authority = definitely revoked (not "unknown")
        devSold,
        risks: Array.isArray(data.risks) ? data.risks.slice(0, 4).map((r) => ({ name: String(r?.name || "").slice(0, 60) })).filter((r) => r.name) : []
      };
    }
  } catch {
    // free tier rate-limits — card omits the section gracefully
  }
  rugcheckFullCache.set(key, { at: Date.now(), value });
  if (rugcheckFullCache.size > 300) {
    const oldest = [...rugcheckFullCache.entries()].sort((a, b) => a[1].at - b[1].at)[0]?.[0];
    if (oldest) rugcheckFullCache.delete(oldest);
  }
  return value;
}

