      const list = (st && Array.isArray(st.oclhv)) ? st.oclhv : [];
      candles = list
        .map((k) => ({ t: Math.floor(Number(k.time) || 0), o: Number(k.open) || 0, h: Number(k.high) || 0, l: Number(k.low) || 0, c: Number(k.close) || 0, v: Number(k.volume) || 0 }))
        .filter((k) => k.t > 0 && k.c > 0)
        .sort((p, q) => p.t - q.t);
