async function handleXReplyCallback(query, userId) {
  const data = String(query?.data || "");
  if (!data.startsWith("xr:")) return false;
  const chatId = query.message?.chat?.id, messageId = query.message?.message_id;
  const ack = (t, a) => telegram("answerCallbackQuery", { callback_query_id: query.id, ...(t ? { text: t, show_alert: Boolean(a) } : {}) }).catch(() => {});
  if (!xReplyOwnerChat() || String(chatId) !== xReplyOwnerChat()) { await ack("Only the SlimeWire owner controls X replies.", true); return true; }
  const clearKb = (label) => telegram("editMessageReplyMarkup", { chat_id: chatId, message_id: messageId, reply_markup: { inline_keyboard: [[{ text: label, callback_data: "noop" }]] } }).catch(() => {});
  const mSkip = data.match(/^xr:skip:(\d+)$/), mPost = data.match(/^xr:post:(\d+)$/);
  const state = await readXReplyState();
  if (mSkip) {
    const q = state.queue[mSkip[1]];
    state.seen[mSkip[1]] = Date.now();
    if (q?.threadKey) state.threadReplies[q.threadKey] = Date.now();
    delete state.queue[mSkip[1]];
    await writeXReplyState(state); await clearKb("🗑 Skipped"); await ack("Skipped"); return true;
  }
  if (mPost) {
    const q = state.queue[mPost[1]];
    if (!q) { await ack("That draft expired — tag us again to re-scan.", true); return true; }
    const reply = await buildXReply(q.mint, q.intent || "scan").catch(() => null);
    if (!reply) { await ack("Couldn't rebuild the scan — try again.", true); return true; }
    const res = await xReply({ inReplyToId: q.anchorId || mPost[1], text: reply.text, mediaBuffer: reply.mediaBuffer, mediaBuffers: reply.mediaBuffers });
    if (res.ok) {
      const postedAt = Date.now();
      state.seen[mPost[1]] = postedAt;
      if (q.threadKey) state.threadReplies[q.threadKey] = postedAt;
      delete state.queue[mPost[1]]; state.posts.push(postedAt); await writeXReplyState(state); await clearKb("✅ Posted to X"); await ack("Posted ✨");
    }
    else { await ack(`Post failed: ${res.reason || "try again"}`, true); }
    return true;
  }
  await ack();
  return true;
}
// Claim this DM as the X-reply owner chat — so you never have to look up a numeric Telegram id. If
// AUTOPILOT_OWNER_KEY is set, you must pass it (/xclaim <key>); otherwise the first claimer wins (TOFU).
async function handleXClaimCommand(chatId, message, argument, userId) {
  if (message?.chat?.type && message.chat.type !== "private") { await say(chatId, "DM me /xclaim (not in a group) to become the X-reply owner."); return; }
  const already = xReplyOwnerChat();
  if (already && String(already) !== String(chatId)) { await say(chatId, "An X-reply owner is already set. Clear X_REPLY_OWNER_CHAT / the state to re-claim."); return; }
  if (CONFIG.autopilotOwnerKey) {
    if (String(argument || "").trim() !== CONFIG.autopilotOwnerKey) { await say(chatId, "Usage: /xclaim <your AUTOPILOT_OWNER_KEY> — this binds X-reply approvals to this chat."); return; }
  }
  const state = await readXReplyState();
  state.ownerChat = String(chatId);
  await writeXReplyState(state);
  await sayHtml(chatId, "✅ <b>You're the X-reply owner.</b> Drafts + approvals come here. Now run <code>/xtest</code> to confirm the X cookies are connected.");
}
// Owner setup check: confirm the cookies took + which handle we're posting as.
async function handleXTestCommand(chatId, userId) {
  if (!xReplyOwnerChat()) { await sayHtml(chatId, "🐦 No X-reply owner yet — DM me <code>/xclaim</code>" + (CONFIG.autopilotOwnerKey ? " <code>&lt;your owner key&gt;</code>" : "") + " first to bind approvals to this chat."); return; }
  if (String(chatId) !== xReplyOwnerChat()) { await say(chatId, "This command is owner-only."); return; }
  if (!xConfigured()) { await sayHtml(chatId, "🐦 <b>X not configured.</b> Set <code>X_AUTH_TOKEN</code> + <code>X_CT0</code> (x.com cookies) on Render. (Grab from x.com → F12 → Application → Cookies → copy the values; or paste your whole <code>document.cookie</code> into one <code>X_COOKIES</code> var.)"); return; }
  const me = await xWhoAmI().catch(() => null);
  if (!(me && (me.username || me.screenName))) {
    const rep = xAuthReport() || {};
    await sayHtml(chatId, [
      "🐦 <b>Auth failed.</b>",
      `• <b>Cookies:</b> ${escapeTelegramHtml(rep.cookies || "not set")}`,
      rep.api ? `• <b>X API:</b> ${escapeTelegramHtml(rep.api)}` : "",
      "",
      "The bot now signs requests the way X's own site does, so valid cookies work. If this still fails, the <code>auth_token</code>/<code>ct0</code> are stale — grab fresh ones:",
      "1. Log into <b>x.com</b> → F12 → <b>Application</b> → <b>Cookies</b> → <code>https://x.com</code>.",
      "2. Copy the <b>Value</b> of <code>auth_token</code> and <code>ct0</code> (value only, no quotes).",
      "3. Set <code>X_AUTH_TOKEN</code> + <code>X_CT0</code> on Render, redeploy, <code>/xtest</code>.",
      "",
      "(Grab both from the SAME panel at once so they match — <code>ct0</code> rotates on reload.)"
    ].filter(Boolean).join("\n"));
    return;
  }
  // Live probe: how many recent @mentions the search sees + how many carry a CA (proves detection works).
  const mentions = await xSearchMentions(20).catch(() => []);
  const withCa = mentions.filter((m) => extractMintsFromText(m.text).length || extractRhAddressesFromText(m.text).length || extractCashtags(m.text).length || m.inReplyToId).length;
  await sayHtml(chatId, [
    `🐦 <b>Connected as @${escapeTelegramHtml(me.username || me.screenName)}</b>`,
    `Mode: <b>${xReplyAuto() ? "AUTO — posts on X itself" : "ASSIST — I DM you to one-tap post"}</b> · Replies: <b>${xReplyEnabled() ? "ON" : "OFF"}</b>`,
    `Sees <b>${mentions.length}</b> recent mentions of @${escapeTelegramHtml(me.username || me.screenName)} · <b>${withCa}</b> with a CA`,
    withCa ? "✅ Detection works. If it's not replying, check Mode/Replies above." : "⚠️ No CA-mentions found yet — tag @that-handle in a tweet WITH a contract, then run /xpoll.",
    "",
    "🎯 <b>Smart replies</b> — the bot reads what they ask:",
    "• “did it rug?” / “safe?” → 🛡️ safety verdict card",
    "• “chart?” / “price?” → 📈 live candlestick card",
    "• tag us under any coin tweet → 🔎 scans that post’s CA",
    "",
    "Test now: <code>/xpoll</code> (check mentions) · <code>/xscan &lt;CA&gt;</code> · <code>/xscan rug &lt;CA&gt;</code> · <code>/xscan chart &lt;CA&gt;</code>.",
    "🎯 <b>Didn't auto-answer a tag?</b> <code>/xreply &lt;tweet url&gt;</code> forces the reply to that exact tweet (bypasses the mention feed)."
  ].join("\n"));
}
// Force a mention check right now (no ~2.5-min wait) — great for testing.
async function handleXPollCommand(chatId, userId) {
  if (!xReplyOwnerChat() || String(chatId) !== xReplyOwnerChat()) { await say(chatId, "Owner-only — DM /xclaim first."); return; }
  if (!xReplyEnabled() || !xConfigured()) { await say(chatId, "X replies are OFF or not configured. Set X_REPLY_ENABLED=true + cookies, then /xtest."); return; }
  await say(chatId, "🐦 Checking mentions now…");
  const r = await xReplyPollTick({ forceSearch: true }).catch((e) => ({ error: String(e?.message || e).slice(0, 140) }));
  if (r?.error) { await sayHtml(chatId, `⚠️ Poll error: <code>${escapeTelegramHtml(r.error)}</code>`); return; }
  const icon = (s) => s === "replied" ? "✅" : s === "fail" ? "⚠️" : s === "draft" ? "📝" : s === "defer" ? "⏳" : "·";
  const lines = (r?.results || []).map((x) => `${icon(x.s)} @${escapeTelegramHtml(x.u)} — ${x.s}${x.d ? ` <i>(${escapeTelegramHtml(x.d)})</i>` : ""}`);
  // Diagnostics so you can SEE the machine's state, not guess: how far back it will look, how many tags it
  // remembers answering, how many posts it's made this hour, and whether it's auto-posting or drafting.
  const st = await readXReplyState();
  const now = Date.now();
  const floorAgo = st.replyFloorMs ? Math.max(0, Math.round((now - Number(st.replyFloorMs)) / 60000)) : null;
  const posts1h = (Array.isArray(st.posts) ? st.posts : []).filter((t) => now - Number(t) < 3_600_000).length;
  const diag = `🔎 <i>mode ${xReplyAuto() ? "AUTO" : "assist"} · window ${floorAgo == null ? "—" : floorAgo + "m"} · answered ${Object.keys(st.seen || {}).length} · ${posts1h}/hr</i>`;
  await sayHtml(chatId, [
    `🐦 Checked <b>${r?.checked || 0}</b> recent mentions.`,
    diag,
    ...(lines.length ? lines : ["No NEW mentions to act on — everything current is already answered.<br>Post a brand-new tweet tagging your handle with a CA, or <code>/xreset force</code> to replay the last 30 min."])
  ].join("\n"));
}
// Clear the seen/queue state so the bot RE-REPLIES to the mentions it already handled — for testing, so
// you can watch it fire without needing a fresh tweet each time. Then immediately runs a poll.
async function handleXResetCommand(chatId, userId, argument) {
  if (!xReplyOwnerChat() || String(chatId) !== xReplyOwnerChat()) { await say(chatId, "Owner-only — DM /xclaim first."); return; }
  const force = /\b(force|old|backtrack|replay)\b/i.test(String(argument || ""));
  const state = await readXReplyState();
  const cleared = Object.keys(state.seen || {}).length;
  state.seen = {}; state.fails = {}; state.queue = {}; state.posts = []; state.threadReplies = {};
  if (force) {
    // FORCE (testing): drop the floor 30 min back + clear seen so the very next poll re-answers that backlog.
    state.replyFloorMs = Date.now() - 30 * 60_000;
    await writeXReplyState(state);
    await say(chatId, `🧪 Force-reset — cleared ${cleared} seen + throttle, floor back 30 min. Re-answering recent mentions now…`);
  } else {
    // DEFAULT: catch up. Push the floor to NOW so it can never backtrack to old tags — from here it only
    // answers genuinely NEW mentions, automatically, and never needs a reset again.
    state.replyFloorMs = Date.now();
    await writeXReplyState(state);
    await say(chatId, `🧹 Caught up — cleared ${cleared} seen + throttle. From now it only replies to NEW tags (never backtracks). Post a fresh tag to test, or /xreset force to replay the last 30 min.`);
    return;
  }
  const r = await xReplyPollTick({ forceSearch: true }).catch((e) => ({ error: String(e?.message || e).slice(0, 140) }));
  if (r?.error) { await sayHtml(chatId, `⚠️ Poll error: <code>${escapeTelegramHtml(r.error)}</code>`); return; }
  const icon = (s) => s === "replied" ? "✅" : s === "fail" ? "⚠️" : s === "draft" ? "📝" : s === "defer" ? "⏳" : "·";
  const lines = (r?.results || []).map((x) => `${icon(x.s)} @${escapeTelegramHtml(x.u)} — ${x.s}${x.d ? ` <i>(${escapeTelegramHtml(x.d)})</i>` : ""}`);
  await sayHtml(chatId, [`🐦 Re-checked <b>${r?.checked || 0}</b> mentions.`, ...(lines.length ? lines : ["Nothing scannable in the current mentions."])].join("\n"));
}
// Preview the exact reply (card + text) for a CA or a link containing one — proves the pipeline end-to-end.
async function handleXScanCommand(chatId, argument, userId) {
  if (!xReplyOwnerChat() || String(chatId) !== xReplyOwnerChat()) { await say(chatId, "Owner-only — DM /xclaim first."); return; }
  const arg = String(argument || "");
  const intent = xIntentFromText(arg);                            // "/xscan rug <CA>" or "chart <CA>" previews that card
  let mint = await resolveScanTargetFromText(arg, [], { allowBareTickerHints: false }).catch(() => null);
  if (!mint) { await say(chatId, "Usage: /xscan <CA or $ticker> — or <code>/xscan rug &lt;CA&gt;</code> / <code>/xscan chart &lt;CA&gt;</code> to preview those cards."); return; }
  await say(chatId, `🐦 Building the <b>${intent === "rug" ? "did-it-rug" : intent === "chart" ? "chart" : "scan"}</b> reply preview…`);
  const reply = await buildXReply(mint, intent).catch(() => null);
  if (!reply) { await say(chatId, "Couldn't scan that — it may be too new or unlisted."); return; }
  const cap = `🐦 <b>Reply preview</b> (${intent}) for <code>${escapeTelegramHtml(shortMint(mint))}</code>\n\n<i>${escapeTelegramHtml(reply.text)}</i>`;
  if (reply.mediaBuffer) await sendPhoto(chatId, "x-scan-preview.png", reply.mediaBuffer, cap, null, "HTML").catch(() => sayHtml(chatId, cap));
  else await sayHtml(chatId, cap);
}

// FORCE-REPLY to a SPECIFIC tweet — the manual override for "I tagged the bot and nothing happened".
// The auto-poller depends on X's mention feed surfacing the tag; when notifications lag AND search is
// 429-rate-limited, a fresh tag can slip through and never get answered. This bypasses detection entirely:
// paste the tweet URL (or id) and the bot fetches THAT tweet, pulls its CA/wallet (from the tweet, its parent,
// or the thread root — same resolver the poller uses), builds the card, and posts the reply right there.
//   /xreply https://x.com/user/status/123…           → auto-picks the map/scan card
//   /xreply 123…  rug        (or chart / map)         → force a specific card
async function handleXForceReplyCommand(chatId, argument, userId) {
  if (!xReplyOwnerChat() || String(chatId) !== xReplyOwnerChat()) { await say(chatId, "Owner-only — DM /xclaim first."); return; }
  if (!xReplyEnabled() || !xConfigured()) { await say(chatId, "X replies are OFF or not configured. Set X_REPLY_ENABLED=true + cookies, then /xtest."); return; }
  const arg = String(argument || "").trim();
  const idMatch = arg.match(/status(?:es)?\/(\d{6,25})/) || arg.match(/\b(\d{15,25})\b/);
  const tweetId = idMatch ? idMatch[1] : "";
  if (!tweetId) { await sayHtml(chatId, "Usage: <code>/xreply &lt;tweet url or id&gt; [rug|chart|map]</code> — I'll fetch that exact tweet, find its CA, and post the reply. Use this when a tag didn't auto-answer."); return; }
  // Optional forced intent keyword anywhere in the argument.
  let intent = /\b(rug|safe|honeypot)\b/i.test(arg) ? "rug" : /\b(chart|price|candle)\b/i.test(arg) ? "chart" : /\bmap\b/i.test(arg) ? "map" : "";
  await say(chatId, `🐦 Fetching tweet ${tweetId}…`);
  const tweet = await xGetTweet(tweetId).catch(() => null);
  if (!tweet) { await sayHtml(chatId, `⚠️ Couldn't fetch that tweet (deleted, protected, or the cookies can't see it). Confirm the URL, then <code>/xtest</code>.`); return; }
  // Resolve the target the SAME way the poller does: tweet → its parent/root, then bare-wallet fallback.
  let target = await resolveXTargetMint(tweet).catch(() => null);
  if (!target) { const w = extractBareWalletAddress(tweet.text, tweet.urls); if (w) { target = w; if (!intent) intent = "map"; } }
  if (!target) { await sayHtml(chatId, `⚠️ No contract/wallet found in that tweet (or its parent/root). Text seen: <i>${escapeTelegramHtml(String(tweet.text || "").slice(0, 160))}</i>`); return; }
  if (!intent) intent = xIntentFromText(tweet.text);
  await say(chatId, `🎯 Target <code>${escapeTelegramHtml(shortMint(target))}</code> · ${intent} — building + posting…`);
  const reply = await Promise.race([
    buildXReply(target, intent, tweetId),
    new Promise((res) => setTimeout(() => res("__timeout__"), 45_000)),
  ]).catch((e) => { console.log(`[xreply] force build THREW: ${String(e?.message || e).slice(0, 140)}`); return null; });
  if (reply === "__timeout__") { await say(chatId, "⏱ The card took too long to build (>45s). Try again — feeds may have been slow."); return; }
  if (!reply) { await sayHtml(chatId, "⚠️ Couldn't build a card for that target — it may be too new or unlisted. Try a different intent, or check it scans with <code>/xscan &lt;CA&gt;</code>."); return; }
  const res = await xReplyToThreadAnchor({ ...tweet, id: tweet.id || tweetId }, { text: reply.text, mediaBuffer: reply.mediaBuffer, mediaBuffers: reply.mediaBuffers });
  if (res.ok) {
    // Mark it seen so the auto-poller doesn't double-reply if the tag DOES surface later.
    try { const st = await readXReplyState(); st.seen = st.seen || {}; st.seen[tweetId] = Date.now(); await writeXReplyState(st); } catch { /* best-effort */ }
    try { await xTrackCoin({ mint: target, symbol: reply.symbol, mc: reply.mc, tweetId: res.id, kind: "reply" }); } catch { /* receipts tracking is best-effort */ }
    await sayHtml(chatId, `✅ <b>Posted.</b> Replied to that tweet with the ${intent} card for <code>${escapeTelegramHtml(shortMint(target))}</code>.${res.id ? ` <a href="https://x.com/i/status/${escapeTelegramHtml(String(res.id))}">view</a>` : ""}`);
    console.log(`[xreply] ✅ FORCE reply to ${tweetId} ${intent} $${reply.symbol} media=${res.media || "text"} id=${res.id || ""}`);
  } else {
    await sayHtml(chatId, `⚠️ Post failed: <code>${escapeTelegramHtml(res.reason || "unknown")}</code>. If it's an auth error, refresh the X cookies and <code>/xtest</code>.`);
  }
}

// Owner dashboard for the X growth engine: what's on, how many coins tracked, and the exact env flips.
// `/xbot`               → status  ·  `/xbot receipt <mint>` → force a receipt-style post now (test)
// `/xbot call`          → force one auto-call now (test)  ·  `/xbot scorecard` → post the weekly card now
async function handleXBotCommand(chatId, argument, userId) {
  if (!xReplyOwnerChat() || String(chatId) !== xReplyOwnerChat()) { await say(chatId, "Owner-only — DM /xclaim first."); return; }
  const arg = String(argument || "").trim();
  const s = await readXCoins();
  const now = Date.now();
  const tracked = Object.keys(s.coins).length;
  const withTweet = Object.values(s.coins).filter((c) => c.tweetId && c.entryMc > 0).length;
  // Test actions (owner-triggered, bypass the broadcast gate so you can prove the pipeline before going live).
  const mMint = arg.match(/^receipt\s+([1-9A-HJ-NP-Za-km-z]{32,44})/);
  if (mMint) {
    const mint = mMint[1];
    await say(chatId, "🎯 Building a test receipt post…");
    const live = await xQuickMc(mint); if (!live) { await say(chatId, "Couldn't read that coin's MC."); return; }
    const c = { mint, symbol: live.sym, entryMc: Math.max(1, Math.round(live.mc / 3)), tweetId: "", peakMc: live.mc };  // pretend entry = ⅓ current
    let mediaBuffer = null; try { const r = await buildXReply(mint, "scan", "rtest"); mediaBuffer = r?.mediaBuffer || null; } catch { /* */ }
    const text = `📈 ${c.symbol ? "$" + c.symbol : shortMint(mint)} — flagged at ${scanFmtMoney(c.entryMc)}, now ${scanFmtMoney(live.mc)}. ~3x.\nreceipts, not promises 🐸 (TEST)`;
    const res = await xPost({ text, mediaBuffer });
    await sayHtml(chatId, res.ok ? `✅ Test receipt posted.${res.id ? ` <a href="https://x.com/i/status/${res.id}">view</a>` : ""}` : `⚠️ ${escapeTelegramHtml(res.reason || "failed")}`);
    return;
  }
  if (/^call\b/i.test(arg)) {
    await say(chatId, "📣 Looking for a coin to call…");
    let cand = await xPickAutoCallCandidate(s), watch = false;
    if (!cand) { cand = await xPickMoverCandidate(s); watch = true; }   // fall back to the trench-watch mover so a test always posts
    if (!cand) { await say(chatId, "Nothing to post right now — no network-backed coin AND no qualifying trending mover. Try again shortly."); return; }
    const reply = await buildXReply(cand.mint, "scan", `calltest${now}`);
    if (!reply || !reply.mediaBuffer) { await say(chatId, "Candidate found but its card wouldn't build. Try again."); return; }
    const res = await xPost({ text: watch ? xMoverText(cand, reply) : xAutoCallText(cand, reply), mediaBuffer: reply.mediaBuffer });
    if (res.ok) { await xTrackCoin({ mint: cand.mint, symbol: reply.symbol, mc: reply.mc || cand.mc, tweetId: res.id, kind: watch ? "watch" : "autocall" }); }
    await sayHtml(chatId, res.ok ? `✅ ${watch ? "Trench-watch" : "Called"} $${escapeTelegramHtml(reply.symbol || "")} (${watch ? `1H +${Math.round(cand.h1)}%` : `score ${cand.score}`}).${res.id ? ` <a href="https://x.com/i/status/${res.id}">view</a>` : ""}` : `⚠️ ${escapeTelegramHtml(res.reason || "failed")}`);
    return;
  }
  if (/^scorecard\b/i.test(arg)) {
    const before = s.lastScorecardAt; s.lastScorecardAt = 0; await writeXCoins(s);   // force the weekly gate open once
    await xScorecardTick();
    const after = await readXCoins();
    await say(chatId, after.lastScorecardAt > before ? "✅ Scorecard posted." : "Nothing to post yet (need ≥3 tracked coins with an entry MC this week).");
    return;
  }
  if (/^terminal\b/i.test(arg)) {
    const pinText = [
      "SLIMEWIRE X TERMINAL",
      "",
      "Tag @SlimeWirebot:",
      "scan <CA> | chart <CA> | rug <CA>",
      "",
      "Full swaps, bundles, TP/SL, launch tools:",
      "web + @SlimeWiredBot",
      "",
      "No seed phrases. Wallet-confirmed."
    ].join("\n");
    const terminalUrl = "https://www.slimewire.org/x-terminal";
    const fullPinText = `${pinText}\n${terminalUrl}`;
    const composerUrl = xPostIntentUrl({ text: pinText, url: terminalUrl, hashtags: ["SlimeWire", "Solana"] });
    const cardUrl = "https://www.slimewire.org/assets/slimewire/auto/x-terminal-card.png";
    const handleUrl = `https://x.com/${xHandle() || "SlimeWirebot"}`;
    const kb = { inline_keyboard: [
      [{ text: "Open X Composer", url: composerUrl }],
      [{ text: "Open X Terminal", url: terminalUrl }, { text: "Open X Profile", url: handleUrl }],
      [{ text: "Open logo card", url: cardUrl }]
    ] };
    const caption = [
      "✅ <b>X pin kit ready.</b>",
      "X blocked automated posting on this account, so use the composer button, post it manually, then pin it on X.",
      "",
      "<b>Pin text</b>",
      `<pre>${escapeTelegramHtml(fullPinText)}</pre>`
    ].join("\n");
    const cardPath = path.join(WEB_STATIC_DIR, "assets", "slimewire", "auto", "x-terminal-card.png");
    const sourceCardPath = path.resolve(__dirname, "..", "web", "public", "assets", "slimewire", "auto", "x-terminal-card.png");
    const mediaBuffer = await fs.readFile(cardPath).catch(() => fs.readFile(sourceCardPath).catch(() => null));
    if (mediaBuffer) {
      await sendPhoto(chatId, "x-terminal-card.png", mediaBuffer, caption, kb, "HTML").catch(async () => {
        await sayHtml(chatId, caption, kb);
      });
    } else {
      await sayHtml(chatId, caption, kb);
    }
    return;
  }
  const on = (b) => b ? "🟢 ON" : "⚪️ off";
  await sayHtml(chatId, [
    "🐦🔥 <b>X Growth Engine</b>",
    `Master broadcast: <b>${xBroadcastOn() ? "🟢 LIVE" : "⚪️ DARK"}</b>  ·  Persona: ${on(xPersonaOn())}`,
    `• 🎯 Receipts (10x quote-tweets): ${on(xReceiptsOn())}`,
    `• 📣 Auto-calls (network-backed): ${on(xAutoCallOn())}`,
    `• 🐸 Trench-watch heartbeat (movers): ${on(xHeartbeatOn())}`,
    `• ⚡ KOL first-responder (their tweets): ${on(xKolWatchOn())} — watching <b>${xKolWatchHandles().length}</b> handles (kolscan top ${_kolscanTopHandles.length} + manual)`,
    `• 🐋 KOL wallet convergence (their trades): ${on(xKolTradeOn())} — following <b>${xKolTopWallets().length}</b> kolscan wallets${CONFIG.heliusApiKey ? "" : " ⚠️ needs Helius key"}`,
    `• 📊 Weekly scorecard: ${on(xScorecardOn())}`,
    "",
    `Tracked coins: <b>${tracked}</b> (${withTweet} with a post to quote)`,
    "",
    "<b>Go live</b> (Render env → redeploy):",
    "<code>XBOT_BROADCAST=true</code> — master switch (everything below needs it)",
    "<code>XBOT_KOLWATCH=true</code> + <code>XBOT_KOL_HANDLES=cupsey,euris,…</code> — first-responder",
    "Tune: <code>XBOT_AUTOCALL_GAP_MIN</code> (180) · <code>XBOT_AUTOCALL_DAILY</code> (6) · <code>XBOT_AUTOCALL_MIN_SCORE</code> (55) · <code>XBOT_AUTOCALL_MIN_MC</code> (15000)",
    "",
    "<b>Test now</b>:",
    "<code>/xbot terminal</code> (manual pin kit) · <code>/xbot call</code> · <code>/xbot receipt &lt;mint&gt;</code> · <code>/xbot scorecard</code>",
  ].join("\n"));
}

// ============================================================================
// 🐦🔥 X GROWTH ENGINE — turns the reactive scan-bot into a trench account people
// FOLLOW: proactive alpha calls, public RECEIPTS (auto "🎯 called at $30k → 10x"
// quote-tweets), a KOL first-responder, a weekly scorecard, plus smarter/degen
// reply text. Everything that POSTS is gated behind XBOT_BROADCAST=true (master,
// default OFF) + per-feature flags — flip one env var to go live, nothing blasts
// the account by accident. Tracking + reply enrich are always on (no post risk).
// ============================================================================
function xBroadcastOn() { return parseBoolean(process.env.XBOT_BROADCAST || "false"); }
function xFeatureOn(env, def) { const v = String(process.env[env] || "").trim(); return xBroadcastOn() && (v ? parseBoolean(v) : def); }
const xReceiptsOn  = () => xFeatureOn("XBOT_RECEIPTS", true);
const xAutoCallOn  = () => xFeatureOn("XBOT_AUTOCALL", true);
const xHeartbeatOn = () => xFeatureOn("XBOT_HEARTBEAT", true);   // "trenches now" mover post when no high-conviction call
const xKolWatchOn  = () => xFeatureOn("XBOT_KOLWATCH", false);   // highest ban risk → OFF even under broadcast until opted in
const xKolTradeOn  = () => xFeatureOn("XBOT_KOLTRADES", true);   // 🐋 follow kolscan top-30 WALLETS on-chain, post on convergence
const xScorecardOn = () => xFeatureOn("XBOT_SCORECARD", true);
const xPersonaOn   = () => { const v = String(process.env.XBOT_PERSONA || "").trim(); return v ? parseBoolean(v) : true; };   // text-only, safe → on by default
const XBOT_MILESTONES = [2, 3, 5, 10, 25, 50, 100];
// GLOBAL anti-spam gate for PROACTIVE posts only (auto-call, heartbeat, receipts, KOL quotes, convergence).
// Replies to user tags are NOT gated — people who tag the bot always get answered, even under heavy use. This
// only stops the proactive broadcasters from bunching up (X folds accounts that machine-gun posts). Short gap by
// default (40s) so the account stays steadily active without long dead pauses; a blocked post just defers to the
// next tick (never lost). Tunable via XBOT_MIN_GAP_SEC.
let _xLastBroadcastAt = 0;
function xBroadcastGateOk() { return Date.now() - _xLastBroadcastAt >= Math.max(10, Number(process.env.XBOT_MIN_GAP_SEC || 40)) * 1000; }
function xMarkBroadcast() { _xLastBroadcastAt = Date.now(); }
// Compose a proactive post with the FULL contract on its own last line, so followers can one-tap copy + ape it.
// Keeps the CA intact (never truncated): fits the CTA if there's room, else drops the CTA to protect the CA.
function xPostText(hook, stats, mint, cta) {
  const ca = String(mint || "");
  for (const withCta of [true, false]) {
    const t = [hook, stats, (withCta && cta) ? cta : "", ca].filter(Boolean).join("\n");
    if (t.length <= 279) return t;
  }
  return [hook, stats, ca].filter(Boolean).join("\n").slice(0, 279);
}
const XBOT_CTA = "🔎 free scan on any coin — tag @SlimeWirebot 🐸";

// ---- tracked-coins store: entry snapshots so receipts can quote our original post later ----
function xCoinsStateFile() { return path.join(CONFIG.dataDir, "x-coins-state.json"); }
let xCoinsCache = null;
async function readXCoins() {
  if (xCoinsCache) return xCoinsCache;
  let s = null; try { s = await readJson(xCoinsStateFile()); } catch { s = null; }
  if (!s || typeof s !== "object") s = {};
  if (!s.coins || typeof s.coins !== "object") s.coins = {};
  if (!Array.isArray(s.posts)) s.posts = [];
  if (typeof s.lastAutoCallAt !== "number") s.lastAutoCallAt = 0;
  if (typeof s.lastScorecardAt !== "number") s.lastScorecardAt = 0;
  if (!s.kolSeen || typeof s.kolSeen !== "object") s.kolSeen = {};
  xCoinsCache = s; return s;
}
async function writeXCoins(s) { xCoinsCache = s; await writeJsonFile(xCoinsStateFile(), s).catch(() => {}); }
// Record a coin the bot surfaced (reply or proactive post). tweetId = OUR post — the receipt quotes it later.
async function xTrackCoin({ mint, symbol, mc, tweetId, kind } = {}) {
  if (!solanaPublicKeyLike(mint)) return null;
  const s = await readXCoins();
  const now = Date.now();
  let c = s.coins[mint];
  if (!c) {
    c = s.coins[mint] = { mint, symbol: symbol || "", entryMc: Number(mc) || 0, firstAt: now, tweetId: tweetId ? String(tweetId) : "", kind: kind || "reply", peakMc: Number(mc) || 0, milestones: [], lastCheckAt: 0 };
  } else {
    if (symbol && !c.symbol) c.symbol = symbol;
    if (!(c.entryMc > 0) && Number(mc) > 0) { c.entryMc = Number(mc); c.firstAt = now; }
    if (tweetId && !c.tweetId) c.tweetId = String(tweetId);   // anchor to our FIRST post/reply for the quote
    if (Number(mc) > (c.peakMc || 0)) c.peakMc = Number(mc);
  }
  const keys = Object.keys(s.coins);
  if (keys.length > 800) keys.map((k) => s.coins[k]).sort((a, b) => (a.firstAt || 0) - (b.firstAt || 0)).slice(0, keys.length - 800).forEach((x) => delete s.coins[x.mint]);
  await writeXCoins(s);
  return c;
}
async function xCoinMemory(mint) { try { const s = await readXCoins(); return s.coins[mint] || null; } catch { return null; } }
// Light MC read for receipts/candidate-vetting — GeckoTerminal (free, not IP-limited on Render), then DexScreener.
async function xQuickMc(mint) {
  try { const g = await getGeckoTerminalTokenMetadata(mint, { timeoutMs: 3500 }).catch(() => null); const mc = Number(g?.marketCap || g?.fdv || 0); if (mc > 0) return { mc, sym: g?.symbol || "" }; } catch { /* */ }
  try { const p = await fetchDexScreenerTokenPairsFallback(mint).catch(() => null); const b = bestDexPairForToken(mint, p); const m = b ? metadataFromDexPair(mint, b) : null; const mc = Number(m?.marketCap || m?.fdv || 0); if (mc > 0) return { mc, sym: m?.symbol || "" }; } catch { /* */ }
  return null;
}

// ---- 🎯 RECEIPTS: when a tracked coin crosses a multiple, quote-tweet our original post ----
let _xReceiptsRunning = false;
async function xReceiptsTick() {
  if (!xConfigured() || _xReceiptsRunning) return;
  _xReceiptsRunning = true;
  try {
    const s = await readXCoins();
    const now = Date.now();
    // Due = anchored to our tweet + has an entry MC + not checked in 12min; oldest-checked first, bounded batch.
    const due = Object.values(s.coins)
      .filter((c) => c.tweetId && c.entryMc > 0 && (now - (c.lastCheckAt || 0)) > 12 * 60_000)
      .sort((a, b) => (a.lastCheckAt || 0) - (b.lastCheckAt || 0)).slice(0, 10);
    let posted = 0;
    for (const c of due) {
      c.lastCheckAt = now;
      const live = await xQuickMc(c.mint);
      if (!live) continue;
      if (live.sym && !c.symbol) c.symbol = live.sym;
      if (live.mc > (c.peakMc || 0)) c.peakMc = live.mc;
      const mult = c.entryMc > 0 ? live.mc / c.entryMc : 0;
      const crossed = XBOT_MILESTONES.filter((m) => mult >= m && !c.milestones.includes(m));
      if (crossed.length && xReceiptsOn() && posted < 2) {
        if (!xBroadcastGateOk()) break;          // global gate — leave milestones unfired, retry next tick
        const top = crossed[crossed.length - 1];
        const ok = await xPostReceipt(c, live.mc, top);
        if (ok) { c.milestones.push(...crossed); posted++; }   // only mark fired when we actually posted (holds until broadcast on)
      }
    }
    await writeXCoins(s);
  } catch (e) { console.log(`[xbot] receipts tick err: ${String(e?.message || e).slice(0, 100)}`); }
  finally { _xReceiptsRunning = false; }
}
async function xPostReceipt(c, curMc, mult) {
  const sym = c.symbol ? `$${c.symbol}` : shortMint(c.mint);
  const emoji = mult >= 100 ? "🌕" : mult >= 50 ? "🚀" : mult >= 10 ? "🔥" : mult >= 5 ? "💰" : "📈";
  const text = xPostText(`${emoji} ${sym} — flagged at ${scanFmtMoney(c.entryMc)}, now ${scanFmtMoney(curMc)}. ${mult}x.`, "receipts, not promises. called it early 🐸", c.mint, XBOT_CTA);
  let mediaBuffer = null;
  try { const r = await buildXReply(c.mint, "scan", `receipt${mult}${c.mint}`); mediaBuffer = r?.mediaBuffer || null; } catch { /* text-only ok */ }
  const res = await xPost({ quoteTweetId: c.tweetId, text, mediaBuffer });
  if (res.ok) { xMarkBroadcast(); console.log(`[xbot] 🎯 receipt ${sym} ${mult}x id=${res.id}`); await xReplyOwnerNotify(`🎯 X receipt: ${sym} ${mult}x (${scanFmtMoney(c.entryMc)} → ${scanFmtMoney(curMc)})`).catch(() => {}); return true; }
  console.log(`[xbot] receipt FAILED ${sym}: ${res.reason}`); return false;
}

// ---- 📣 PROACTIVE AUTO-CALL: post the SlimeWire brain's best network-backed coin, throttled ----
let _xAutoCallRunning = false;
async function xAutoCallTick() {
  if (!xConfigured() || !xAutoCallOn() || _xAutoCallRunning) return;
  _xAutoCallRunning = true;
  try {
    const s = await readXCoins();
    const now = Date.now();
    const gapMin = Math.max(45, Number(process.env.XBOT_AUTOCALL_GAP_MIN || 180));
    if (now - (s.lastAutoCallAt || 0) < gapMin * 60_000) return;
    const dailyCap = Math.max(1, Number(process.env.XBOT_AUTOCALL_DAILY || 6));
    s.posts = s.posts.filter((t) => now - t < 86_400_000);
    if (s.posts.length >= dailyCap) return;
    // 1) HIGH-CONVICTION network-backed call (rare, the real signal). 2) HEARTBEAT: if none, post the best live
    // trending MOVER as a clearly-framed "trench watch" so the account has daily content + seeds the receipt
    // store (a mover we watch today is a receipt candidate if it runs). Same throttle → still ≤daily-cap posts.
    if (!xBroadcastGateOk()) return;            // global anti-spam gate — defer to next tick
    let cand = await xPickAutoCallCandidate(s), watch = false;
    if (!cand && xHeartbeatOn()) { cand = await xPickMoverCandidate(s); watch = true; }
    if (!cand) return;
    const reply = await buildXReply(cand.mint, "scan", `autocall${now}`);
    if (!reply || !reply.mediaBuffer) return;   // never post a text-only call — the card is the point
    const res = await xPost({ text: watch ? xMoverText(cand, reply) : xAutoCallText(cand, reply), mediaBuffer: reply.mediaBuffer });
    if (res.ok) {
      xMarkBroadcast();
      s.lastAutoCallAt = now; s.posts.push(now); await writeXCoins(s);
      await xTrackCoin({ mint: cand.mint, symbol: reply.symbol, mc: reply.mc || cand.mc, tweetId: res.id, kind: watch ? "watch" : "autocall" });
      console.log(`[xbot] ${watch ? "🐸 trench-watch" : "📣 auto-call"} $${reply.symbol} ${watch ? `1H=${cand.h1}%` : `score=${cand.score}`} id=${res.id}`);
      await xReplyOwnerNotify(`${watch ? "🐸 X trench-watch" : "📣 X auto-call"}: $${reply.symbol} (${scanFmtMoney(reply.mc || cand.mc)}${watch ? ` · 1H +${Math.round(cand.h1)}%` : ` · score ${cand.score}`})`).catch(() => {});
    }
  } catch (e) { console.log(`[xbot] autocall tick err: ${String(e?.message || e).slice(0, 100)}`); }
  finally { _xAutoCallRunning = false; }
}
// HEARTBEAT candidate = best FREE trending mover (GeckoTerminal, not IP-limited): real momentum + liquidity,
// trench-sized MC (not a mega-cap), not already surfaced. Keeps the account alive between rare conviction calls.
async function xPickMoverCandidate(s) {
  let pools = [];
  try { pools = await fetchGeckoPools("trending", { pages: 2, timeoutMs: 3500 }); } catch { pools = []; }
  const minLiq = Number(process.env.XBOT_MOVER_MIN_LIQ || 20_000);
  const minMc = Number(process.env.XBOT_MOVER_MIN_MC || 25_000);
  const maxMc = Number(process.env.XBOT_MOVER_MAX_MC || 8_000_000);
  const minH1 = Number(process.env.XBOT_MOVER_MIN_H1 || 8);
  const cands = [];
  for (const p of (pools || [])) {
    const mint = p.tokenMint; const pr = p.profile || {};
    if (!mint || s.coins[mint]) continue;
    const liq = Number(pr.liquidityUsd || pr.liquidity?.usd || 0);
    const mc = Number(pr.marketCap || pr.fdv || 0);
    const h1 = Number(pr.priceChange?.h1 || 0);
    if (liq < minLiq || mc < minMc || mc > maxMc || h1 < minH1) continue;   // real, liquid, trench-sized, moving up
    cands.push({ mint, mc, sym: pr.symbol || "", h1, liq, score: h1 + Math.min(40, Math.log10(Math.max(1, liq)) * 6) });
  }
  cands.sort((a, b) => b.score - a.score);
  return cands[0] || null;
}
function xMoverText(cand, reply) {
  const sym = reply.symbol ? `$${reply.symbol}` : shortMint(cand.mint);
  const openers = ["🐸 trench watch:", "👀 moving in the trenches:", "🔥 heating up:", "⚡ on the move:"];
  const op = openers[Math.abs(xSeedHash(cand.mint)) % openers.length];
  const h1 = `${cand.h1 >= 0 ? "+" : ""}${Math.round(cand.h1)}%`;
  return xPostText(`${op} ${sym}`, `${scanFmtMoney(reply.mc || cand.mc)} MC · 1H ${h1} · liq ${scanFmtMoney(cand.liq)} · NFA`, cand.mint, XBOT_CTA);
}
// Candidate = highest network-backed coin from the observatory not already posted, live-MC vetted (dust filter).
async function xPickAutoCallCandidate(s) {
  const seen = new Set();
  try { for (const m of insiderLaunches.keys()) seen.add(m); } catch { /* */ }
  try { for (const m of obsCoins.keys()) seen.add(m); } catch { /* */ }
  try { for (const m of earlyBuyers.keys()) seen.add(m); } catch { /* */ }
  const minScore = Math.max(40, Number(process.env.XBOT_AUTOCALL_MIN_SCORE || 55));
  const cands = [];
  for (const mint of seen) {
    if (s.coins[mint]) continue;                 // never re-call a coin we already surfaced
    let net; try { net = computeNetworkBacking(mint); } catch { continue; }
    if (!net || !net.backed || (net.score || 0) < minScore) continue;
    cands.push({ mint, score: net.score || 0 });
  }
  cands.sort((a, b) => b.score - a.score);
  for (const c of cands.slice(0, 6)) {           // vet the top few with a live MC read; skip dust
    const live = await xQuickMc(c.mint);
    if (live && live.mc >= Math.max(8_000, Number(process.env.XBOT_AUTOCALL_MIN_MC || 15_000))) return { ...c, mc: live.mc, sym: live.sym };
  }
  return null;
}
function xAutoCallText(cand, reply) {
  const sym = reply.symbol ? `$${reply.symbol}` : shortMint(cand.mint);
  const openers = ["👀 eyes on", "🐸 trench watch:", "⚡ on the radar:", "🧪 the SlimeWire brain flagged"];
  const op = openers[Math.abs(xSeedHash(cand.mint)) % openers.length];
  return xPostText(`${op} ${sym}`, `${scanFmtMoney(reply.mc || cand.mc)} MC · network-backed · NFA`, cand.mint, XBOT_CTA);
}
function xSeedHash(s) { let h = 2166136261; const str = String(s || ""); for (let i = 0; i < str.length; i++) { h ^= str.charCodeAt(i); h = Math.imul(h, 16777619); } return h | 0; }

