  return { text: [`🏆 <b>Room PnL</b> — the room is <b>${total >= 0 ? "+" : ""}${total.toFixed(2)} ◎</b> banked`, ...lines, "", "<i>Realized SOL from members' own SlimeWire trades. Fully opt-in — your call.</i>"].join("\n"), markup: roomMenuMarkup() };
