async function applyBuyPrefInput(message, userId) {
  const pend = buyPrefPending.get(String(userId)); if (!pend) return false;
  if (Date.now() - pend.at > 180000) { buyPrefPending.delete(String(userId)); return false; }
  const raw = String(message.text || "").trim(); if (!raw || raw.startsWith("/")) return false;
  const v = Number(raw.replace(/[^0-9.]/g, ""));
  if (!Number.isFinite(v) || v <= 0) { await say(message.chat.id, "Send just the SOL amount, e.g. 0.5"); return true; }
  buyPrefPending.delete(String(userId));
  await setBuyPref(userId, pend.kind, v);
  const menu = buyPresetsMenu(userBuyPrefs(await readBuyPrefs(), userId));
  await sayHtml(message.chat.id, "✅ Saved.\n" + menu.text, menu.markup).catch(() => {});
  return true;
}
async function tgExecuteQuickBuy(userId, mint, amountSol, options = {}) {
  try {
    const st = await readState().catch(() => null);
    if (st && st.paused) return { ok: false, why: "trading is paused right now" };
    const wallets = walletsForOwner(await readWalletStore(), userId);
    const wallet = wallets && wallets[0];
    if (!wallet) return { ok: false, needWallet: true };
    const amt = Number(amountSol);
    if (!Number.isFinite(amt) || amt <= 0) return { ok: false, why: "bad amount" };
    const lamports = solToLamports(amt);
    const slippageBps = userBuyPrefs(await readBuyPrefs(), userId).slippageBps;
    // Dedup rapid identical double-taps within ~15s without collapsing different wallets/amounts/settings.
    const extraKeyParts = Array.isArray(options.idempotencyParts) ? options.idempotencyParts.map((v) => String(v || "").replace(/:/g, "_")).filter(Boolean) : [];
    const attemptId = [mint, wallet.publicKey || "", String(lamports), `slip${slippageBps}`, ...extraKeyParts, Math.floor(Date.now() / 15000)].join(":");
    const result = await runIdempotentMoneyOp("tg-quick-buy", userId, attemptId,
      () => buyTokenForPlan(wallet, mint, lamports, slippageBps, { trackTokenDelta: true, userId }));
    if (result) {
      await recordTradeEvents([{ userId, type: "buy", source: "tg-quick-buy", tokenMint: mint, walletLabel: wallet.label, walletPublicKey: wallet.publicKey, solLamportsSpent: String(result.amountLamports || lamports), ...(result.tokenAmount != null ? { tokenAmount: String(result.tokenAmount) } : {}), signature: result.signature }]).catch(() => {});
    }
    return { ok: Boolean(result), result, wallet, amt };
  } catch (e) { return { ok: false, why: (friendlyError ? friendlyError(e) : (e && e.message)) || "buy failed" }; }
}
