async function handleLimitOrderCallback(query, userId) {
  const data = String(query?.data || ""); if (!data.startsWith("lo:")) return false;
  const chatId = query.message?.chat?.id, messageId = query.message?.message_id;
  const ack = (t, alert) => telegram("answerCallbackQuery", { callback_query_id: query.id, ...(t ? { text: t, show_alert: Boolean(alert) } : {}) }).catch(() => {});
  // cancel
  let m = data.match(/^lo:x:(.+)$/);
  if (m) { const ok = await cancelLimitOrder(userId, m[1]); await ack(ok ? "Cancelled." : "Already gone."); await showOrdersHub(chatId, userId, messageId); return true; }
  // open the clean per-coin builder (sub-menu buttons, in-chat, tidy typed inputs) — works in groups + DM
  m = data.match(/^lo:new:([1-9A-HJ-NP-Za-km-z]{32,44})$/);
  if (m) { await ack(); await openLimitBuilder(chatId, userId, m[1]); return true; }
  // price alert (no trade) → prompt for the target MC only
  m = data.match(/^lo:a:([1-9A-HJ-NP-Za-km-z]{32,44})$/);
  if (m) {
    const mint = m[1];
    const info = await alphaRadarFetchMc(mint).catch(() => null);
    const refMc = info && info.mc > 0 ? info.mc : 0;
    limitOrderPending.set(String(userId), { side: "alert", mint, sym: (info && info.sym) || "", refMc, at: Date.now() });
    await ack();
    await sayHtml(userId, [
      `🔔 <b>Price alert</b>${refMc ? ` (now ${fmtMc(refMc)})` : ""} — reply with the <b>target market cap</b>.`,
      "e.g. <code>1m</code> = DM me when it hits $1M. I'll watch it; no trade, just a ping.",
      "Target above now = pings on a pump · below now = pings on a dip."
    ].join("\n")).catch(() => {});
    return true;
  }
  // choose a side → prompt for the trigger + amount
  m = data.match(/^lo:(b|s):([1-9A-HJ-NP-Za-km-z]{32,44})$/);
  if (m) {
    if (!walletsForOwner(await readWalletStore(), userId).length) { await ack("Make a free SlimeWire wallet first — DM me /start.", true); return true; }
    const side = m[1] === "b" ? "buy" : "sell", mint = m[2];
    const info = await alphaRadarFetchMc(mint).catch(() => null);
    const refMc = info && info.mc > 0 ? info.mc : 0;
    limitOrderPending.set(String(userId), { side, mint, sym: (info && info.sym) || "", refMc, at: Date.now() });
    await ack();
    const now = refMc ? ` (now ${fmtMc(refMc)})` : "";
    if (side === "buy") {
      await sayHtml(userId, [
        `🟢 <b>Limit Buy</b>${now} — reply with <b>target MC</b> and <b>SOL amount</b>.`,
        "e.g. <code>30k 0.5</code> = buy 0.5◎ when it hits $30k.",
        "Target below now = buy the dip · above now = buy the breakout."
      ].join("\n")).catch(() => {});
    } else {
      await sayHtml(userId, [
        `🔴 <b>Limit Sell</b>${now} — reply with <b>target MC</b> and <b>sell %</b>.`,
        "e.g. <code>250k 100</code> = sell 100% when it hits $250k.",
        "Target above now = take profit · below now = stop loss."
      ].join("\n")).catch(() => {});
    }
    return true;
  }
  await ack();
  return true;
}
// ---- ⏰ CLEAN in-chat Limit builder (lo2:*) — sub-menu buttons, per-field, tidy typed inputs -----------
// Everything happens right in the chat (group or DM): tap Side, tap 🎯 Target MC / 💰 Amount to type ONE
// value, and the bot deletes both the prompt and your typed reply so the chat never fills with text.
// Per-user (owner-gated) + keyed by chat+user, so many people can build orders in the same group.
const limitDraft = new Map();        // `${chatId}:${userId}` -> { mint, sym, refMc, side, triggerMc, amount, uid, builderMsgId, at }
const cleanInputPending = new Map();  // `${chatId}:${userId}` -> { kind, at, promptMsgId, builderMsgId }
function limitBuilderView(draft, mc) {
  const side = draft.side || "buy";
  const uid = draft.uid;
  const mk = (on, l) => (on ? "• " : "") + l;
  const sideLabel = side === "buy" ? "🟢 Buy" : side === "sell" ? "🔴 Sell" : "🔔 Alert";
  const mcLine = draft.triggerMc ? fmtMc(draft.triggerMc) : "— tap to set";
  const dir = draft.triggerMc && mc ? (draft.triggerMc >= mc ? "▲ up" : "▼ down") : "";
  const amtLine = side === "alert" ? "" : (draft.amount ? (side === "buy" ? `${draft.amount}◎` : `${draft.amount}%`) : "— tap to set");
  const rows = [
    [
      { text: mk(side === "buy", "🟢 Buy"), callback_data: `lo2:s:b:${uid}` },
      { text: mk(side === "sell", "🔴 Sell"), callback_data: `lo2:s:s:${uid}` },
      { text: mk(side === "alert", "🔔 Alert"), callback_data: `lo2:s:a:${uid}` }
    ],
    [{ text: `🎯 Target MC${draft.triggerMc ? `: ${fmtMc(draft.triggerMc)}` : ""}`, callback_data: `lo2:mc:${uid}` }]
  ];
  if (side !== "alert") {
    const quick = side === "buy" ? [0.1, 0.25, 0.5, 1] : [25, 50, 100];
    rows.push(quick.map((v) => ({ text: mk(draft.amount === v, side === "buy" ? `${v}◎` : `${v}%`), callback_data: `lo2:amt:${v}:${uid}` }))
      .concat([{ text: "✏️", callback_data: `lo2:amtx:${uid}` }]));
  }
  rows.push([{ text: "✅ Arm order", callback_data: `lo2:arm:${uid}` }, { text: "✖ Cancel", callback_data: `lo2:x:${uid}` }]);
  const text = [
    `⏰ <b>Limit order</b> — ${escapeTelegramHtml(draft.sym || shortMint(draft.mint))}`,
    mc ? `Now: <b>${fmtMc(mc)}</b>` : "Now: <i>MC unavailable</i>",
    "",
    `Side: <b>${sideLabel}</b>`,
    `Target MC: <b>${mcLine}</b>${dir ? ` <i>(${dir})</i>` : ""}`,
    side === "alert" ? "" : `Amount: <b>${amtLine}</b>`,
    "",
    side === "buy" ? "<i>Below now = buy the dip · above = buy the breakout. Fires from your own wallet.</i>"
      : side === "sell" ? "<i>Above now = take profit · below = stop loss. Fires from your own wallet.</i>"
      : "<i>I'll DM you when it crosses — no trade.</i>"
  ].filter(Boolean).join("\n");
  return { text, markup: { inline_keyboard: rows } };
}
async function openLimitBuilder(chatId, userId, mint) {
  const info = await alphaRadarFetchMc(mint).catch(() => null);
  const mc = info && info.mc > 0 ? info.mc : 0;
  const draft = { mint, sym: (info && info.sym) || "", refMc: mc, side: "buy", triggerMc: 0, amount: 0, uid: String(userId), builderMsgId: null, at: Date.now() };
  limitDraft.set(`${chatId}:${userId}`, draft);
  const v = limitBuilderView(draft, mc);
  const res = await telegram("sendMessage", { chat_id: chatId, text: v.text, parse_mode: "HTML", disable_web_page_preview: true, reply_markup: v.markup }).catch(() => null);
  if (res && res.message_id) draft.builderMsgId = res.message_id;
}
async function renderLimitBuilder(chatId, userId) {
  const draft = limitDraft.get(`${chatId}:${userId}`);
  if (!draft || !draft.builderMsgId) return;
  const v = limitBuilderView(draft, draft.refMc);
  await telegram("editMessageText", { chat_id: chatId, message_id: draft.builderMsgId, text: v.text, parse_mode: "HTML", disable_web_page_preview: true, reply_markup: v.markup }).catch(() => {});
}
async function handleLimitBuilderCallback(query, userId) {
  const data = String(query?.data || ""); if (!data.startsWith("lo2:")) return false;
  const chatId = query.message?.chat?.id, messageId = query.message?.message_id;
  const ack = (t, a) => telegram("answerCallbackQuery", { callback_query_id: query.id, ...(t ? { text: t, show_alert: Boolean(a) } : {}) }).catch(() => {});
  const parts = data.split(":");
  const kind = parts[1];
  const owner = parts[parts.length - 1];
  if (String(userId) !== String(owner)) { await ack("Tap ⏰ Limit to open your own.", true); return true; }
  const key = `${chatId}:${owner}`;
  const draft = limitDraft.get(key);
  if (!draft) { await ack("That order builder expired — tap ⏰ Limit again.", true); return true; }
  if (messageId) draft.builderMsgId = messageId;
  if (kind === "s") {
    const s = parts[2]; draft.side = s === "b" ? "buy" : s === "s" ? "sell" : "alert";
    if (draft.side === "alert") draft.amount = 0;
    await renderLimitBuilder(chatId, userId); await ack(); return true;
  }
  if (kind === "mc") { await ack(); await promptCleanInput(chatId, userId, "🎯 Reply with the <b>target market cap</b> (e.g. <code>30k</code>, <code>250k</code>, <code>1.2m</code>).", "lo_mc"); return true; }
  if (kind === "amt") { draft.amount = Number(parts[2]); await renderLimitBuilder(chatId, userId); await ack(); return true; }
  if (kind === "amtx") { await ack(); await promptCleanInput(chatId, userId, draft.side === "buy" ? "💰 Reply with the <b>SOL amount</b> (e.g. <code>0.5</code>)." : "💰 Reply with the <b>sell %</b> (e.g. <code>100</code>).", "lo_amt"); return true; }
  if (kind === "x") { limitDraft.delete(key); if (messageId) await telegram("deleteMessage", { chat_id: chatId, message_id: messageId }).catch(() => {}); await ack("Cancelled"); return true; }
  if (kind === "arm") {
    if (!draft.triggerMc) { await ack("Set the target market cap first.", true); return true; }
    if (draft.side !== "alert" && !(draft.amount > 0)) { await ack(draft.side === "buy" ? "Set the SOL amount first." : "Set the sell % first.", true); return true; }
    if (draft.side !== "alert" && !walletsForOwner(await readWalletStore(), userId).length) { await ack(noWalletAckText(await funnelNoWallet(userId)), true); return true; }
    const slippageBps = userBuyPrefs(await readBuyPrefs(), userId).slippageBps;
    const dir = draft.triggerMc >= (draft.refMc || 0) ? ">=" : "<=";
    const spec = { side: draft.side, mint: draft.mint, sym: draft.sym, refMc: draft.refMc || 0, triggerMc: draft.triggerMc, dir, slippageBps };
    if (draft.side === "buy") spec.amountSol = Math.min(LIMIT_MAX_SOL, Math.max(LIMIT_MIN_SOL, draft.amount));
    else if (draft.side === "sell") spec.pct = Math.min(100, Math.max(1, Math.round(draft.amount)));
    const res = await addLimitOrder(userId, spec);
    if (!res.ok) { if (res.needWallet) await ack(noWalletAckText(await funnelNoWallet(userId)), true); else await ack(`Couldn't arm: ${res.why || "try again"}.`, true); return true; }
    limitDraft.delete(key);
    const o = res.order;
    const text = ["⏰✅ <b>Order armed</b>", limitOrderLine(o), "", `<i>Fires automatically when ${escapeTelegramHtml(o.sym || shortMint(o.mint))} crosses ${fmtMc(o.triggerMc)}. Expires in 14 days.</i>`].join("\n");
    const markup = { inline_keyboard: [[{ text: "⏰ My Orders", callback_data: "orders_hub" }, { text: "➕ Another", callback_data: `lo:new:${draft.mint}` }]] };
    if (messageId) await telegram("editMessageText", { chat_id: chatId, message_id: messageId, text, parse_mode: "HTML", disable_web_page_preview: true, reply_markup: markup }).catch(() => {});
    await ack("⏰ Armed!");
    return true;
  }
  await ack(); return true;
}
// Prompt for ONE value with force-reply; store the prompt id so we can delete it after the answer.
async function promptCleanInput(chatId, userId, promptText, kind, builderMsgId = null) {
  const res = await telegram("sendMessage", { chat_id: chatId, text: promptText, parse_mode: "HTML", disable_web_page_preview: true, reply_markup: { force_reply: true, selective: true } }).catch(() => null);
  cleanInputPending.set(`${chatId}:${userId}`, { kind, at: Date.now(), promptMsgId: (res && res.message_id) || null, builderMsgId });
}
// Consume a typed value for a pending clean-input, then DELETE the user's message + the prompt so the
// chat stays clean (message deletion in groups needs the bot's Delete-messages admin right; best-effort).
async function applyCleanInput(message, userId) {
  const chatId = message.chat.id;
  const key = `${chatId}:${userId}`;
  const pend = cleanInputPending.get(key);
  if (!pend) return false;
  if (Date.now() - pend.at > 180000) { cleanInputPending.delete(key); return false; }
  const raw = String(message.text || "").trim();
  if (!raw || raw.startsWith("/")) return false;
  const cleanup = () => {
    telegram("deleteMessage", { chat_id: chatId, message_id: message.message_id }).catch(() => {});
    if (pend.promptMsgId) telegram("deleteMessage", { chat_id: chatId, message_id: pend.promptMsgId }).catch(() => {});
  };
  const reprompt = async (hint) => {
    cleanup();
    const res = await telegram("sendMessage", { chat_id: chatId, text: hint, parse_mode: "HTML", reply_markup: { force_reply: true, selective: true } }).catch(() => null);
    cleanInputPending.set(key, { ...pend, at: Date.now(), promptMsgId: (res && res.message_id) || null });
  };
  if (pend.kind === "lo_mc" || pend.kind === "lo_amt") {
    const draft = limitDraft.get(key);
    if (!draft) { cleanInputPending.delete(key); cleanup(); return true; }
    if (pend.kind === "lo_mc") {
      const mc = parseMcInput(raw);
      if (!mc) { await reprompt("🎯 Couldn't read that. Reply with a market cap like <code>30k</code>, <code>250k</code>, or <code>1.2m</code>."); return true; }
      draft.triggerMc = mc;
    } else {
      const n = Number(raw.replace(/[^0-9.]/g, ""));
      if (!Number.isFinite(n) || n <= 0) { await reprompt(draft.side === "buy" ? "💰 Couldn't read that. Reply with a SOL amount like <code>0.5</code>." : "💰 Couldn't read that. Reply with a sell % like <code>100</code>."); return true; }
      draft.amount = draft.side === "buy" ? n : Math.min(100, Math.max(1, Math.round(n)));
    }
    cleanInputPending.delete(key);
    cleanup();
    await renderLimitBuilder(chatId, userId);
    return true;
  }
  if (pend.kind === "pe_amt") {
    const n = Number(raw.replace(/[^0-9.]/g, ""));
    if (!Number.isFinite(n) || n <= 0) { await reprompt("💰 Couldn't read that. Reply with a SOL amount like <code>0.5</code>."); return true; }
    cleanInputPending.delete(key);
    cleanup();
    await setBuyPref(userId, "amount", n);
    if (pend.builderMsgId) {
      const v = presetEditorView(userBuyPrefs(await readBuyPrefs(), userId), userId);
      await telegram("editMessageText", { chat_id: chatId, message_id: pend.builderMsgId, text: v.text, parse_mode: "HTML", disable_web_page_preview: true, reply_markup: v.markup }).catch(() => {});
    }
    return true;
  }
  cleanInputPending.delete(key);
  return true;
}
// ---- 🎯 Auto-TP ladder: one tap after a buy arms a set of limit-sell rungs at multiples of entry MC ----
const TP_LADDERS = {
  balanced: { label: "Balanced — 2× / 4×", rungs: [{ mult: 2, pct: 50 }, { mult: 4, pct: 50 }] },
  runner:   { label: "Runner — 2× / 5× / 10×", rungs: [{ mult: 2, pct: 34 }, { mult: 5, pct: 33 }, { mult: 10, pct: 33 }] },
  safe:     { label: "Safe — 1.5× / 3×", rungs: [{ mult: 1.5, pct: 50 }, { mult: 3, pct: 50 }] }
};
async function showTpLadder(userId, mint, messageId = null) {
  const info = await alphaRadarFetchMc(mint).catch(() => null);
  const mc = info && info.mc > 0 ? info.mc : 0;
  const sym = (info && info.sym) || shortMint(mint);
  const text = [
    `🎯 <b>Auto-TP ladder</b> — ${escapeTelegramHtml(sym)}`,
    mc ? `From here (${fmtMc(mc)}), I'll arm limit sells that auto-fire as it climbs:` : "Market cap unavailable right now — try the ⏰ Limit menu to set an exact target.",
    mc ? `• <b>Balanced</b>: sell 50% at ${fmtMc(mc * 2)}, 50% at ${fmtMc(mc * 4)}` : "",
    mc ? `• <b>Runner</b>: 34% at ${fmtMc(mc * 2)}, 33% at ${fmtMc(mc * 5)}, 33% at ${fmtMc(mc * 10)}` : "",
    mc ? `• <b>Safe</b>: 50% at ${fmtMc(mc * 1.5)}, 50% at ${fmtMc(mc * 3)}` : ""
  ].filter(Boolean).join("\n");
  const rows = mc ? [
    [{ text: "🎯 Balanced 2×/4×", callback_data: `tp:set:balanced:${mint}` }],
    [{ text: "🚀 Runner 2×/5×/10×", callback_data: `tp:set:runner:${mint}` }],
    [{ text: "🛡 Safe 1.5×/3×", callback_data: `tp:set:safe:${mint}` }],
    [{ text: "⏰ Custom limit", callback_data: `lo:new:${mint}` }, { text: "🏠 Main Menu", callback_data: "main_menu" }]
  ] : [[{ text: "⏰ Limit menu", callback_data: `lo:new:${mint}` }, { text: "🏠 Main Menu", callback_data: "main_menu" }]];
  if (messageId) await telegram("editMessageText", { chat_id: userId, message_id: messageId, text, parse_mode: "HTML", disable_web_page_preview: true, reply_markup: { inline_keyboard: rows } }).catch(() => {});
  else await sayHtml(userId, text, { inline_keyboard: rows });
}
async function handleTpCallback(query, userId) {
  const data = String(query?.data || ""); if (!data.startsWith("tp:")) return false;
  const messageId = query.message?.message_id;
  const ack = (t, alert) => telegram("answerCallbackQuery", { callback_query_id: query.id, ...(t ? { text: t, show_alert: Boolean(alert) } : {}) }).catch(() => {});
  let m = data.match(/^tp:([1-9A-HJ-NP-Za-km-z]{32,44})$/);
  if (m) { await ack(); await showTpLadder(userId, m[1], isPrivateChat(query.message?.chat) ? messageId : null); return true; }
  m = data.match(/^tp:set:(balanced|runner|safe):([1-9A-HJ-NP-Za-km-z]{32,44})$/);
  if (m) {
    const ladder = TP_LADDERS[m[1]], mint = m[2];
    if (!walletsForOwner(await readWalletStore(), userId).length) { await ack("Make a free SlimeWire wallet first — DM me /start.", true); return true; }
    const info = await alphaRadarFetchMc(mint).catch(() => null);
    const mc = info && info.mc > 0 ? info.mc : 0;
    if (!mc) { await ack("Market cap unavailable — use ⏰ Custom limit.", true); return true; }
    const slippageBps = userBuyPrefs(await readBuyPrefs(), userId).slippageBps;
    const armed = [];
    for (const rung of ladder.rungs) {
      const triggerMc = Math.round(mc * rung.mult);
      const res = await addLimitOrder(userId, { side: "sell", mint, sym: (info && info.sym) || "", refMc: mc, triggerMc, dir: ">=", pct: rung.pct, slippageBps });
      if (res.ok) armed.push(`sell ${rung.pct}% at ${fmtMc(triggerMc)} (${rung.mult}×)`);
    }
    await ack(armed.length ? `🎯 Armed ${armed.length} take-profits!` : "Couldn't arm — maybe you hit the order cap.", true);
    if (armed.length) {
      await sayHtml(userId, [
        `🎯 <b>Auto-TP armed</b> — ${escapeTelegramHtml((info && info.sym) || shortMint(mint))}`,
        ...armed.map((a) => `• ${a}`),
        "",
        "<i>Each fires automatically as the market cap climbs. Manage or cancel under ⏰ My Orders.</i>"
      ].join("\n"), { inline_keyboard: [[{ text: "⏰ My Orders", callback_data: "orders_hub" }, { text: "🏠 Main Menu", callback_data: "main_menu" }]] }).catch(() => {});
    }
    return true;
  }
  await ack();
  return true;
}

// Typed "<targetMC> <amount>" for a pending limit order. Returns true when it consumed the message.
async function applyLimitOrderInput(message, userId) {
  const pend = limitOrderPending.get(String(userId));
  if (!pend) return false;
  if (Date.now() - pend.at > 180000) { limitOrderPending.delete(String(userId)); return false; }
  const raw = String(message.text || "").trim();
  if (!raw || raw.startsWith("/")) return false;
  const parts = raw.split(/[\s,]+/).filter(Boolean);
  const isAlert = pend.side === "alert";
  if (!isAlert && parts.length < 2) { await say(message.chat.id, "Send two values: target MC then amount, e.g. `30k 0.5`."); return true; }
  const triggerMc = parseMcInput(parts[0]);
  if (!triggerMc) { await say(message.chat.id, "Couldn't read the target MC. Try like `30k`, `250k`, or `1.2m`."); return true; }
  const amtNum = isAlert ? 0 : Number(String(parts[1]).replace(/[^0-9.]/g, ""));
  if (!isAlert && (!Number.isFinite(amtNum) || amtNum <= 0)) { await say(message.chat.id, pend.side === "buy" ? "Couldn't read the SOL amount, e.g. 0.5" : "Couldn't read the sell %, e.g. 100"); return true; }
  limitOrderPending.delete(String(userId));
  const slippageBps = userBuyPrefs(await readBuyPrefs(), userId).slippageBps;
  const ref = pend.refMc || 0;
  const dir = triggerMc >= ref ? ">=" : "<=";   // ref 0 → ">=" (treat as breakout/TP; harmless)
  const spec = { side: pend.side, mint: pend.mint, sym: pend.sym, refMc: ref, triggerMc, dir, slippageBps };
  if (pend.side === "buy") {
    const sol = Math.min(LIMIT_MAX_SOL, Math.max(LIMIT_MIN_SOL, amtNum));
    spec.amountSol = sol;
  } else if (pend.side === "sell") {
    spec.pct = Math.min(100, Math.max(1, Math.round(amtNum)));
  }
  const res = await addLimitOrder(userId, spec);
  if (!res.ok) { await sayHtml(message.chat.id, `⏰ Couldn't arm it: ${escapeTelegramHtml(res.why || "try again")}.`); return true; }
  const o = res.order;
  await sayHtml(message.chat.id, [
    "⏰✅ <b>Order armed.</b>",
    limitOrderLine(o),
    "",
    `<i>Fires automatically when ${escapeTelegramHtml(o.sym || shortMint(o.mint))} crosses ${fmtMc(o.triggerMc)}. I watch it for you — expires in 14 days.</i>`
  ].join("\n"), { inline_keyboard: [[{ text: "⏰ My Orders", callback_data: "orders_hub" }, { text: "🏠 Main Menu", callback_data: "main_menu" }]] }).catch(() => {});
  return true;
}

// Caller footer for the scan card: who FIRST called this CA in this channel, when, and how
// it's done since the call (live X / %, plus peak). Also refreshes the call's last/peak MC so
// the caller-intel warehouse stays current on every look/refresh. Channel-only (no record in
// DMs). Returns "" when there's no recorded call (e.g. a DM or a never-called coin).
async function buildScanCallerFooter(chatId, mint, currentMc, message) {
  try {
    if (!mint) return "";
    const store = await readTelegramCalls();
    if (!store.calls) return "";
    const mc = Number(currentMc) || 0;
    // Freshen THIS chat's record if it exists (per-channel warehouse stays current).
    let here = chatId ? store.calls[`${chatId}:${mint}`] : null;
    // SELF-SEED: if this is a channel look and nobody has recorded a call for THIS chat yet, record
    // it now so the footer appears from the very first look (and any later Refresh keeps tracking it).
    // Belt-and-suspenders for paths that build the footer without recording first.
    if (!here && message && !isPrivateChat(message.chat)) {
      here = await recordTelegramCall(message, mint, mc).catch(() => null);
    }
    if (here && mc > 0) { here.lastMc = mc; here.lastAt = Date.now(); if (mc > (here.peakMc || 0)) here.peakMc = mc; scheduleTelegramCallsFlush(); }
    // The footer shows the EARLIEST caller of this mint ANYWHERE in the warehouse (not just this
    // chat) — so it appears in DM and on $ticker looks too, surfacing who really called it first
    // and where. Also track the best peak across every channel that called it.
    let rec = null, bestPeak = 0;
    for (const k in store.calls) {
      const r = store.calls[k];
      if (!r || r.mint !== mint) continue;
      if (Number(r.peakMc) > bestPeak) bestPeak = Number(r.peakMc) || 0;
      if (!rec || (Number(r.firstAt) || 0) < (Number(rec.firstAt) || 0)) rec = r;
    }
    if (!rec) return "";
    const entry = Number(rec.entryMc) || 0;
    const ago = alphaAgeLabel(Math.max(0, Date.now() - Number(rec.firstAt || Date.now())));
    // Scanner-bot footer the user asked for: WHO first called it · the MC then · the move since
    // (green/red %), plus the peak if it ran. e.g. "📣 First called by @x at $12k · 🟢 +340% · 2h ago".
    const atMc = entry > 0 ? ` at ${scanFmtMoney(entry)}` : "";
    // Live MC to measure the move: prefer the current scan's MC, else the freshest stored value.
    const liveMc = mc > 0 ? mc : (Number(rec.lastMc) || 0);
    let bracket = "";
    if (entry > 0 && liveMc > 0) {
      const pct = Math.round((liveMc / entry - 1) * 100);
      bracket = ` · ${pct >= 0 ? "🟢" : "🔴"} ${pct >= 0 ? "+" : ""}${pct}%`;
    }
    const peakX = entry > 0 ? bestPeak / entry : 0;
    const peakStr = peakX >= 2 ? ` · peak +${Math.round((peakX - 1) * 100)}%` : "";
    // Name the room it was first called in when that's somewhere other than here (informative in DM).
    const sameChat = chatId && String(rec.chatId || "") === String(chatId);
    const where = !sameChat && rec.chatTitle ? ` in ${escapeTelegramHtml(String(rec.chatTitle).slice(0, 28))}` : "";
    return `📣 First called by <b>${escapeTelegramHtml(rec.callerName || "someone")}</b>${where}${atMc}${bracket}${peakStr} · ${ago} ago`;
  } catch { return ""; }
}

// Group /flex and /pnl: render the CALL's performance — credited to the FIRST caller, measured from
// the call's entry MC (not a personal buy/sell). This is "flex/pnl based off first call and caller".
// NEVER dead-ends in a group: if nobody has called this coin yet, it RECORDS the call right now
// (seeding the caller-intel warehouse so the footer + future /pnl track it) and posts a live-stats
// card from the coin's real DexScreener momentum + ATH — so /pnl <CA> always answers with something
// useful instead of the old "No PnL data... only works for buys/sells made from this bot." dead-end.
// Returns true whenever a card was posted (effectively always, for a valid mint with a live read).
async function postCallFlexCard(chatId, mint, message) {
  try {
    // Always pull the live read first — needed for both the recorded-call card and the seed/fallback.
    let curMc = 0, sym = "", meta = null, ath = null;
    try {
      const scan = await gatherSlimeScan(mint);
      curMc = Number(scan?.meta?.marketCap || scan?.meta?.fdv || scan?.bonding?.marketCap || 0);
      sym = scan?.meta?.symbol || scan?.bonding?.symbol || "";
      meta = scan?.meta || null; ath = scan?.ath || null;
    } catch {}

    let rec = null, bestPeak = 0;
    const store = await readTelegramCalls();
    for (const k in (store.calls || {})) {
      const r = store.calls[k];
      if (!r || r.mint !== mint) continue;
      if (Number(r.peakMc) > bestPeak) bestPeak = Number(r.peakMc) || 0;
      if (!rec || (Number(r.firstAt) || 0) < (Number(rec.firstAt) || 0)) rec = r;
    }

    // No call on record yet → SEED it now (so the caller-intel warehouse + footer start tracking
    // from this moment) and re-read so the rest of the function treats it like any recorded call.
    if (!rec && message && !isPrivateChat(message.chat)) {
      rec = await recordTelegramCall(message, mint, curMc).catch(() => null);
      if (rec) bestPeak = Math.max(bestPeak, Number(rec.peakMc) || 0);
    }

    // Still no record (e.g. couldn't seed) → post an honest live-momentum card from DexScreener
    // so the command never dead-ends. Real recent change + ATH, credited to "just spotted".
    if (!rec) {
      const ch24 = meta?.priceChange?.h24, ch1 = meta?.priceChange?.h1;
      const live = curMc > 0 ? curMc : Number(meta?.fdv || meta?.marketCap || 0);
      const lines = [
        `🟢 <b>$${escapeTelegramHtml(sym || shortMint(mint))}</b>${live > 0 ? ` — now ${scanFmtMoney(live)}` : ""}`,
        `📣 First spotted here — tracking from now`,
        (ch24 != null || ch1 != null) ? `📊 24h <b>${scanFmtPct(ch24)}</b>${ch1 != null ? ` · 1h <b>${scanFmtPct(ch1)}</b>` : ""}` : null,
        (ath && Number(ath.mc) > 0 && live > 0 && Number(ath.mc) > live * 1.05) ? `🏔 ATH ${scanFmtMoney(ath.mc)} <i>(${Math.round((live / ath.mc - 1) * 100)}% from peak)</i>` : null,
        `⚡ <a href="https://slimewire.org/t?ca=${mint}">Trade $${escapeTelegramHtml(sym || "it")} on SlimeWire</a>`
      ].filter(Boolean);
      await sayHtml(chatId, lines.join("\n"), slimeScanKeyboard(mint));
      return true;
    }

    const entry = Number(rec.entryMc) || 0;
    const live = curMc > 0 ? curMc : (Number(rec.lastMc) || 0);
    if (live > 0) { rec.lastMc = live; if (live > (rec.peakMc || 0)) { rec.peakMc = live; bestPeak = Math.max(bestPeak, live); } scheduleTelegramCallsFlush(); }
    const pct = entry > 0 && live > 0 ? Math.round((live / entry - 1) * 100) : 0;
    const x = entry > 0 && live > 0 ? live / entry : 0;
    const peakPct = entry > 0 && bestPeak > 0 ? Math.round((bestPeak / entry - 1) * 100) : 0;
    const up = pct >= 0;
    const fresh = (Date.now() - Number(rec.firstAt || Date.now())) < 90_000; // seeded in the last ~90s
    const ago = alphaAgeLabel(Math.max(0, Date.now() - Number(rec.firstAt || Date.now())));
    const lines = [
      `${up ? "🟢" : "🔴"} <b>$${escapeTelegramHtml(sym || shortMint(mint))} — the call</b>`,
      fresh
        ? `📣 First spotted here — tracking from now`
        : `📣 Called by <b>${escapeTelegramHtml(rec.callerName || "someone")}</b>${rec.chatTitle ? ` in ${escapeTelegramHtml(String(rec.chatTitle).slice(0, 28))}` : ""} · ${ago} ago`,
      entry > 0 ? `🎯 Entry ${scanFmtMoney(entry)} → ${scanFmtMoney(live)}` : `now ${scanFmtMoney(live)}`,
      fresh && meta?.priceChange
        ? `📊 24h <b>${scanFmtPct(meta.priceChange.h24)}</b>${meta.priceChange.h1 != null ? ` · 1h <b>${scanFmtPct(meta.priceChange.h1)}</b>` : ""}`
        : `${up ? "📈" : "📉"} <b>${up ? "+" : ""}${pct}%</b>${x >= 2 ? ` · <b>${x.toFixed(1)}x</b>` : ""}${peakPct >= pct + 25 ? ` · peak +${peakPct}%` : ""}`,
      `⚡ <a href="https://slimewire.org/t?ca=${mint}">Trade $${escapeTelegramHtml(sym || "it")} on SlimeWire</a>`
    ].filter(Boolean);
    await sayHtml(chatId, lines.join("\n"), slimeScanKeyboard(mint));
    return true;
  } catch { return false; }
}

// SCAN BOT — PnL FLEX CARDS. When someone in a group brags a win that names a coin ("+340% on
// $OGRE 🚀", "just did 5x on <CA>"), reply with OUR rotating SlimeWire slime-card (the same
// 15-background design the app + site rotate through) showing that coin's CALL performance — so a
// competitor's screenshot never owns the moment in your chat. Renders in receipt mode (no personal
// round-trip P&L needed — it's the call's move from first-seen MC). Falls back to the text card.
async function sendCallFlexImageCard(chatId, mint, message) {
  try {
    let curMc = 0, sym = "", name = "", imageUrl = "";
    try {
      const scan = await gatherSlimeScan(mint);
      curMc = Number(scan?.meta?.marketCap || scan?.meta?.fdv || scan?.bonding?.marketCap || 0);
      sym = scan?.meta?.symbol || scan?.bonding?.symbol || "";
      name = scan?.meta?.name || scan?.bonding?.name || "";
      imageUrl = scan?.meta?.imageUrl || scan?.meta?.avatarUrl || "";
    } catch {}
    // Find or seed the call (entry MC) so the % is honest — measured from first-seen, not a made-up base.
    let rec = null, bestPeak = 0;
    const store = await readTelegramCalls();
    for (const k in (store.calls || {})) {
      const r = store.calls[k];
      if (!r || r.mint !== mint) continue;
      if (Number(r.peakMc) > bestPeak) bestPeak = Number(r.peakMc) || 0;
      if (!rec || (Number(r.firstAt) || 0) < (Number(rec.firstAt) || 0)) rec = r;
    }
    if (!rec && message) rec = await recordTelegramCall(message, mint, curMc).catch(() => null);
    const entry = rec ? Number(rec.entryMc) || 0 : 0;
    const live = curMc > 0 ? curMc : (rec ? Number(rec.lastMc) || 0 : 0);
    if (rec && live > 0) { rec.lastMc = live; if (live > (rec.peakMc || 0)) rec.peakMc = live; bestPeak = Math.max(bestPeak, live); scheduleTelegramCallsFlush(); }
    // Need a real entry + move to render a meaningful flex; otherwise fall back to the honest text card.
    if (!(entry > 0 && live > 0)) return await postCallFlexCard(chatId, mint, message);
    const gainPct = Math.round((live / entry - 1) * 100);
    const x = live / entry;
    const win = gainPct >= 0;
    const fresh = (Date.now() - Number(rec.firstAt || Date.now())) < 90_000;
    const ago = alphaAgeLabel(Math.max(0, Date.now() - Number(rec.firstAt || Date.now())));
    const png = await renderSlimeCard({
      mint, symbol: sym || shortMint(mint), name: name || "SlimeWire", imageUrl,
      loss: !win, receipt: true,
      headline: win ? `${Math.round(x * 10) / 10}X` : `-${Math.abs(gainPct)}%`,
      lines: [
        win ? `Called +${gainPct}%` : `Down ${gainPct}%`,
        entry > 0 ? `Entry ${formatUsdCompact(entry)} -> ${formatUsdCompact(live)}` : "",
        fresh ? "First spotted here" : `Called by ${String(rec.callerName || "someone").slice(0, 20)} · ${ago} ago`
      ]
    }).catch(() => null);
    if (!png) return await postCallFlexCard(chatId, mint, message);
    const cap = `${win ? "🟢" : "🔴"} <b>$${escapeTelegramHtml(sym || shortMint(mint))} — the call</b> ${win ? `<b>+${gainPct}%</b>` : `${gainPct}%`}\n⚡ <a href="https://www.slimewire.org/t?ca=${mint}">Trade it on SlimeWire</a>`;
    await sendPhoto(chatId, `flex-${sanitizeFilenamePart(sym || mint)}.png`, png, cap, slimeScanKeyboard(mint), "HTML");
    return true;
  } catch { try { return await postCallFlexCard(chatId, mint, message); } catch { return false; } }
}

// 📸 Personal win-flex — a shareable card of YOUR realized PnL on a coin (from your own trades, not a
// channel call). Fires from a button on the sell receipt when you're up. Viral loop: forward it, it
// links back to SlimeWire. Honest — the numbers come straight from your recorded buys/sells.
async function sendUserWinFlex(userId, mint) {
  try {
    const pnl = await realizedPnlForMint(userId, mint);
    if (!pnl || !pnl.hasBuys) { await sayHtml(userId, "No recorded PnL on this coin yet — buy/sell it through the bot first."); return true; }
    const info = await alphaRadarFetchMc(mint).catch(() => null);
    const sym = (info && info.sym) || shortMint(mint);
    const win = pnl.net >= 0n;
    const spentSol = Number(lamportsBigToSol(pnl.spent)) || 0;
    const recvSol = Number(lamportsBigToSol(pnl.received)) || 0;
    const x = spentSol > 0 ? recvSol / spentSol : 0;
    const png = await renderSlimeCard({
      mint, symbol: sym, name: "SlimeWire", imageUrl: "",
      loss: !win, receipt: true,
      headline: win ? (x >= 2 ? `${Math.round(x * 10) / 10}X` : `+${pnl.pct.toFixed(0)}%`) : `${pnl.pct.toFixed(0)}%`,
      lines: [
        win ? `Banked +◎${lamportsBigToSol(pnl.net)}` : `Down ◎${lamportsBigToSol(-pnl.net)}`,
        `on $${sym}`,
        "traded on @SlimeWiredBot"
      ]
    }).catch(() => null);
    const lx = slimewireTokenLinks(mint);
    if (!png) {
      await sayHtml(userId, `${win ? "🟢" : "🔴"} <b>$${escapeTelegramHtml(sym)}</b> — realized ${win ? "+" : ""}◎${lamportsBigToSol(pnl.net)} (${win ? "+" : ""}${pnl.pct.toFixed(0)}%).\n⚡ <a href="${lx.site}">Trade it on SlimeWire</a>`);
      return true;
    }
    const cap = `${win ? "🟢" : "🔴"} <b>$${escapeTelegramHtml(sym)}</b> — I ${win ? "banked" : "took"} <b>${win ? "+" : ""}◎${lamportsBigToSol(pnl.net)}</b> (${win ? "+" : ""}${pnl.pct.toFixed(0)}%) on @SlimeWiredBot.\n⚡ <a href="${lx.site}">Trade it here →</a>`;
    await sendPhoto(userId, `flex-${sanitizeFilenamePart(sym)}.png`, png, cap, { inline_keyboard: [[{ text: "⚡ Trade on SlimeWire", url: lx.site }]] }, "HTML");
    return true;
  } catch { return false; }
}
async function handleWinFlexCallback(query, userId) {
  const data = String(query?.data || ""); if (!data.startsWith("wf:")) return false;
  const ack = (t) => telegram("answerCallbackQuery", { callback_query_id: query.id, ...(t ? { text: t } : {}) }).catch(() => {});
  const m = data.match(/^wf:([1-9A-HJ-NP-Za-km-z]{32,44})$/);
  if (!m) { await ack(); return true; }
  await ack("📸 Building your flex card…");
  await sendUserWinFlex(userId, m[1]);
  return true;
}

// Detect a "PnL flex / brag" that names a coin, so the scan bot can answer with a SlimeWire card.
// Returns { mint } (a pasted CA wins), { ticker } (first $cashtag), or null. Deliberately tight so it
// only fires on a real win-brag — a numeric gain (+NN% / NNx) OR profit words — that also names a coin.
function detectFlexBragMint(raw) {
  const text = String(raw || "").trim();
  if (text.length < 4 || text.length > 400) return null;
  if (text.startsWith("/")) return null;
  const gain = /(?:^|[\s(+])\+?\d{2,}\s?%/.test(text)                       // +250% or 250%
    || /(?:^|[\s(x])\d{1,3}(?:\.\d+)?\s?x\b/i.test(text)                     // 5x, 12.5x
    || /\b(pnl|profit|profits|gains?|printed|bagged|banger|moon(?:ed|ing|shot)?|ath)\b/i.test(text);
  if (!gain) return null;
  // A pasted contract address anywhere beats a ticker (exact + unambiguous).
  for (const tok of text.split(/[\s,]+/)) {
    const clean = tok.replace(/^\$/, "").replace(/[.,!?)]+$/, "");
    if (isLikelySolMint(clean)) return { mint: clean };
  }
  const tag = /\$([A-Za-z][A-Za-z0-9._]{1,19})\b/.exec(text);
  if (tag) return { ticker: tag[1] };
  return null;
}

function formatSlimeScanCard({ mint, meta, rug, shield, bonding, best, dexPaid, supply, callerLine, ath }) {
  const esc = escapeTelegramHtml;
  const links = slimewireTokenLinks(mint);
  const dex = dexScreenerUrl(mint);
  const sym = (meta?.symbol || bonding?.symbol || shortMint(mint)).slice(0, 18);
  const name = (meta?.name || bonding?.name || sym).slice(0, 40);
  const dexId = meta?.dexId || (mint.endsWith("pump") ? "pump" : "sol");

  // header status FIRST — it also decides metadata PRECEDENCE: a coin still ON the bonding
  // curve reads Pump-first (live + accurate there); a migrated coin reads Dex-first (Pump
  // metadata freezes at migration). This is the "pump coins use Pump first" priority.
  const stats = scanMarketStatsFromSources({ meta, bonding, best, rug, supply, mint });
  const bondPct = firstMeaningfulNumber(bonding?.bondingProgressPct);
  const onCurve = Boolean(stats.onCurve || (bonding && bondPct != null && !meta?.graduated));
  const pick = (pumpVal, dexVal) => onCurve ? firstMeaningfulNumber(pumpVal, dexVal) : firstMeaningfulNumber(dexVal, pumpVal);
  const mc = stats.mc;
  const liq = stats.liq;
  const { vol, ch24, ch1, buys1, sells1 } = stats;
  const price = scanFmtPriceSub(pick(Number(bonding?.priceUsd), Number(best?.priceUsd || meta?.priceUsd)) || (mc && supply ? mc / supply : 0));
  // ATH (real, from SolanaTracker) — only shown when genuinely at/above the current MC.
  const showAth = ath && Number(ath.mc) > 0 && Number(ath.mc) >= mc * 0.999;
  let athTail = "";
  if (showAth) {
    const fromAth = mc > 0 ? Math.round((mc / ath.mc - 1) * 100) : null;
    const aAge = ath.at ? alphaAgeLabel(Math.max(0, Date.now() - Number(ath.at))) : "";
    const parts = [fromAth != null ? `${fromAth}%` : "", aAge].filter(Boolean).join(" / ");
    athTail = parts ? ` <i>(${parts})</i>` : "";
  }

  const headStatus = onCurve
    ? `(Pump @ ${Math.max(0, Math.min(100, Math.round(bondPct)))}%)`
    : (meta?.graduated ? "(Migrated)" : "");
  // AGE + holders come from the aggregator now (all sources + sticky cache) so they always populate.
  const createdMs = Number(stats.createdAt) || 0;
  const headerTail = [`#SOL${headStatus ? ` ${headStatus}` : ""}`, `🌱 ${scanFmtAge(createdMs)}`]
    .concat(stats.holders ? [`∞ ${scanFmtSupply(stats.holders)}`] : [])
    .join(" | ");

  // socials: REAL links only — X, website, Telegram, Pump.fun. (Dropped the generic "about";
  // show only what the token actually has, with a chart/Pump link always present.)
  // Socials: prefer DexScreener, fall back to the creator-entered pump.fun links (bonding). pump has
  // these the instant a coin launches — long before Dex lists it — so a fresh coin shows real 𝕏/TG/Web
  // instead of just the search fallback. (This was reading `meta` only → empty socials on new coins.)
  const twUrl = meta?.twitterUrl || bonding?.twitterUrl;
  const webUrl = meta?.websiteUrl || bonding?.websiteUrl;
  const tgUrl = meta?.telegramUrl || bonding?.telegramUrl;
  const socialBits = [];
  socialBits.push(`<a href="${esc(twUrl || `https://x.com/search?q=${encodeURIComponent(mint)}&f=live`)}">𝕏</a>`);
  if (webUrl) socialBits.push(`<a href="${esc(webUrl)}">🌐 Web</a>`);
  if (tgUrl) socialBits.push(`<a href="${esc(tgUrl)}">✈️ TG</a>`);
  socialBits.push(`<a href="https://pump.fun/coin/${mint}">🚀 Pump</a>`);

  // security (RugCheck full)
  const light = (b, onYes) => b === true ? (onYes ? "🟢" : "🔴") : b === false ? (onYes ? "🔴" : "🟢") : "⚪";
  const top10 = rug?.top10Pct != null ? `${Math.round(rug.top10Pct)}%` : "n/a";
  const holders = stats.holders ? ` | ${stats.holders} (total)` : "";
  const th = rug?.topHolders?.length ? rug.topHolders.map((p) => (Number(p) || 0).toFixed(1)).join("|") : "n/a";
  const devSold = rug ? `${light(rug.devSold, false)} ${rug.devSold === true ? "Yes" : rug.devSold === false ? "No" : "n/a"}` : "⚪ n/a";
  const dexPaidStr = `${light(dexPaid, true)} ${dexPaid === true ? "Paid" : dexPaid === false ? "Unpaid" : "n/a"}`;
  // Authorities: only render 🟢 none (revoked) when we DEFINITELY read the state (RugCheck report or an
  // on-chain mint decode). If neither resolved, show n/a rather than a false "revoked".
  const authKnown = Boolean(rug && rug.authoritiesKnown);
  const mintAuth = authKnown ? (rug.mintAuthority ? "🔴 active" : "🟢 none") : (rug && rug.mintAuthority ? "🔴 active" : "⚪ n/a");
  const freezeAuth = authKnown ? (rug.freezeAuthority ? "🔴 active" : "🟢 none") : (rug && rug.freezeAuthority ? "🔴 active" : "⚪ n/a");

  const lines = [
    `💊 <b>${esc(name)} ($${esc(sym)})</b>`,
    `├ <code>${esc(mint)}</code>`,
    `└ ${headerTail}`,
    "",
    `📊 <b>Stats</b>`,
    `├ USD  <b>${price}</b> (${scanFmtPct(ch24)})`,
    `├ MC   <b>${scanFmtMoney(mc)}</b>`,
    `├ Vol  <b>${scanFmtMoney(vol.value)}</b>${vol.label ? ` <i>${vol.label}</i>` : ""}`,
    `├ LP   <b>${scanFmtMoney(liq)}</b>`,
    `├ Sup  <b>${supply ? scanFmtSupply(supply) : "n/a"}</b>`,
    `${showAth ? "├" : "└"} 1H   <b>${scanFmtPct(ch1)}</b>  🟢 ${buys1}  🔴 ${sells1}`,
    showAth ? `└ ATH  <b>${scanFmtMoney(ath.mc)}</b>${athTail}` : null,
    "",
    `🔗 <b>Socials</b>`,
    `└ ${socialBits.join(" • ")}`,
    "",
    `🔒 <b>Security</b>`,
    `├ Top 10   <b>${top10}</b>${holders}`,
    `├ TH       <b>${th}</b>`,
    `├ Dev Sold <b>${devSold}</b>`,
    `├ DEX Paid <b>${dexPaidStr}</b>`,
    `└ Mint <b>${mintAuth}</b> | Freeze <b>${freezeAuth}</b>`,
    "",
    // CALLER INTEL: who first called it here, the MC then, the move since, and how long ago.
    callerLine || null,
    // Compact quick-links row (matches scanner-bot style) — SlimeWire chart first.
    `🔗 <a href="${links.site}">Chart</a> • <a href="${dex}">DS</a> • <a href="https://www.geckoterminal.com/solana/tokens/${mint}">GT</a> • <a href="https://rugcheck.xyz/tokens/${mint}">Rug</a> • <a href="https://solscan.io/token/${mint}">Sol</a> • <a href="${links.proof}">Proof</a>`,
    `<a href="https://www.slimewire.org">⚡ Powered by SlimeWire</a> — Quick Buy below`
  ].filter((l) => l != null); // keep intentional "" section separators; drop omitted (null) lines
  return lines.join("\n");
}

// /look <CA>: instant SlimeShield read with trade links - the group-native version of
// pasting a CA into Slime Scope.
async function handleTelegramLookCommand(chatId, message, argument, options = {}) {
  // One resolver for CA, Dex/Pump links, $tickers, bare scan tickers, and Robinhood Chain 0x contracts.
  const target = await resolveScanTargetFromText(argument).catch(() => null);
  const rhAddr = /^0x[0-9a-fA-F]{40}$/.test(String(target || "")) ? String(target) : "";
  if (rhAddr) { if (!options.skipCooldown && tgCommandOnCooldown(chatId, `look:${rhAddr.toLowerCase()}`, TG_LOOK_COOLDOWN_MS)) return; await sendRhScanCard(chatId, rhAddr, options); return; }
  const mint = isLikelySolMint(target) ? String(target) : "";
  if (!mint) {
    await say(chatId, "Usage: /look <token CA> — Solana mint OR Robinhood Chain 0x… address. I'll run a SlimeShield read with chart + quick-buy.");
    return;
  }
  // Deduplicate only the SAME token. A busy group may paste several different CAs within 20 seconds;
  // the old chat-wide cooldown silently discarded all but the first and looked like a broken scanner.
  if (!options.skipCooldown && tgCommandOnCooldown(chatId, `look:${mint.toLowerCase()}`, TG_LOOK_COOLDOWN_MS)) return;
  const tickerSymbol = String(options.tickerSymbol || extractCashtags(String(argument || ""))[0] || "").replace(/^\$+/, "").trim().toUpperCase();
  const keyboard = slimeScanKeyboard(mint, tickerSymbol);
  void telegram("sendChatAction", { chat_id: chatId, action: "typing" }).catch(() => {});
  // Clean OgreScanBot-style scan card: stats + audit + socials + a prefilled
  // "Buy on SlimeWire" button. The all-in-one funnel — scan in any channel, buy on the site.
  let scan = null;
  try {
    scan = await gatherSlimeScan(mint);
  } catch {
    // fall through to the degraded reply below
  }
  // CALLER INTELLIGENCE: record this channel "call" with its entry MC, then show who FIRST
  // called it here + how it's done since (channel-only; the footer updates on every refresh).
  const inChannel = Boolean(message && message.chat && !isPrivateChat(message.chat));
  const curMc = Number(scan?.meta?.marketCap || scan?.meta?.fdv || scan?.bonding?.marketCap || 0);
  if (inChannel) await recordTelegramCall(message, mint, curMc).catch(() => {});
  // Footer is built ALWAYS now (DM + $ticker too): buildScanCallerFooter looks up the earliest
  // caller of this mint across the whole warehouse, so it surfaces who called it first even when
  // this exact chat never did. Empty only when nobody anywhere has called the coin.
  const callerLine = await buildScanCallerFooter(message?.chat?.id, mint, curMc, message).catch(() => "");
  const matchLine = tickerTruthLine(tickerSymbol, mint);
  const scanContextLine = [String(options.contextHtml || "").trim(), matchLine, callerLine].filter(Boolean).join("\n");
  let text = null;
  if (scan && (scan.meta || scan.bonding || scan.shield || scan.rug || scan.onchain)) {
    try { text = formatSlimeScanCard({ mint, ...scan, callerLine: scanContextLine }); } catch { text = null; }
  }
  if (!text) {
    await sayHtml(chatId, `Could not pull a clean read on <code>${escapeTelegramHtml(mint)}</code> right now. Links below.`, keyboard);
    return;
  }
  // Picture at the top: token image from Dexscreener, falling back to pump.fun metadata.
  // Caption carries the full card. If the image fails (or is missing), send text only.
  // Telegram's 1024 caption limit applies to the VISIBLE text (after entity parsing), not the
  // raw HTML — the long href URLs don't count. Measure visible length so the richer card
  // (ATH + quick-links + caller line) still ships WITH the image at the top, not text-only.
  const captionVisibleLen = text.replace(/<[^>]+>/g, "").length;
  if (captionVisibleLen <= 1024) {
    // Resolve a NORMALIZED PNG buffer (hardened fetch + fast IPFS gateways + sticky cache) and UPLOAD it, so
    // Telegram never has to reach a slow ipfs.io gateway or decode a webp itself — the old raw-URL sendPhoto
    // silently fell to text-only whenever Telegram couldn't fetch/decode the coin's image. URL is the fallback.
    const logoBuf = await scanFastTimeout(xCoinLogo(scan, mint), Number(process.env.TG_SCAN_LOGO_TIMEOUT_MS || 1_400), null);
    if (logoBuf) {
      try { await sendPhoto(chatId, "scan.png", logoBuf, text, keyboard, "HTML"); return; }
      catch { /* fall through to URL, then text */ }
    }
    const img = scanImageUrlFromScan(scan);
    if (img && /^true$/i.test(String(process.env.TG_SCAN_RAW_IMAGE_FALLBACK || ""))) {
      try { await telegram("sendPhoto", { chat_id: chatId, photo: img, caption: text, parse_mode: "HTML", reply_markup: keyboard }); return; }
      catch { /* fall back to the text card */ }
    }
  }
  await sayHtml(chatId, text, keyboard);
}

// /alpha: current top picks. Falls through scanner modes and finally the live feed so
// it ALWAYS returns candidates - an empty alpha reply teaches people to stop asking.
async function telegramAlphaRows(chatId) {
  const sources = [
    {
      label: "live trending · safety-screened",
      load: () => webLivePairs(`tg:${chatId}:trending`, "dexTrending", { sort: "best" })
    },
    {
      label: "live surging · safety-screened",
      load: () => webLivePairs(`tg:${chatId}:surging`, "gtSurging", { sort: "best" })
    },
    ...["safe", "fast", "moonshot"].map((mode) => ({
      label: `${mode} scanner · safety-screened`,
      load: () => webSniperScan(`tg:${chatId}:${mode}`, mode)
    }))
  ];
  for (const source of sources) {
    try {
      const feed = await source.load();
      const rows = await telegramSafetyScreenTrendingRows(feed?.rows || [], 3);
      if (rows.length) return { rows, source: source.label };
    } catch {
      // try the next independent source
    }
  }
  try {
    const feed = await webLivePairs(`tg:${chatId}`, "live", { sort: "best" });
    const rows = await telegramSafetyScreenTrendingRows(feed?.rows || [], 3);
    if (rows.length) return { rows, source: "live feed · safety-screened" };
  } catch {
    // degraded reply below
  }
  return { rows: [], source: "" };
}

function telegramRecommendationBlocked(row, shield) {
  return scanRecommendationBlocked(row, shield);
}

async function telegramSafetyScreenTrendingRows(rows, limit = 3) {
  const unique = [];
  const seen = new Set();
  for (const row of rows || []) {
    const mint = String(row?.tokenMint || "").trim();
    if (!mint || seen.has(mint) || hasHardBlockedLivePairRisk(row)) continue;
    seen.add(mint);
    unique.push(row);
    if (unique.length >= 12) break;
  }
  const checked = await Promise.all(unique.map(async (row) => {
    const shield = await scanFastTimeout(webSlimeShield(row.tokenMint), 1_800, null);
    return { row, shield };
  }));
  return checked
    .filter(({ row, shield }) => !telegramRecommendationBlocked(row, shield))
    .slice(0, Math.max(1, Number(limit) || 3))
    .map(({ row, shield }) => ({ ...row, telegramShield: shield }));
}

