  const recent = (kolCallFeedRate.get(key) || []).filter((at) => at > cutoff);
  if (recent.length >= maxPerHour) { kolCallFeedRate.set(key, recent); return false; }
  recent.push(now); kolCallFeedRate.set(key, recent); return true;
