  const xDmActivePollMs = xDmOfficial
    ? xDmIdlePollMs
    : Math.max(1_500, Number(process.env.X_DM_ACTIVE_POLL_MS || 2_000));
  let xDmLastActivityAt = 0;
  let xDmPollErrorStreak = 0;
