    var d = Math.floor(ms / 86400000), h = Math.floor(ms / 3600000) % 24, m = Math.floor(ms / 60000) % 60, s = Math.floor(ms / 1000) % 60;
    el.textContent = (d ? d + "d " : "") + h + "h " + m + "m " + s + "s";
    setTimeout(tick, 1000);
