// --- Degen Seasons v1: weekly bests computed from the call ledger. The Monday post
// crowns last week's winners in every armed chat - status is the retention engine.
function weeklySeasonStats(allCalls = [], allReceipts = []) {
  const weekAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
  const recent = allCalls.filter((call) => Date.parse(call.calledAt) > weekAgo);
  const wins = recent.filter((call) => call.outcome === "won");
  const bestCall = wins.sort((a, b) => (b.peakX || 0) - (a.peakX || 0))[0] || null;
  const fastest = wins
    .map((call) => ({ call, minutes: (Date.parse(call.resolvedAt) - Date.parse(call.calledAt)) / 60000 }))
    .filter((item) => Number.isFinite(item.minutes) && item.minutes > 0)
    .sort((a, b) => a.minutes - b.minutes)[0] || null;
  const lowestMc = wins.filter((call) => Number(call.entryMcUsd) > 0).sort((a, b) => a.entryMcUsd - b.entryMcUsd)[0] || null;
  const rugsFlagged = allReceipts.filter((item) => item.outcome === "rugged" && Date.parse(item.resolvedAt || "") > weekAgo).length;
  const pick = (call, extra = {}) => call ? { symbol: call.symbol, mint: call.mint, peakX: call.peakX || null, entryMcUsd: call.entryMcUsd || null, ...extra } : null;
  return {
    calls: recent.length,
    wins: wins.length,
    bestCall: pick(bestCall),
    fastestWin: fastest ? pick(fastest.call, { minutes: Math.round(fastest.minutes) }) : null,
    lowestMcWin: pick(lowestMc),
    rugsFlagged
  };
}

let lastSeasonPostWeek = "";
async function runWeeklySeasonPost() {
  const now = new Date();
  if (now.getUTCDay() !== 1 || now.getUTCHours() < 13) return; // Mondays, after 13:00 UTC
  const weekKey = `${now.getUTCFullYear()}-w${Math.floor((Date.now() / 86400000 + 4) / 7)}`;
  if (lastSeasonPostWeek === weekKey) return;
  const groupsStore = await readTelegramGroups();
  if (groupsStore.meta?.lastSeasonPostWeek === weekKey) {
    lastSeasonPostWeek = weekKey;
    return;
  }
  const calls = await readAlphaCalls().catch(() => ({ calls: [] }));
  const receipts = await readShieldReceipts().catch(() => ({ receipts: [] }));
  const week = weeklySeasonStats(calls.calls, receipts.receipts);
  if (!week.wins && !week.rugsFlagged) return;
  const lines = [
    `🏆 <b>Swamp Season - last week's winners</b>`,
    week.bestCall ? `Best call: $${escapeTelegramHtml(week.bestCall.symbol)} <b>${week.bestCall.peakX}x</b>` : "",
    week.fastestWin ? `Fastest 2x: $${escapeTelegramHtml(week.fastestWin.symbol)} in ${week.fastestWin.minutes} min` : "",
    week.lowestMcWin ? `Lowest MC winner: $${escapeTelegramHtml(week.lowestMcWin.symbol)} from ${formatUsdCompact(week.lowestMcWin.entryMcUsd)}` : "",
    week.rugsFlagged ? `🛡 ${week.rugsFlagged} rug(s) flagged before death` : "",
    `Full ledger: <a href="https://www.slimewire.org/proof">slimewire.org/proof</a> - new week starts now.`
  ].filter(Boolean);
  const text = lines.join("\n");
  for (const [chatId, group] of Object.entries(groupsStore.groups || {})) {
    if (group?.alerts) groupBridgeFor(chatId).announce("season", weekKey, text);
  }
  tgChannel.announce("season", weekKey, text);
  await withFileLock(telegramGroupsPath(), async () => {
    const fresh = await readTelegramGroups();
    fresh.meta = { ...(fresh.meta || {}), lastSeasonPostWeek: weekKey };
    await writeJsonFile(telegramGroupsPath(), fresh);
  });
  lastSeasonPostWeek = weekKey;
}

// --- Launch milestones: SlimeWire-launched coins announce their own wins. MC
// thresholds and 2x-from-launch post automatically to armed chats with the launch
// room link - creators keep getting reasons to share without lifting a finger.
const LAUNCH_MILESTONES = [
  { key: "mc5k", label: "$5K MC", test: (mc) => mc >= 5_000 },
  { key: "mc10k", label: "$10K MC", test: (mc) => mc >= 10_000 },
  { key: "mc25k", label: "$25K MC", test: (mc) => mc >= 25_000 },
  { key: "mc50k", label: "$50K MC", test: (mc) => mc >= 50_000 }
];

function launchMilestonesPath() {
  return path.join(CONFIG.dataDir, "launch-milestones.json");
}

async function readLaunchMilestones() {
  const store = await readJson(launchMilestonesPath());
  if (!store.tracked || typeof store.tracked !== "object") store.tracked = {};
  return store;
}

async function checkLaunchMilestones() {
  await withFileLock(launchMilestonesPath(), async () => {
    const attempts = await readPumpLaunchAttempts().catch(() => ({ attempts: [] }));
    const recentCutoff = Date.now() - 48 * 60 * 60 * 1000;
    const live = (attempts.attempts || []).filter((attempt) =>
      String(attempt.status || "").toUpperCase() === "COMPLETE"
      && attempt.tokenMint
      && Date.parse(attempt.completedAt || attempt.updatedAt || "") > recentCutoff);
    if (!live.length) return;
    const store = await readLaunchMilestones();
    const mints = live.map((attempt) => attempt.tokenMint).slice(0, 25);
    const pairs = await fetchDexScreenerTokenPairsBatch(mints).catch(() => []);
    let changed = false;
    for (const attempt of live.slice(0, 25)) {
      const mint = attempt.tokenMint;
      const best = bestDexPairForToken(mint, pairs.filter((pair) => pairMatchesToken(pair, mint)));
      const mc = Number(best?.marketCap || best?.fdv) || 0;
      const price = Number(best?.priceUsd) || 0;
      const symbol = best?.baseToken?.symbol || attempt.symbol || shortMint(mint);
      const entry = store.tracked[mint] || { symbol, basePrice: price || null, hit: {} };
      if (!entry.basePrice && price) entry.basePrice = price;
      const fired = [];
      for (const milestone of LAUNCH_MILESTONES) {
        if (!entry.hit[milestone.key] && mc > 0 && milestone.test(mc)) {
          entry.hit[milestone.key] = new Date().toISOString();
          fired.push(milestone.label);
        }
      }
      if (!entry.hit.x2 && entry.basePrice && price >= entry.basePrice * 2) {
        entry.hit.x2 = new Date().toISOString();
        fired.push("2x from launch");
      }
      store.tracked[mint] = entry;
      if (fired.length) {
        changed = true;
        const text = [
          `🎉 <b>$${escapeTelegramHtml(symbol)} hit ${escapeTelegramHtml(fired.join(" + "))}</b> - launched on <a href="https://www.slimewire.org">SlimeWire</a>.`,
          `<a href="https://www.slimewire.org/t?ca=${mint}">launch room</a> | <a href="https://pump.fun/coin/${mint}">pump.fun</a> | <a href="https://www.slimewire.org">launch yours</a>`
        ].join("\n");
        const groupsStore = await readTelegramGroups().catch(() => ({ groups: {} }));
        for (const [chatId, group] of Object.entries(groupsStore.groups || {})) {
          if (group?.alerts) groupBridgeFor(chatId).announce("launch-milestone", `${mint}:${fired[0]}`, text);
        }
        tgChannel.announce("launch-milestone", `${mint}:${fired[0]}`, text);
      }
    }
    const keys = Object.keys(store.tracked);
    if (keys.length > 200) {
      for (const key of keys.slice(0, keys.length - 200)) delete store.tracked[key];
      changed = true;
    }
    if (changed) await writeJsonFile(launchMilestonesPath(), store);
  });
}

// --- Daily Swamp Report: one digest post per UTC day to every armed chat ----------
let lastSwampReportDay = "";
async function runDailySwampReport() {
  const today = new Date().toISOString().slice(0, 10);
  if (lastSwampReportDay === today) return;
  const hourUtc = new Date().getUTCHours();
  if (hourUtc < 14) return; // post mid-day UTC, after the morning action
  const groupsStore = await readTelegramGroups();
  const meta = groupsStore.meta || {};
  if (meta.lastSwampReportDay === today) {
    lastSwampReportDay = today;
    return;
  }
  const calls = await readAlphaCalls().catch(() => ({ calls: [] }));
  const receipts = await readShieldReceipts().catch(() => ({ receipts: [] }));
  const dayAgo = Date.now() - 24 * 60 * 60 * 1000;
  const recent = calls.calls.filter((call) => Date.parse(call.calledAt) > dayAgo);
  const recentWins = recent.filter((call) => call.outcome === "won");
  const bestWin = recentWins.sort((a, b) => (b.peakX || 0) - (a.peakX || 0))[0];
  const recentRugs = receipts.receipts.filter((item) => item.outcome === "rugged" && Date.parse(item.resolvedAt || "") > dayAgo);
  if (!recent.length && !recentRugs.length) return; // nothing worth reporting
  const lines = [
    `🐸 <b>Daily Swamp Report</b>`,
    `${recent.length} call(s) dropped, ${recentWins.length} hit 2x${bestWin ? ` (best: $${escapeTelegramHtml(bestWin.symbol)} ${bestWin.peakX}x)` : ""}.`,
    recentRugs.length ? `🛡 SlimeShield flagged ${recentRugs.length} token(s) before they died.` : "",
    `Full record, wins AND losses: <a href="https://www.slimewire.org/proof">slimewire.org/proof</a>`
  ].filter(Boolean);
  const text = lines.join("\n");
  // Daily digest posts ONLY to the official SlimeWire channel — NOT into every armed group (that's spam
  // in someone else's room). Groups only get slime launches by default (see broadcastToTelegramGroups).
  tgChannel.announce("daily-report", today, text);
  await withFileLock(telegramGroupsPath(), async () => {
    const fresh = await readTelegramGroups();
    fresh.meta = { ...(fresh.meta || {}), lastSwampReportDay: today };
    await writeJsonFile(telegramGroupsPath(), fresh);
  });
  lastSwampReportDay = today;
}

// --- SlimeShield receipts: every AVOID/RISK flag gets recorded, then we go back and
// check what actually happened to the token. "Flagged 43 min before the rug" is the
// kind of proof no other terminal publishes. Global store, capped, best-effort.
const SHIELD_RECEIPT_LIMIT = 400;
const SHIELD_RECEIPT_MIN_AGE_MS = 20 * 60 * 1000;       // let the market move before judging
const SHIELD_RECEIPT_SURVIVE_AGE_MS = 48 * 60 * 60 * 1000; // alive after 48h = survived
const SHIELD_RECEIPT_RUG_LIQ_KEEP_PCT = 15;             // <15% of flag-time liquidity = rugged

function shieldReceiptsPath() {
  return path.join(CONFIG.dataDir, "shield-receipts.json");
}

async function readShieldReceipts() {
  const store = await readJson(shieldReceiptsPath());
  if (!Array.isArray(store.receipts)) store.receipts = [];
  return store;
}

function recordShieldReceipt(result, row = {}) {
  const verdict = String(result?.verdict || "").toUpperCase();
  if (!["AVOID", "RISK"].includes(verdict)) return;
  const mint = String(result?.mint || row.tokenMint || "").trim();
  if (!mint) return;
  void withFileLock(shieldReceiptsPath(), async () => {
    try {
      const store = await readShieldReceipts();
      const dayAgo = Date.now() - 24 * 60 * 60 * 1000;
      const existing = store.receipts.find((item) => item.mint === mint
        && (item.status === "watching" || Date.parse(item.flaggedAt || "") > dayAgo));
      if (existing) return;
      store.receipts.push({
        mint,
        symbol: String(row.symbol || row.baseSymbol || "").slice(0, 24),
        name: String(row.name || row.baseName || "").slice(0, 48),
        verdict,
        score: Number(result.score) || 0,
        summary: String(result.summary || "").slice(0, 160),
        flaggedAt: new Date().toISOString(),
        liquidityUsd: Number(row.liquidityUsd ?? row.liquidity?.usd) || null,
        priceUsd: Number(row.priceUsd) || null,
        status: "watching",
        outcome: null,
        resolvedAt: null
      });
      store.receipts = store.receipts.slice(-SHIELD_RECEIPT_LIMIT);
      await writeJsonFile(shieldReceiptsPath(), store);
    } catch (error) {
      console.warn(`[shield-receipts] record failed: ${error.message}`);
    }
  });
}

async function checkShieldReceiptOutcomes() {
  return withFileLock(shieldReceiptsPath(), async () => {
  const store = await readShieldReceipts();
  const now = Date.now();
  const due = store.receipts
    .filter((item) => item.status === "watching" && now - Date.parse(item.flaggedAt || "") > SHIELD_RECEIPT_MIN_AGE_MS)
    .slice(0, 25);
  if (!due.length) return { checked: 0 };
  const pairs = await fetchDexScreenerTokenPairsBatch(due.map((item) => item.mint)).catch(() => []);
  let changed = false;
  for (const receipt of due) {
    const tokenPairs = pairs.filter((pair) => pairMatchesToken(pair, receipt.mint));
    const best = bestDexPairForToken(receipt.mint, tokenPairs);
    const liqNow = Number(best?.liquidity?.usd) || 0;
    const priceNow = Number(best?.priceUsd) || 0;
    // Black-box timeline: every check appends a snapshot so confirmed rugs carry the
    // full collapse curve ("flagged at min 3, liquidity gone by min 41").
    receipt.timeline = [...(receipt.timeline || []), { at: new Date(now).toISOString(), liqUsd: liqNow, priceUsd: priceNow }].slice(-48);
    changed = true;
    const flaggedLiq = Number(receipt.liquidityUsd) || 0;
    const flaggedPrice = Number(receipt.priceUsd) || 0;
    const ageMs = now - Date.parse(receipt.flaggedAt || "");
    const liquidityCollapsed = flaggedLiq > 1000 && liqNow < flaggedLiq * (SHIELD_RECEIPT_RUG_LIQ_KEEP_PCT / 100);
    const priceCollapsed = flaggedPrice > 0 && priceNow > 0 && priceNow < flaggedPrice * 0.1;
    if (!best || liquidityCollapsed || priceCollapsed) {
      receipt.status = "resolved";
      receipt.outcome = "rugged";
      receipt.resolvedAt = new Date(now).toISOString();
      receipt.confirmedAfterMinutes = Math.round(ageMs / 60_000);
      changed = true;
    } else if (ageMs > SHIELD_RECEIPT_SURVIVE_AGE_MS) {
      receipt.status = "resolved";
      receipt.outcome = "survived";
      receipt.resolvedAt = new Date(now).toISOString();
      changed = true;
    }
  }
  if (changed) await writeJsonFile(shieldReceiptsPath(), store);
  return { checked: due.length };
  });
}

if (CONFIG.serviceRole === "web") {
  const shieldReceiptTimer = setInterval(() => {
    checkShieldReceiptOutcomes().catch((error) => console.warn(`[shield-receipts] check failed: ${error.message}`));
    checkAlphaCallOutcomes().catch((error) => console.warn(`[alpha-calls] check failed: ${error.message}`));
    runCallerIntelTick().catch((error) => console.warn(`[caller-intel] tick failed: ${error.message}`));
    if (Date.now() - autopilotCalibrationAt > 6 * 60 * 60 * 1000) { // refresh the learned bias ~every 6h
      recomputeAutopilotCalibration().catch((error) => console.warn(`[calibration] recompute failed: ${error.message}`));
    }
    if (Date.now() - lastBackupAt > 24 * 60 * 60 * 1000) { // daily off-box backup to R2 (no-op if unconfigured)
      backupDataToR2("daily").catch((error) => console.warn(`[backup] daily failed: ${error.message}`));
    }
    // "🐸 SlimeWire plays" group broadcast DISABLED for now — spammed frequent short-term/rug-prone
    // pops; groups use 🕵️ Alpha Radar (top wallets) instead. Re-enable this line to restore.
    // runAlphaDropTick().catch((error) => console.warn(`[alpha-drop] tick failed: ${error.message}`));
    checkBoardCallOutcomes().catch((error) => console.warn(`[call-board] check failed: ${error.message}`));
    runDailySwampReport().catch((error) => console.warn(`[swamp-report] failed: ${error.message}`));
    runWeeklySeasonPost().catch((error) => console.warn(`[season] failed: ${error.message}`));
    checkLaunchMilestones().catch((error) => console.warn(`[launch-milestones] failed: ${error.message}`));
    if (Date.now() % (10 * 60 * 1000) < 5 * 60 * 1000) {
      checkWatchlistMoveAlerts().catch((error) => console.warn(`[watch-alerts] failed: ${error.message}`));
      checkWatchedDevs().catch((error) => console.warn(`[dev-watch] failed: ${error.message}`));
      checkRadarRules().catch((error) => console.warn(`[radar] failed: ${error.message}`));
    }
  }, 5 * 60 * 1000);
  shieldReceiptTimer.unref?.();
}

// --- Web push alerts (per-user, private; enabled only when VAPID keys are set) ---
const webPushEnabled = Boolean(CONFIG.pushVapidPublicKey && CONFIG.pushVapidPrivateKey);
if (webPushEnabled) {
  webpush.setVapidDetails(CONFIG.pushVapidSubject, CONFIG.pushVapidPublicKey, CONFIG.pushVapidPrivateKey);
}

function pushSubscriptionsPath() {
  return path.join(CONFIG.dataDir, "push-subscriptions.json");
}

async function readPushSubscriptions() {
  const store = await readJson(pushSubscriptionsPath());
  if (!store.subs || typeof store.subs !== "object") store.subs = {};
  return store;
}

async function savePushSubscription(userId, subscription) {
  if (!subscription?.endpoint) throw new Error("Invalid push subscription.");
  const store = await readPushSubscriptions();
  const list = Array.isArray(store.subs[userId]) ? store.subs[userId] : [];
  const without = list.filter((item) => item?.endpoint !== subscription.endpoint);
  store.subs[userId] = [...without, subscription].slice(-5); // a handful of devices per user
  await writeJsonFile(pushSubscriptionsPath(), store);
  return store.subs[userId].length;
}

async function removePushSubscription(userId, endpoint) {
  const store = await readPushSubscriptions();
  const list = Array.isArray(store.subs[userId]) ? store.subs[userId] : [];
  store.subs[userId] = list.filter((item) => item?.endpoint !== endpoint);
  if (!store.subs[userId].length) delete store.subs[userId];
  await writeJsonFile(pushSubscriptionsPath(), store);
}

// Fire-and-forget per-user push. Dead subscriptions (410/404) are pruned in place.
// --- Watch-this-dev: users track a deployer wallet; when it launches again on
// pump.fun they get a web push + Telegram DM (if linked) with the shield-read link.
function watchDevsPath() {
  return path.join(CONFIG.dataDir, "watch-devs.json");
}

async function readWatchDevs() {
  const store = await readJson(watchDevsPath());
  if (!store.watchers || typeof store.watchers !== "object") store.watchers = {};
  return store;
}

async function checkWatchedDevs() {
  const peek = await readWatchDevs().catch(() => null);
  const wallets = Object.keys(peek?.watchers || {}).slice(0, 25);
  if (!wallets.length) return;
  const links = await readTelegramLinks().catch(() => ({ links: {} }));
  await withFileLock(watchDevsPath(), async () => {
    const store = await readWatchDevs();
    let changed = false;
    for (const wallet of wallets) {
      const watcher = store.watchers[wallet];
      if (!watcher || !Object.keys(watcher.byUser || {}).length) continue;
      const launches = await getPumpFunCreatorLaunches(wallet).catch(() => []);
      if (!launches.length) continue;
      const known = new Set(watcher.knownMints || []);
      const newLaunches = launches.filter((launch) => launch.mint && !known.has(launch.mint));
      watcher.lastCheckedAt = new Date().toISOString();
      changed = true;
      if (!newLaunches.length) continue;
      watcher.knownMints = [...known, ...newLaunches.map((launch) => launch.mint)].slice(-50);
      const shortWallet = `${wallet.slice(0, 4)}..${wallet.slice(-4)}`;
      for (const launch of newLaunches.slice(0, 3)) {
        const symbol = launch.symbol || "???";
        for (const userId of Object.keys(watcher.byUser)) {
          sendWebPushToUser(userId, {
            title: `👀 Watched dev launched $${symbol}`,
            body: `Deployer ${shortWallet} just launched again. Get the shield read before you ape.`,
            tag: `dev-watch-${wallet}`,
            url: `/t?ca=${launch.mint}`
          }).catch(() => {});
          const tgUserId = links.links?.[userId];
          if (tgUserId) {
            sayHtml(tgUserId, [
              `👀 <b>A dev you watch just launched</b> $${escapeTelegramHtml(symbol)}`,
              `Deployer <code>${escapeTelegramHtml(shortWallet)}</code> is at it again.`,
              `<a href="https://www.slimewire.org/t?ca=${launch.mint}">Shield read + chart on SlimeWire</a>`
            ].join("\n")).catch(() => {});
          }
        }
      }
    }
    if (changed) await writeJsonFile(watchDevsPath(), store);
  });
}

// --- Instant dev-watch -----------------------------------------------------
// Two push paths replace the old "find out within 10 minutes" polling:
//   1. The PumpPortal websocket sees EVERY pump.fun creation with its creator
//      wallet - watched devs trigger alerts within ~1 second, no extra cost.
//   2. A Helius webhook (optional, HELIUS_WEBHOOK_ID + HELIUS_WEBHOOK_SECRET)
//      pushes any tx from watched wallets and triggers an immediate re-check,
//      covering non-pump.fun activity. Polling stays as the safety net.

let watchedDevSetCache = { at: 0, set: new Set() };

async function watchedDevWalletSet(force = false) {
  if (force || Date.now() - watchedDevSetCache.at > 60_000) {
    const store = await readWatchDevs().catch(() => null);
    watchedDevSetCache = { at: Date.now(), set: new Set(Object.keys(store?.watchers || {})) };
  }
  return watchedDevSetCache.set;
}

async function handlePumpPortalCreationForDevWatch(entry) {
  const creator = String(entry?.event?.traderPublicKey || "").trim();
  if (!creator) return;
  const watched = await watchedDevWalletSet();
  if (!watched.has(creator)) return;
  const mint = String(entry.mint || "");
  const symbol = String(entry.event?.symbol || "???");
  const links = await readTelegramLinks().catch(() => ({ links: {} }));
  await withFileLock(watchDevsPath(), async () => {
    const store = await readWatchDevs();
    const watcher = store.watchers[creator];
    if (!watcher || !Object.keys(watcher.byUser || {}).length) return;
    const known = new Set(watcher.knownMints || []);
    if (known.has(mint)) return;
    watcher.knownMints = [...known, mint].slice(-50);
    watcher.lastCheckedAt = new Date().toISOString();
    await writeJsonFile(watchDevsPath(), store);
    const shortWallet = `${creator.slice(0, 4)}..${creator.slice(-4)}`;
    for (const userId of Object.keys(watcher.byUser)) {
      sendWebPushToUser(userId, {
        title: `👀 Watched dev launched $${symbol}`,
        body: `Deployer ${shortWallet} just launched again - seconds ago. Get the shield read before you ape.`,
        tag: `dev-watch-${creator}`,
        url: `/t?ca=${mint}`
      }).catch(() => {});
      const tgUserId = links.links?.[userId];
      if (tgUserId) {
        sayHtml(tgUserId, [
          `👀 <b>A dev you watch just launched</b> $${escapeTelegramHtml(symbol)} <i>(live, seconds old)</i>`,
          `Deployer <code>${escapeTelegramHtml(shortWallet)}</code> is at it again.`,
          `<a href="https://www.slimewire.org/t?ca=${mint}">Shield read + chart on SlimeWire</a>`
        ].join("\n")).catch(() => {});
      }
    }
  });
}

let instantDevCheckTimer = null;

// Debounced: a webhook burst (one launch = many txs) becomes one re-check.
function scheduleInstantWatchedDevCheck() {
  if (instantDevCheckTimer) return;
  instantDevCheckTimer = setTimeout(() => {
    instantDevCheckTimer = null;
    void checkWatchedDevs().catch(() => {});
  }, 1_500);
}

// Keep the Helius webhook's address list in sync with who is being watched.
// No-op unless HELIUS_WEBHOOK_ID is configured (webhook created once in the
// Helius dashboard pointing at /api/internal/helius-webhook).
async function syncHeliusWebhookAddresses() {
  if (!CONFIG.heliusApiKey || !CONFIG.heliusWebhookId) return false;
  try {
    const store = await readWatchDevs().catch(() => null);
    const addresses = Object.keys(store?.watchers || {}).slice(0, 100);
    if (!addresses.length) return false;
    await fetchJson(`https://api.helius.xyz/v0/webhooks/${encodeURIComponent(CONFIG.heliusWebhookId)}?api-key=${encodeURIComponent(CONFIG.heliusApiKey)}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        webhookURL: `${CONFIG.pumpLaunchHostedMetadataBaseUrl || ""}/api/internal/helius-webhook`,
        transactionTypes: ["ANY"],
        accountAddresses: addresses,
        webhookType: "enhanced",
        authHeader: CONFIG.heliusWebhookSecret || undefined
      }),
      timeoutMs: 5_000
    });
    return true;
  } catch (error) {
    console.warn(`[helius-webhook] address sync failed: ${error.message}`);
    return false;
  }
}

async function sendWebPushToUser(userId, payload = {}) {
  if (!webPushEnabled || !userId) return;
  try {
    const store = await readPushSubscriptions();
    const list = Array.isArray(store.subs[userId]) ? store.subs[userId] : [];
    if (!list.length) return;
    const body = JSON.stringify({
      title: String(payload.title || "SlimeWire"),
      body: String(payload.body || ""),
      tag: String(payload.tag || "slimewire"),
      url: String(payload.url || "/terminal")
    });
    const dead = [];
    await Promise.all(list.map(async (subscription) => {
      try {
        await webpush.sendNotification(subscription, body, { TTL: 3600 });
      } catch (error) {
        if ([404, 410].includes(Number(error?.statusCode))) dead.push(subscription.endpoint);
      }
    }));
    if (dead.length) {
      store.subs[userId] = list.filter((item) => !dead.includes(item?.endpoint));
      if (!store.subs[userId].length) delete store.subs[userId];
      await writeJsonFile(pushSubscriptionsPath(), store);
    }
  } catch (error) {
    console.warn(`[web-push] send failed: ${error.message}`);
  }
}

async function writeTradePlans(store) {
  await writeJsonFile(tradePlansPath(), store);
}

// Atomic read-modify-write of the trade-plans store — keeps a user stop/start/arm from clobbering a
// concurrent worker tick (and vice-versa). fn mutates `store` in place; its return value is passed back.
async function mutateTradePlans(fn) {
  return withFileLock(tradePlansPath(), async () => {
    const store = await readTradePlans();
    const result = await fn(store);
    await writeTradePlans(store);
    return result;
  });
}

function durableTradeWatchKey(parts = []) {
  return crypto.createHash("sha256")
    .update(parts.map((value) => String(value ?? "")).join("\0"))
    .digest("hex");
}

async function addUniqueActiveTradeWatch(plan, activeStatuses = []) {
  let storedPlan = plan;
  let created = false;
  const active = new Set(activeStatuses.map((status) => String(status)));
  await mutateTradePlans((store) => {
    const existing = objectRows(store.plans).find((row) => row.watchKey === plan.watchKey && active.has(String(row.status || "")));
    if (existing) {
      storedPlan = existing;
      return;
    }
    store.plans.push(plan);
    created = true;
  });
  return { plan: storedPlan, created };
}

// --- Ogre A.I. autopilot (guarded auto-buy) -----------------------------
// Hard, conservative limits. The autopilot only ever spends inside these.
const OGRE_AUTOPILOT_LIMITS = {
  amountSol: { min: 0.001, max: 1, default: 0.05 },
  minScore: { min: 0, max: 100, default: 62 },
  maxConcurrent: { min: 1, max: 5, default: 2 },
  maxSpendPerHourSol: { min: 0.01, max: 2, default: 0.3 },
  intervalMinutes: { min: 3, max: 240, default: 10 }
};

function clampLimit(value, spec, fallback) {
  const num = Number(value);
  if (!Number.isFinite(num)) return fallback === undefined ? spec.default : fallback;
  return Math.min(spec.max, Math.max(spec.min, num));
}

async function readOgreAutopilotStore() {
  const store = await readJson(ogreAutopilotPath());
  if (!store.configs || typeof store.configs !== "object") store.configs = {};
  return store;
}

async function writeOgreAutopilotStore(store) {
  await writeJsonFile(ogreAutopilotPath(), store);
}

function defaultOgreAutopilotConfig() {
  return {
    enabled: false,
    category: "super_fresh",
    amountSol: OGRE_AUTOPILOT_LIMITS.amountSol.default,
    // Runner profile: 2x target, wide stop for volatility, 1h fallback timer.
    takeProfitPct: "100",
    stopLossPct: "40",
    sellDelay: "60",
    slippageBps: "400",
    walletIndexes: [],
    walletGroup: "",
    minScore: OGRE_AUTOPILOT_LIMITS.minScore.default,
    maxConcurrent: OGRE_AUTOPILOT_LIMITS.maxConcurrent.default,
    maxSpendPerHourSol: OGRE_AUTOPILOT_LIMITS.maxSpendPerHourSol.default,
    intervalMinutes: OGRE_AUTOPILOT_LIMITS.intervalMinutes.default,
    spendLog: [],
    recentMints: [],
    lastRunAt: null,
    nextRunAt: null,
    lastStatus: "",
    updatedAt: null
  };
}

// Sanitize + clamp an incoming autopilot config from the web form. Never
// trusts client values; every numeric guard is clamped to the hard limits.
function sanitizeOgreAutopilotConfig(existing, body = {}) {
  const base = { ...defaultOgreAutopilotConfig(), ...(existing || {}) };
  const walletIndexes = Array.isArray(body.walletIndexes)
    ? body.walletIndexes.map((value) => Number.parseInt(String(value), 10)).filter((n) => Number.isFinite(n) && n > 0).slice(0, 50)
    : base.walletIndexes;
  const next = {
    ...base,
    enabled: Boolean(body.enabled),
    category: normalizeOgreAiCategory(firstString(body.category, base.category)),
    amountSol: clampLimit(body.amountSol, OGRE_AUTOPILOT_LIMITS.amountSol, base.amountSol),
    takeProfitPct: String(firstString(body.takeProfitPct, base.takeProfitPct) || "100"),
    stopLossPct: String(firstString(body.stopLossPct, base.stopLossPct) || "40"),
    sellDelay: String(firstString(body.sellDelay, base.sellDelay) || "60"),
    slippageBps: String(firstString(body.slippageBps, base.slippageBps) || "400"),
    walletIndexes,
    walletGroup: String(body.walletGroup || base.walletGroup || "").trim(),
    minScore: Math.round(clampLimit(body.minScore, OGRE_AUTOPILOT_LIMITS.minScore, base.minScore)),
    maxConcurrent: Math.round(clampLimit(body.maxConcurrent, OGRE_AUTOPILOT_LIMITS.maxConcurrent, base.maxConcurrent)),
    maxSpendPerHourSol: clampLimit(body.maxSpendPerHourSol, OGRE_AUTOPILOT_LIMITS.maxSpendPerHourSol, base.maxSpendPerHourSol),
    intervalMinutes: Math.round(clampLimit(body.intervalMinutes, OGRE_AUTOPILOT_LIMITS.intervalMinutes, base.intervalMinutes)),
    updatedAt: new Date().toISOString()
  };
  // Cannot enable without at least one wallet target.
  if (next.enabled && !next.walletIndexes.length && !next.walletGroup) {
    const error = new Error("Pick at least one managed wallet (or a wallet group) before enabling autopilot.");
    error.statusCode = 400;
    throw error;
  }
  // Re-enabling clears any stale schedule so the first tick can run soon.
  if (next.enabled && !base.enabled) {
    next.nextRunAt = null;
    next.lastStatus = "Autopilot armed. Waiting for the next qualified pick.";
  }
  if (!next.enabled) {
    next.lastStatus = "Autopilot off.";
  }
  return next;
}

function ogreAutopilotSpendLastHour(config, now = Date.now()) {
  const cutoff = now - 60 * 60 * 1000;
  const log = Array.isArray(config.spendLog) ? config.spendLog : [];
  return log
    .filter((entry) => Number(entry?.at) >= cutoff)
    .reduce((sum, entry) => sum + (Number(entry?.sol) || 0), 0);
}

function prunedOgreAutopilotSpendLog(config, now = Date.now()) {
  const cutoff = now - 60 * 60 * 1000;
  return (Array.isArray(config.spendLog) ? config.spendLog : [])
    .filter((entry) => Number(entry?.at) >= cutoff)
    .slice(-200);
}

// Public-facing status (no secrets) for the web panel.
function ogreAutopilotStatusView(config) {
  const now = Date.now();
  const spentLastHour = ogreAutopilotSpendLastHour(config, now);
  return {
    enabled: Boolean(config.enabled),
    category: config.category,
    categoryLabel: ogreAiCategoryLabel(config.category),
    amountSol: config.amountSol,
    takeProfitPct: config.takeProfitPct,
    stopLossPct: config.stopLossPct,
    sellDelay: config.sellDelay,
    slippageBps: config.slippageBps,
    walletIndexes: config.walletIndexes,
    walletGroup: config.walletGroup,
    minScore: config.minScore,
    maxConcurrent: config.maxConcurrent,
    maxSpendPerHourSol: config.maxSpendPerHourSol,
    intervalMinutes: config.intervalMinutes,
    spentLastHourSol: Math.round(spentLastHour * 1e6) / 1e6,
    remainingThisHourSol: Math.max(0, Math.round((config.maxSpendPerHourSol - spentLastHour) * 1e6) / 1e6),
    lastRunAt: config.lastRunAt,
    nextRunAt: config.nextRunAt,
    lastStatus: config.lastStatus,
    updatedAt: config.updatedAt
  };
}

async function countActiveOgreAiPlans(userId) {
  try {
    const store = await readTradePlans();
    return (store.plans || []).filter((plan) => (
      plan
      && plan.userId === userId
      && plan.source === "ogre_ai"
      && !["completed", "closed", "cancelled", "canceled", "stopped", "failed"].includes(String(plan.status || "").toLowerCase())
    )).length;
  } catch {
    return 0;
  }
}

let ogreAutopilotTickActive = false;

// One scheduler pass over every saved autopilot config. Self-gates on the
// per-config schedule and enforces all hard guards before spending anything.
async function runOgreAutopilotTick(reason = "interval") {
  if (ogreAutopilotTickActive) return { skipped: true, reason: "tick_active" };
  ogreAutopilotTickActive = true;
  try {
    const store = await readOgreAutopilotStore();
    const userIds = Object.keys(store.configs || {});
    if (!userIds.length) return { skipped: true, reason: "no_configs" };
    const now = Date.now();
    let mutated = false;

    for (const userId of userIds) {
      const config = store.configs[userId];
      if (!config || !config.enabled) continue;
      if (config.nextRunAt && now < Date.parse(config.nextRunAt)) continue;

      const intervalMs = clampLimit(config.intervalMinutes, OGRE_AUTOPILOT_LIMITS.intervalMinutes, OGRE_AUTOPILOT_LIMITS.intervalMinutes.default) * 60 * 1000;
      const setStatus = (message, { skip = false } = {}) => {
        config.lastStatus = message;
        config.spendLog = prunedOgreAutopilotSpendLog(config, now);
        // After a skip, re-check soon so the hunt resumes fast - fresh pairs
        // launch every few seconds, so idling for a minute means missing them.
        config.nextRunAt = new Date(now + (skip ? Math.min(intervalMs, 15_000) : intervalMs)).toISOString();
        mutated = true;
      };

      const walletCount = config.walletIndexes.length || 1;
      const projectedSpend = config.amountSol * walletCount;
      const spentLastHour = ogreAutopilotSpendLastHour(config, now);
      if (spentLastHour + projectedSpend > config.maxSpendPerHourSol + 1e-9) {
        setStatus(`Hourly spend cap reached (${spentLastHour.toFixed(4)}/${config.maxSpendPerHourSol} SOL). Cooling down.`, { skip: true });
        continue;
      }

      const activePlans = await countActiveOgreAiPlans(userId);
      if (activePlans >= config.maxConcurrent) {
        setStatus(`Holding: ${activePlans}/${config.maxConcurrent} managed Ogre A.I. plans already live.`, { skip: true });
        continue;
      }

      try {
        // Persistent hunt: don't bail after one empty scan. Fresh pairs launch
        // constantly, so keep re-scanning for up to ~30s, skipping any token
        // that fails the buy precheck, until a buy arms or the budget runs out.
        // Selection is read-only and at most ONE buy ever arms per tick, so
        // looping is safe and respects the spend/concurrency guards above.
        const huntDeadlineMs = Date.now() + Math.min(intervalMs, 30_000);
        const avoidMints = normalizeOgreAiRecentMints(config.recentMints || []);
        let result = null;
        let armed = false;
        let huntPasses = 0;
        do {
          huntPasses += 1;
          result = await webStartOgreAiRun(userId, {
            category: config.category,
            amountSol: String(config.amountSol),
            runCount: "1",
            sellDelay: config.sellDelay,
            takeProfitPct: config.takeProfitPct,
            stopLossPct: config.stopLossPct,
            sellPercent: "100",
            slippageBps: config.slippageBps,
            walletIndexes: config.walletIndexes,
            walletGroup: config.walletGroup,
            recentMints: avoidMints,
            minScore: String(config.minScore || ""),
            autopilot: true
          });
          armed = Number(result?.armedCount || 0) > 0;
          if (armed) break;
          // Remember tokens that were tried but failed the buy precheck so the
          // next scan moves on instead of re-picking the same dud.
          for (const item of (result?.errors || [])) {
            if (item?.tokenMint && !avoidMints.includes(item.tokenMint)) avoidMints.push(item.tokenMint);
          }
          for (const item of (result?.attemptedPicks || [])) {
            if (item?.tokenMint && !avoidMints.includes(item.tokenMint)) avoidMints.push(item.tokenMint);
          }
          if (Date.now() >= huntDeadlineMs) break;
          await sleep(5_000); // let the live stream surface new sub-30s launches
        } while (Date.now() < huntDeadlineMs);
        if (armed) {
          const spend = config.amountSol * Number(result.walletCount || walletCount);
          config.spendLog = prunedOgreAutopilotSpendLog(config, now).concat([{ at: now, sol: spend }]);
          const newMints = (result.plans || []).map((plan) => plan.tokenMint).filter(Boolean);
          config.recentMints = normalizeOgreAiRecentMints((config.recentMints || []).concat(newMints));
          config.lastRunAt = new Date(now).toISOString();
          config.nextRunAt = new Date(now + intervalMs).toISOString();
          config.lastStatus = `Aped ${ogreAiCategoryLabel(config.category)} pick ${newMints.map(shortMint).join(", ") || ""} for ${spend.toFixed(4)} SOL.`;
          mutated = true;
          await audit("web_ogre_ai_autopilot_buy", {
            userId, category: config.category, spend, tokenMints: newMints, reason
          });
        } else {
          setStatus(`${result?.message || "No qualified pick yet"} - hunting (${huntPasses} scan${huntPasses === 1 ? "" : "s"}), retrying shortly.`, { skip: true });
        }
      } catch (error) {
        setStatus(`Skipped: ${friendlyError(error)}`, { skip: true });
      }
    }

    if (mutated) await writeOgreAutopilotStore(store);
    return { ok: true, reason };
  } catch (error) {
    console.warn(`Ogre A.I. autopilot tick failed: ${friendlyError(error)}`);
    return { ok: false, error: friendlyError(error) };
  } finally {
    ogreAutopilotTickActive = false;
  }
}

function startOgreAutopilotRunner() {
  // Tick every 10s: per-config nextRunAt still gates buys (full interval after
  // a fill), but a no-pick config can resume its hunt within seconds instead of
  // waiting out a minute. The tick-active guard prevents overlap.
  const intervalMs = 10_000;
  setTimeout(() => void runOgreAutopilotTick("startup").catch(() => {}), 12_000);
  setInterval(() => void runOgreAutopilotTick("interval").catch(() => {}), intervalMs);
  console.log("Ogre A.I. autopilot runner enabled (guarded auto-buy; off until a user opts in).");
}

async function writeTradePlansPreservingNewPlans(store, initialPlanIds = new Set()) {
  return withFileLock(tradePlansPath(), async () => {
    const latest = await readTradePlans();
    const incomingPlans = objectRows(store.plans);
    const latestById = new Map(objectRows(latest.plans).map((plan) => [plan.id, plan]));
    const incomingIds = new Set(incomingPlans.map((plan) => plan.id).filter(Boolean));
    const terminal = new Set(["canceled", "cancelled", "stopped", "completed", "closed"]);
    const mergedPlans = [];

    for (const incoming of incomingPlans) {
      if (!incoming?.id) continue;
      const current = latestById.get(incoming.id);
      // A plan removed while this worker was running stays removed.
      if (initialPlanIds.has(incoming.id) && !current) continue;
      // User cancellation/stop always wins over an older worker snapshot.
      if (current && (terminal.has(String(current.status || "").toLowerCase())
        || ["sweeping", "done", "stopped"].includes(String(current.botStage || "").toLowerCase()))) {
        mergedPlans.push(current);
      } else {
        mergedPlans.push(incoming);
      }
    }

    for (const current of objectRows(latest.plans)) {
      if (!current?.id || incomingIds.has(current.id)) continue;
      if (!initialPlanIds.has(current.id)) mergedPlans.push(current);
    }
    const merged = { ...latest, ...store, plans: mergedPlans };
    await writeTradePlans(merged);
    return merged;
  });
}

