async function confirmOrCancel(chatId, text, onConfirm, options = {}) {
  if (text.trim().toLowerCase() !== "yes") {
    await sendConfirmPrompt(chatId, "Confirm this action:");
    return;
  }

  if (!options.allowWhilePaused && (await readState()).paused) {
    clearSession(chatId);
    await say(chatId, "Emergency stop is active. Transaction flow canceled.");
    return;
  }

  await say(chatId, "Executing. This can take a bit if several wallets are selected.");
  await onConfirm();
}

function isAdmin(userId) {
  return CONFIG.adminUserIds.includes(userId);
}

function isPrivateChat(chat) {
  return chat?.type === "private";
}

async function isPausedActionBlocked(action) {
  const allowedWhilePaused = new Set([
    "quick_start",
    "main_menu",
    "list_wallets",
    "check_balances",
    "backup_menu",
    "manual_launch_watches",
    "export_backup",
    "restore_backup",
    "verify_backup_file",
    "rescue_backup_keys",
    "export_private_keys",
    "export_audit",
    "emergency_stop",
    "unlock_bot"
  ]);
  return (await readState()).paused && !allowedWhilePaused.has(action);
}

function setSession(chatId, step, userId) {
  sessions.set(chatId, { step, userId, data: {} });
}

function clearSession(chatId) {
  sessions.delete(chatId);
}

function chunkText(text, size) {
  const chunks = [];
  for (let index = 0; index < text.length; index += size) {
    chunks.push(text.slice(index, index + size));
  }
  return chunks.length ? chunks : [""];
}

function chunkArray(items, size) {
  const chunks = [];
  for (let index = 0; index < items.length; index += size) {
    chunks.push(items.slice(index, index + size));
  }
  return chunks;
}

function getTimedCache(cache, key, ttlMs = CONFIG.balanceCacheTtlMs) {
  if (ttlMs <= 0) return undefined;
  const entry = cache.get(key);
  if (!entry) return undefined;
  if (Date.now() - entry.createdAt > ttlMs) {
    cache.delete(key);
    return undefined;
  }
  return entry.value;
}

function setTimedCache(cache, key, value) {
  if (CONFIG.balanceCacheTtlMs <= 0) return;
  cache.set(key, { createdAt: Date.now(), value });
}

function invalidateWalletReadCache(publicKey) {
  const key = String(publicKey || "");
  if (!key) return;
  solBalanceCache.delete(key);
  tokenAccountsCache.delete(key);
  for (const cacheKey of [...tokenBalanceCache.keys()]) {
    if (cacheKey.startsWith(`${key}:`)) {
      tokenBalanceCache.delete(cacheKey);
    }
  }
  positionValueCache.clear();
}

async function runWithConcurrency(items, concurrency, worker) {
  let nextIndex = 0;
  const results = Array.from({ length: items.length });
  const runners = Array.from({ length: Math.min(concurrency, items.length) }, async () => {
    while (nextIndex < items.length) {
      const index = nextIndex;
      nextIndex += 1;
      results[index] = await worker(items[index], index);
    }
  });

  await Promise.all(runners);
  return results;
}

function formatError(error) {
  return error instanceof Error ? error.message : String(error);
}

function friendlyError(error) {
  const message = formatError(error);

  if (message.startsWith("Buy failed after funding check:")) {
    return message;
  }

  if (message.includes("429") || /too many requests|rate limit/i.test(message)) {
    return "Rate limit after automatic retries. The bot slowed down and queued requests, but the RPC or Jupiter endpoint is still throttling. Use fewer wallets, wait a minute, or upgrade SOLANA_RPC_URL/Jupiter limits for reliable batches.";
  }

  if (/failed to get quote|could not build a quote|quote\/order|No routes/i.test(message)) {
    return "No Jupiter route/quote. Check token mint, liquidity, amount size, slippage, and wallet SOL balance.";
  }

  if (/insufficient funds for rent/i.test(message)) {
    return "Not enough SOL after fees/rent. For Withdraw SOL, use an existing funded destination wallet, or make sure the amount is enough to create a brand-new destination account.";
  }

  if (/destination account does not exist/i.test(message)) {
    return message;
  }

  if (/insufficient funds|custom program error: 0x1/i.test(message)) {
    return "Not enough SOL for swap plus network fees. Add SOL, use a smaller amount, or type max in the buy amount step.";
  }

  return message;
}

function friendlyBackupError(error) {
  const message = formatError(error);
  if (/APP_SECRET|could not be decrypted/i.test(message)) {
    return "Backup opened, but wallet keys could not be decrypted. Set the new Render APP_SECRET to the exact old APP_SECRET, redeploy, then restore or use /rescue.";
  }
  if (/Unexpected token|JSON|Could not read that backup|Backup format/i.test(message)) {
    return "Could not read that backup. Upload the original wallet-backup .txt file, paste the full backup text, or paste emergency key text with Base58 secret key / JSON secret key lines.";
  }
  return message;
}

function looksLikeBackupDocument(filename, text) {
  const name = String(filename || "").toLowerCase();
  const sample = String(text || "").slice(0, 500).toLowerCase();
  return name.includes("backup")
    || name.endsWith(".txt")
    || sample.includes("\"wallets\"")
    || sample.includes("wallet-backup")
    || sample.includes("encrypted");
}

// Route a READ through the optional cheaper provider (Alchemy/Chainstack) with the
// same retry/limiter behavior, then AUTOMATICALLY fall back to the primary Helius
// connection if the read provider errors out. `opFactory` takes a Connection so the
// same closure can run against either provider. When no read provider is configured
// (readConnection === connection) this is exactly rpcWithRetry on Helius — no change.
async function rpcRead(label, opFactory, options = {}) {
  if (readConnection === connection) {
    return rpcWithRetry(label, () => opFactory(connection), options.retries ?? CONFIG.rpcRetries, options);
  }
  rpcStats.readCallCount = (rpcStats.readCallCount || 0) + 1;
  // Tag metrics/logs with the ACTUAL read provider so log lines show alchemy/chainstack
  // (not the static "helius" label) when a read is served off Helius.
  const readOpts = { ...options, providerName: CONFIG.readRpcProviderName || "read", providerHost: CONFIG.readRpcHost || "" };
  try {
    return await rpcWithRetry(label, () => opFactory(readConnection), readOpts.retries ?? CONFIG.rpcRetries, readOpts);
  } catch (error) {
    rpcStats.readFallbackCount = (rpcStats.readFallbackCount || 0) + 1;
    // Tier 2 — CHAINSTACK (paid): absorb the failover before touching the primary Helius. Only if set.
    if (chainstackReadConnection) {
      try {
        return await rpcWithRetry(label, () => opFactory(chainstackReadConnection), options.retries ?? CONFIG.rpcRetries, { ...options, providerName: "chainstack", providerHost: (chainstackRpcUrl.match(/https?:\/\/([^/]+)/) || [])[1] || "" });
      } catch (csError) {
        console.warn(`${label}: chainstack read also failed (${friendlyError(csError)}); falling back to Helius.`);
      }
    }
    console.warn(`${label}: read provider failed (${friendlyError(error)}); falling back to Helius.`);
    return rpcWithRetry(label, () => opFactory(connection), options.retries ?? CONFIG.rpcRetries, options);
  }
}

async function rpcWithRetry(label, operation, retries = CONFIG.rpcRetries, options = {}) {
  let lastError;
  const limiter = options.priority ? priorityRpcLimiter : rpcLimiter;
  const providerName = options.providerName || CONFIG.rpcProviderName;
  const providerHost = options.providerHost || CONFIG.rpcUrlHost;
  const startedAt = Date.now();

  for (let attempt = 0; attempt <= retries; attempt += 1) {
    try {
      const result = await limiter.schedule(label, operation);
      recordRpcMetric(Date.now() - startedAt, null, label, providerName, providerHost);
      return result;
    } catch (error) {
      lastError = error;
      if (isRetryableRpcError(error)) {
        rpcStats.rateLimitCount += 1;
      }
      if (!isRetryableRpcError(error) || attempt === retries) break;
      if (CONFIG.rpc429CooldownMs > 0) {
        limiter.cooldown(CONFIG.rpc429CooldownMs);
      }
      const jitterMs = Math.floor(Math.random() * 250);
      const delayMs = CONFIG.rpcDelayMs * (attempt + 1) + jitterMs;
      console.warn(`${label} failed with a retryable RPC error. Retrying in ${delayMs}ms.`);
      await sleep(delayMs);
    }
  }

  recordRpcMetric(Date.now() - startedAt, lastError, label, providerName, providerHost);
  throw lastError;
}

function recordRpcMetric(durationMs, error = null, label = "rpc", providerName = CONFIG.rpcProviderName, providerHost = CONFIG.rpcUrlHost) {
  const safeDuration = Number.isFinite(Number(durationMs)) ? Math.max(0, Math.round(Number(durationMs))) : 0;
  rpcStats.callCount += 1;
  rpcStats.totalMs += safeDuration;
  rpcStats.samples.push(safeDuration);
  if (rpcStats.samples.length > 500) rpcStats.samples.splice(0, rpcStats.samples.length - 500);
  rpcStats.lastCallAt = new Date().toISOString();
  if (error) {
    rpcStats.errorCount += 1;
    rpcStats.lastErrorAt = rpcStats.lastCallAt;
    rpcStats.lastError = safePerfEventText(error?.message || "RPC error", 120);
    if (isRetryableRpcError(error)) rpcStats.rateLimitCount += 1;
  }
  logRpcMetric({ label, durationMs: safeDuration, error, providerName, providerHost });
}

function logRpcMetric({ label = "rpc", durationMs = 0, error = null, providerName = CONFIG.rpcProviderName, providerHost = CONFIG.rpcUrlHost } = {}) {
  const rateLimited = Boolean(error && isRetryableRpcError(error));
  // LOG NOISE: every OK RPC read was logged if it took >=250ms (i.e. nearly all of them), which
  // buried the useful lines and rotated Render's log retention down to minutes. Log only ERRORS,
  // rate-limits, and genuinely SLOW ok calls (>RPC_LOG_SLOW_MS, default 2.5s). Ordinary ok reads
  // are not logged. (rpc cost/metrics are unaffected — this only controls the console line.)
  const slowMs = Math.max(250, Number(process.env.RPC_LOG_SLOW_MS) || 2500);
  if (!error && durationMs < slowMs) return;
  try {
    console.info(JSON.stringify({
      event: "rpc_call",
      rpcProviderName: providerName,
      rpcUrlHost: providerHost,
      method: safePerfEventText(label, 80),
      duration_ms: Math.max(0, Math.round(Number(durationMs) || 0)),
      status: error ? (rateLimited ? "rate_limited" : "error") : "ok",
      rate_limited: rateLimited,
      errorCode: error ? safePerfEventText(error?.name || "RpcError", 60) : "",
      errorMessage: error ? safePerfEventText(error?.message || "RPC error", 120) : ""
    }));
  } catch {
    // RPC observability must never affect trading or display paths.
  }
}

async function jupiterFetchJson(url, init, label, retries = CONFIG.jupiterRetries) {
  let lastError;
  const { priority = false, ...fetchInit } = init || {};
  const limiter = priority ? priorityJupiterLimiter : jupiterLimiter;

  for (let attempt = 0; attempt <= retries; attempt += 1) {
    try {
      return await limiter.schedule(label, () => fetchJson(url, fetchInit));
    } catch (error) {
      lastError = error;
      if (!isRetryableServiceError(error) || attempt === retries) break;
      const retryAfterMs = parseRetryAfterMs(error.retryAfter);
      if (CONFIG.jupiter429CooldownMs > 0) {
        limiter.cooldown(Math.max(CONFIG.jupiter429CooldownMs, retryAfterMs));
      }
      const jitterMs = Math.floor(Math.random() * 250);
      const delayMs = Math.max(CONFIG.jupiterMinIntervalMs, retryAfterMs) + (CONFIG.jupiterMinIntervalMs * attempt) + jitterMs;
      console.warn(`${label} failed with a retryable API error. Retrying in ${delayMs}ms.`);
      await sleep(delayMs);
    }
  }

  throw lastError;
}

function createRpcLimiter(options = {}) {
  let gate = Promise.resolve();
  let nextStartAt = 0;
  let cooldownUntil = 0;
  const minIntervalMs = Number.isFinite(Number(options.minIntervalMs))
    ? Math.max(0, Number(options.minIntervalMs))
    : CONFIG.rpcMinIntervalMs;

  return {
    async schedule(_label, operation) {
      const waitTurn = gate.then(async () => {
        const waitMs = Math.max(0, nextStartAt - Date.now(), cooldownUntil - Date.now());
        if (waitMs > 0) {
          await sleep(waitMs);
        }
        nextStartAt = Date.now() + minIntervalMs;
      });
      gate = waitTurn.catch(() => {});
      await waitTurn;
      return operation();
    },
    cooldown(milliseconds) {
      cooldownUntil = Math.max(cooldownUntil, Date.now() + milliseconds);
    }
  };
}

function createJupiterLimiter(options = {}) {
  let gate = Promise.resolve();
  let nextStartAt = 0;
  let cooldownUntil = 0;
  const minIntervalMs = Number.isFinite(Number(options.minIntervalMs))
    ? Math.max(0, Number(options.minIntervalMs))
    : CONFIG.jupiterMinIntervalMs;

  return {
    async schedule(_label, operation) {
      const waitTurn = gate.then(async () => {
        const waitMs = Math.max(0, nextStartAt - Date.now(), cooldownUntil - Date.now());
        if (waitMs > 0) {
          await sleep(waitMs);
        }
        nextStartAt = Date.now() + minIntervalMs;
      });
      gate = waitTurn.catch(() => {});
      await waitTurn;
      return operation();
    },
    cooldown(milliseconds) {
      cooldownUntil = Math.max(cooldownUntil, Date.now() + milliseconds);
    }
  };
}

function isRetryableRpcError(error) {
  const message = formatError(error);
  return message.includes("429") || /too many requests/i.test(message) || /rate limit/i.test(message);
}

function isRetryableServiceError(error) {
  const status = Number(error?.status);
  const message = formatError(error);
  return status === 429
    || [500, 502, 503, 504].includes(status)
    || /too many requests|rate limit|temporarily unavailable|fetch failed|network/i.test(message);
}

function isRetryableSwapError(error) {
  const message = formatError(error);
  if (/insufficient funds|not enough sol|no token balance|missing jupiter|invalid public key/i.test(message)) {
    return false;
  }

  return isRetryableServiceError(error)
    || /slippage|price|quote|route|blockhash|expired|timeout|temporarily|execute|simulation|transaction|failed to land|did not return/i.test(message);
}

function isRetryableSweepError(error) {
  const message = formatError(error);
  return isRetryableRpcError(error)
    || /blockhash|block height exceeded|insufficient funds|insufficient funds for rent|account.*insufficient/i.test(message);
}

function parseRetryAfterMs(value) {
  if (!value) return 0;
  const seconds = Number.parseFloat(value);
  if (Number.isFinite(seconds)) {
    return Math.max(0, Math.floor(seconds * 1000));
  }
  const dateMs = Date.parse(value);
  return Number.isFinite(dateMs) ? Math.max(0, dateMs - Date.now()) : 0;
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
